-- Poems batch 69
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('10f0af8f-fc6d-4567-a0c4-99ae6c552a60','謁焦鍊師','王昌齡','唐','唐诗','tang','','[]','中峯青苔壁，一點雲生時。',48,'全唐诗/poet.tang.6000.json','["中峯青苔壁，一點雲生時。", "豈意石堂裏，得逢焦鍊師。", "爐香淨琴案，松影閑瑤墀。", "拜受長年藥，翩翻西海期。"]'),
('bbd3b9f0-53a9-468a-a6ec-96498624d8a9','宿京江口期劉昚虛不至','王昌齡','唐','唐诗','tang','','[]','霜天起長望，殘月生海門。',48,'全唐诗/poet.tang.6000.json','["霜天起長望，殘月生海門。", "風靜夜潮滿，城高寒氣昏。", "故人何寂寞，久已乖清言。", "明發不能寐，徒盈江上尊。"]'),
('53464ad6-c788-4688-b38d-4634a524a2f6','寒食即事','王昌齡','唐','唐诗','tang','','[]','晉陽寒食地，風俗舊來傳。',48,'全唐诗/poet.tang.6000.json','["晉陽寒食地，風俗舊來傳。", "雨滅龍蛇火，春生鴻雁天。", "泣多流水漲，歌發舞雲旋。", "西見之推廟，空爲人所憐。"]'),
('ba7f3fd4-cf73-48c1-b6bc-2e26b66bf75a','九日登高','王昌齡','唐','唐诗','tang','','[]','青山遠近帶皇州，霽景重陽上北樓。',64,'全唐诗/poet.tang.6000.json','["青山遠近帶皇州，霽景重陽上北樓。", "雨歇亭臯仙菊潤，霜飛天苑御梨秋。", "茱萸插鬢花宜壽，翡翠橫釵舞作愁。", "謾說陶潛籬下醉，何曾得見此風流。"]'),
('6f7e5cd4-f302-4cc4-b79d-2abb0b6e3088','萬歲樓','王昌齡','唐','唐诗','tang','','[]','江上巍巍萬歲樓，不知經歷幾千秋。',64,'全唐诗/poet.tang.6000.json','["江上巍巍萬歲樓，不知經歷幾千秋。", "年年喜見山長在，日日悲看水獨流。", "猿狖何曾離暮嶺，鸕鶿空自泛寒洲。", "誰堪登望雲烟裏，向晚茫茫發旅愁。"]'),
('607042a4-3dbc-46f3-8491-91baf1566991','夏月花萼樓酺宴應制','王昌齡','唐','唐诗','tang','','[]','土德三元正，堯心萬國同。',96,'全唐诗/poet.tang.6000.json','["土德三元正，堯心萬國同。", "汾陰備冬禮，長樂應和風。", "賜慶垂天澤，流歡舊渚宮。", "樓臺生海上，簫鼓出天中。", "霧曉筵初接，宵長曲未終。", "雨隨青幕合，月照舞羅空。", "玉陛分朝列，文章發聖聰。", "愚臣忝書賦，歌詠頌絲桐。"]'),
('c8280b48-5458-437b-908b-4cbf50cd982b','送歐陽會稽之任','王昌齡','唐','唐诗','tang','','[]','懷祿貴心賞，東流山水長。',96,'全唐诗/poet.tang.6000.json','["懷祿貴心賞，東流山水長。", "官移會稽郡，地邇上虞鄉。", "緩帶屏紛雜，漁舟臨訟堂。", "逶迤迴谿趣，猿嘯飛鳥行。", "萬室霽朝雨，千峰迎夕陽。", "輝輝遠洲暎，曖曖澄湖光。", "白髮有高士，青春期上皇。", "應須枉車歇，爲我訪荷裳。"]'),
('aebc05f0-516c-4909-83c3-f9e51a2a1a6c','同王維集青龍寺曇壁上人兄院五韻','王昌齡','唐','唐诗','tang','','[]','本來清淨所，竹樹引幽陰。',60,'全唐诗/poet.tang.6000.json','["本來清淨所，竹樹引幽陰。", "簷外含山翠，人間出世心。", "圓通無有象，聖境不能侵。", "真是吾兄法，何妨友弟深。", "天香自然會，靈異識鐘音。"]'),
('c18e5b00-f843-4768-a1d7-a12394d603ea','東谿翫月','王昌齡','唐','唐诗','tang','','[]','月從斷山口，遙吐柴門端。',72,'全唐诗/poet.tang.6000.json','["月從斷山口，遙吐柴門端。", "萬木分空霽，流陰中夜攢。", "光連虛象白，氣與風露寒。", "谷靜秋泉響，巖深青靄殘。", "澄清入幽夢，破影抱空巒。", "恍惚琴窗裏，松谿曉思難。"]'),
('f8878861-e55c-453c-ac79-3f728e9d0842','朝來曲','王昌齡','唐','唐诗','tang','','["\u7231\u60c5"]','月昃鳴珂動，花連繡戶春。',24,'全唐诗/poet.tang.6000.json','["月昃鳴珂動，花連繡戶春。", "盤龍玉臺鏡，唯待畫眉人。"]'),
('33a97617-dcc4-4a08-81d6-24063abfd0e8','從軍行','王昌齡','唐','唐诗','tang','','["\u7ec4\u8bd7", "\u6218\u4e89", "\u8fb9\u585e"]','大將軍出戰，白日暗榆關。',24,'全唐诗/poet.tang.6000.json','["大將軍出戰，白日暗榆關。", "三面黃金甲，單于破膽還。"]'),
('351313ad-b817-4198-93c5-ef305c824210','答武陵田太守','王昌齡','唐','唐诗','tang','','["\u6292\u60c5", "\u7b54\u8c22"]','仗劒行千里，微軀感一言。',24,'全唐诗/poet.tang.6000.json','["仗劒行千里，微軀感一言。", "曾爲大梁客，不負信陵恩。"]'),
('efa00292-744f-487f-8940-e86c65c23a3f','題灞池二首 一','王昌齡','唐','唐诗','tang','','[]','腰鎌欲何之，東園刈秋韭。',24,'全唐诗/poet.tang.6000.json','["腰鎌欲何之，東園刈秋韭。", "世事不復論，悲歌和樵叟。"]'),
('850a9520-0620-445c-98e9-ed842822cf9e','題灞池二首 二','王昌齡','唐','唐诗','tang','','[]','開門望長川，薄暮見漁者。',24,'全唐诗/poet.tang.6000.json','["開門望長川，薄暮見漁者。", "借問白頭翁，垂綸幾年也。"]'),
('f7d3f6a6-75be-486c-96ae-4b9590b35695','題僧房','王昌齡','唐','唐诗','tang','','[]','椶櫚花滿院，苔蘚入閑房。',24,'全唐诗/poet.tang.6000.json','["椶櫚花滿院，苔蘚入閑房。", "彼此名言絕，空中聞異香。"]'),
('beff880b-695c-4643-8115-250be332ddc0','擊磬老人','王昌齡','唐','唐诗','tang','','[]','雙峰褐衣久，一磬白眉長。',24,'全唐诗/poet.tang.6000.json','["雙峰褐衣久，一磬白眉長。", "誰識野人意，徒看春草芳。"]'),
('4529cb2e-4db1-4a15-a062-1f4d83e45989','送胡大','王昌齡','唐','唐诗','tang','','[]','荆門不堪別，況乃瀟湘秋。',24,'全唐诗/poet.tang.6000.json','["荆門不堪別，況乃瀟湘秋。", "何處遙望君，江邊明月樓。"]'),
('d878a2ff-a8ba-498f-a325-6cc5d54ff4ab','送郭司倉','王昌齡','唐','唐诗','tang','','["\u9001\u522b", "\u53cb\u60c5"]','暎門淮水綠，留騎主人心。',24,'全唐诗/poet.tang.6000.json','["暎門淮水綠，留騎主人心。", "明月隨良掾，春潮夜夜深。"]'),
('e49dac06-6bd7-4be3-bee9-dfe76bfb648e','送李十五','王昌齡','唐','唐诗','tang','','[]','怨別秦楚深，江中秋雲起。',24,'全唐诗/poet.tang.6000.json','["怨別秦楚深，江中秋雲起。", "天長杳無隔，月影在寒水。"]'),
('c1275df2-d211-448e-88d6-554a7dccc11e','送張四','王昌齡','唐','唐诗','tang','','[]','楓林已愁暮，楚水復堪悲。',24,'全唐诗/poet.tang.6000.json','["楓林已愁暮，楚水復堪悲。", "別後冷山月，清猿無斷時。"]'),
('7382129c-d8e3-407e-9a23-d9d22738aada','武陵田太守席送司馬盧谿','王昌齡','唐','唐诗','tang','','[]','諸侯分楚郡，飲餞五谿春。',24,'全唐诗/poet.tang.6000.json','["諸侯分楚郡，飲餞五谿春。", "山水清暉遠，俱憐一逐臣。"]'),
('0fa83a19-32a8-4404-8bd3-27716ab651c6','送譚八之桂林','王昌齡','唐','唐诗','tang','','[]','客心仍在楚，江館復臨湘。',24,'全唐诗/poet.tang.6000.json','["客心仍在楚，江館復臨湘。", "別意猿鳥外，天寒桂水長。"]'),
('5dc35e8f-eb85-4bfb-9426-f8c53cb97408','送劉十五之郡','王昌齡','唐','唐诗','tang','','[]','平明江霧寒，客馬江上發。',24,'全唐诗/poet.tang.6000.json','["平明江霧寒，客馬江上發。", "扁舟事洛陽，窅窅含楚月。"]'),
('0ac86eeb-6fbe-4fea-bbb2-f2cabb97d68e','從軍行七首 一','王昌齡','唐','唐诗','tang','','[]','烽火城西百尺樓，黃昏獨上海風秋。',32,'全唐诗/poet.tang.6000.json','["烽火城西百尺樓，黃昏獨上海風秋。", "更吹羌笛關山月，無那金閨萬里愁。"]'),
('7b657130-529b-4128-b4bb-279af91baed1','從軍行七首 二','王昌齡','唐','唐诗','tang','','[]','琵琶起舞換新聲，總是關山舊別情。',32,'全唐诗/poet.tang.6000.json','["琵琶起舞換新聲，總是關山舊別情。", "撩亂邊愁聽不盡，高高秋月照長城。"]'),
('80f4b4f0-96e5-46a9-a634-f152b9f390d8','從軍行七首 三','王昌齡','唐','唐诗','tang','','[]','關城榆葉早疎黃，日暮雲沙古戰場。',32,'全唐诗/poet.tang.6000.json','["關城榆葉早疎黃，日暮雲沙古戰場。", "表請回軍掩塵骨，莫教兵士哭龍荒。"]'),
('fb92a089-72f0-44c2-93f8-060124eaa0a9','從軍行七首 四','王昌齡','唐','唐诗','tang','','["\u6218\u4e89", "\u5c71\u6c34", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u8fb9\u585e", "\u9ad8\u4e2d\u53e4\u8bd7", "\u58ee\u5fd7"]','青海長雲暗雪山，孤城遙望玉門關。',32,'全唐诗/poet.tang.6000.json','["青海長雲暗雪山，孤城遙望玉門關。", "黃沙百戰穿金甲，不破樓蘭終不還。"]'),
('924151b2-fb99-456c-8788-a3265159792e','從軍行七首 五','王昌齡','唐','唐诗','tang','','[]','大漠風塵日色昏，紅旗半捲出轅門。',32,'全唐诗/poet.tang.6000.json','["大漠風塵日色昏，紅旗半捲出轅門。", "前軍夜戰洮河北，已報生擒吐谷渾。"]'),
('e19fbd6b-a7de-46b8-be86-125c3941777f','從軍行七首 六','王昌齡','唐','唐诗','tang','','[]','胡瓶落膊紫薄汗，碎葉城西秋月團。',32,'全唐诗/poet.tang.6000.json','["胡瓶落膊紫薄汗，碎葉城西秋月團。", "明敕星馳封寶劒，辭君一夜取樓蘭。"]'),
('ca7390ce-3f21-4291-a03b-de83e46060f9','從軍行七首 七','王昌齡','唐','唐诗','tang','','[]','玉門山嶂幾千重，山北山南總是烽。',32,'全唐诗/poet.tang.6000.json','["玉門山嶂幾千重，山北山南總是烽。", "人依遠戍須看火，馬踏深山不見蹤。"]'),
('de6b7e3d-03cd-4daa-bdc2-7fb820fda441','出塞二首 一','王昌齡','唐','唐诗','tang','','["\u6218\u4e89", "\u5199\u666f", "\u5fe7\u56fd\u5fe7\u6c11", "\u7231\u56fd", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','秦時明月漢時關，萬里長征人未還。',32,'全唐诗/poet.tang.6000.json','["秦時明月漢時關，萬里長征人未還。", "但使龍城飛將在，不教胡馬度陰山。"]'),
('25e93094-40d5-45ee-845d-b15dc6a5c1c3','出塞二首 二','王昌齡','唐','唐诗','tang','','[]','騮馬新跨白玉鞍，戰罷沙場月色寒。',32,'全唐诗/poet.tang.6000.json','["騮馬新跨白玉鞍，戰罷沙場月色寒。", "城頭鐵鼓聲猶振，匣裏金刀血未乾。"]'),
('84f40b5c-4c5b-43c4-822a-d2b92c7b41e1','采蓮曲二首 一','王昌齡','唐','唐诗','tang','','[]','吳姬越豔楚王妃，爭弄蓮舟水濕衣。',32,'全唐诗/poet.tang.6000.json','["吳姬越豔楚王妃，爭弄蓮舟水濕衣。", "來時浦口花迎入，采罷江頭月送歸。"]'),
('5383487f-7c1f-43ee-9cf9-c1f44a4a0e45','采蓮曲二首 二','王昌齡','唐','唐诗','tang','','["\u5c11\u5973", "\u690d\u7269", "\u5199\u666f"]','荷葉羅裙一色裁，芙蓉向臉兩邊開。',32,'全唐诗/poet.tang.6000.json','["荷葉羅裙一色裁，芙蓉向臉兩邊開。", "亂入池中看不見，聞歌始覺有人來。"]'),
('1e1e21da-a20a-4c12-9c5d-5ae05d2df153','殿前曲二首 一','王昌齡','唐','唐诗','tang','','[]','貴人妝梳殿前催，香風吹入殿後來。',32,'全唐诗/poet.tang.6000.json','["貴人妝梳殿前催，香風吹入殿後來。", "仗引笙歌大宛馬，白蓮花發照池臺。"]'),
('5432f819-f445-4cb3-bf9a-e6692bbd033a','殿前曲二首 二','王昌齡','唐','唐诗','tang','','[]','胡部笙歌西殿頭，梨園弟子和涼州。',32,'全唐诗/poet.tang.6000.json','["胡部笙歌西殿頭，梨園弟子和涼州。", "新聲一段高樓月，聖主千秋樂未休。"]'),
('d0fa1454-f337-4343-ab4a-2a42dfdf4e8f','春宮曲','王昌齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u5bab\u6028", "\u5973\u5b50"]','昨夜風開露井桃，未央前殿月輪高。',32,'全唐诗/poet.tang.6000.json','["昨夜風開露井桃，未央前殿月輪高。", "平陽歌舞新承寵，簾外春寒賜錦袍。"]'),
('3b5f5a9f-754b-4dda-8b18-bac4598eb0fe','西宮春怨','王昌齡','唐','唐诗','tang','','[]','西宮夜靜百花香，欲捲珠簾春恨長。',32,'全唐诗/poet.tang.6000.json','["西宮夜靜百花香，欲捲珠簾春恨長。", "斜抱雲和深見月，朦朧樹色隱昭陽。"]'),
('786a91cb-4e20-4cdb-951e-70abfcf1af85','西宮秋怨','王昌齡','唐','唐诗','tang','','[]','芙蓉不及美人妝，水殿風來珠翠香。',32,'全唐诗/poet.tang.6000.json','["芙蓉不及美人妝，水殿風來珠翠香。", "誰分含啼掩秋扇，空懸明月待君王。"]'),
('913bf762-71a5-46bf-88d9-af85385191c6','長信秋詞五首 一','王昌齡','唐','唐诗','tang','','[]','金井梧桐秋葉黃，珠簾不捲夜來霜。',32,'全唐诗/poet.tang.6000.json','["金井梧桐秋葉黃，珠簾不捲夜來霜。", "熏籠玉枕無顏色，臥聽南宮清漏長。"]'),
('620823bf-6fe5-4db1-aef1-ea1e91b97397','長信秋詞五首 二','王昌齡','唐','唐诗','tang','','[]','高殿秋砧響夜闌，霜深猶憶御衣寒。',32,'全唐诗/poet.tang.6000.json','["高殿秋砧響夜闌，霜深猶憶御衣寒。", "銀燈青瑣裁縫歇，還向金城明主看。"]'),
('88ffb109-8e3f-4175-9352-8e02c28a4d9f','長信秋詞五首 三','王昌齡','唐','唐诗','tang','','[]','奉帚平明金殿開，且將團扇暫裴回。',34,'全唐诗/poet.tang.6000.json','["奉帚平明金殿開，且將團扇暫裴回。", "玉顏不及寒鴉色，猶帶[昭]陽日影來。"]'),
('e2c2c33b-fd1d-4aa2-9558-2b55137adec4','長信秋詞五首 四','王昌齡','唐','唐诗','tang','','[]','真成薄命久尋思，夢見君王覺後疑。',32,'全唐诗/poet.tang.6000.json','["真成薄命久尋思，夢見君王覺後疑。", "火照西宮知夜飲，分明複道奉恩時。"]'),
('058b2020-c2cd-44fb-9657-358a5468ac2d','長信秋詞五首 五','王昌齡','唐','唐诗','tang','','[]','長信宮中秋月明，昭陽殿下擣衣聲。',32,'全唐诗/poet.tang.6000.json','["長信宮中秋月明，昭陽殿下擣衣聲。", "白露堂中細草跡，紅羅帳裏不勝情。"]'),
('3af49c81-e4be-4724-9b7b-1b41966e9d69','青樓曲二首 一','王昌齡','唐','唐诗','tang','','[]','白馬金鞍從武皇，旌旗十萬宿長楊。',32,'全唐诗/poet.tang.6000.json','["白馬金鞍從武皇，旌旗十萬宿長楊。", "樓頭小婦鳴箏坐，遙見飛塵入建章。"]'),
