('1fea4e9e-800a-4d1d-bad2-2a4019ae787b','青樓怨','王昌齡','唐','唐诗','tang','','["\u601d\u5ff5", "\u4f24\u6000"]','香幃風動花入樓，高調鳴箏緩夜愁。',32,'全唐诗/poet.tang.6000.json','["香幃風動花入樓，高調鳴箏緩夜愁。", "腸斷關山不解說，依依殘月下簾鉤。"]'),
('8209ce8e-92c6-4123-b130-1186ed714dfa','浣紗女','王昌齡','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','錢塘江邊是誰家，江上女兒全勝花。',32,'全唐诗/poet.tang.6000.json','["錢塘江邊是誰家，江上女兒全勝花。", "吳王在時不得出，今日公然來浣紗。"]'),
('4ac3f099-73da-43e8-a4e5-1dbbd9427491','閨怨','王昌齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5987\u5973", "\u6625\u5929", "\u4e03\u8a00\u7edd\u53e5", "\u95fa\u6028"]','閨中少婦不曾愁，春日凝妝上翠樓。',32,'全唐诗/poet.tang.6000.json','["閨中少婦不曾愁，春日凝妝上翠樓。", "忽見陌頭楊柳色，悔教夫壻覓封侯。"]'),
('3286b733-02a6-4c21-951d-c873830a08b8','甘泉歌','王昌齡','唐','唐诗','tang','','[]','乘輿執玉已登壇，細草霑衣春殿寒。',32,'全唐诗/poet.tang.6000.json','["乘輿執玉已登壇，細草霑衣春殿寒。", "昨夜雲生拜初月，萬年甘露水晶盤。"]'),
('cb12783c-1c1b-44c4-82ce-7cf9e3096a9e','蕭駙馬宅花燭','王昌齡','唐','唐诗','tang','','[]','青鸞飛入合歡宮，紫鳳銜花出禁中。',32,'全唐诗/poet.tang.6000.json','["青鸞飛入合歡宮，紫鳳銜花出禁中。", "可憐今夜千門裏，銀漢星回一道通。"]'),
('92f55a8c-7778-4802-9991-d76b0e4fdb48','觀獵','王昌齡','唐','唐诗','tang','','[]','角鷹初下秋草稀，鐵驄拋鞚去如飛。',32,'全唐诗/poet.tang.6000.json','["角鷹初下秋草稀，鐵驄拋鞚去如飛。", "少年獵得平原兔，馬後橫捎意氣歸。"]'),
