('86637a29-5545-453f-9bbf-fc2a0a83c6d1','寄陶副使','王昌齡','唐','唐诗','tang','','["\u534e\u5c71"]','聞道將軍破海門，如何遠謫渡湘沅。',32,'全唐诗/poet.tang.6000.json','["聞道將軍破海門，如何遠謫渡湘沅。", "春來明主封西嶽，自有還君紫綬恩。"]'),
('26f3af10-4553-416c-9d86-c110264a16dc','至南陵答皇甫岳','王昌齡','唐','唐诗','tang','','["\u957f\u6c5f"]','與君同病復漂淪，昨夜宣城別故人。',32,'全唐诗/poet.tang.6000.json','["與君同病復漂淪，昨夜宣城別故人。", "明主恩深非歲久，長江還共五谿濱。"]'),
('d60591c0-2c20-48b3-aa03-8f40188cb455','西江寄越弟','王昌齡','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','南浦逢君嶺外還，沅谿更遠洞庭山。',32,'全唐诗/poet.tang.6000.json','["南浦逢君嶺外還，沅谿更遠洞庭山。", "堯時恩澤如春雨，夢裏相逢同入關。"]'),
('94054365-0488-4baa-ad3c-ff7fffaebf1d','李四倉曹宅夜飲','王昌齡','唐','唐诗','tang','','[]','霜天留後故情歡，銀燭金爐夜不寒。',32,'全唐诗/poet.tang.6000.json','["霜天留後故情歡，銀燭金爐夜不寒。", "欲問吳江別來意，青山明月夢中看。"]'),
('7a64addc-bcd1-4e2a-91ff-4f060a803ecb','宴春源','王昌齡','唐','唐诗','tang','','[]','源向春城花幾重，江明深翠引諸峯。',32,'全唐诗/poet.tang.6000.json','["源向春城花幾重，江明深翠引諸峯。", "與君醉失松溪路，山館寥寥傳暝鐘。"]'),
('7646be95-fa97-4cc3-b7e2-3ae09962288d','龍標野宴','王昌齡','唐','唐诗','tang','','[]','沅溪夏晚足涼風，春酒相攜就竹叢。',32,'全唐诗/poet.tang.6000.json','["沅溪夏晚足涼風，春酒相攜就竹叢。", "莫道絃歌愁遠謫，青山明月不曾空。"]'),
('a52785c6-d98a-45ed-a53d-60043e8b5de7','聽流人水調子','王昌齡','唐','唐诗','tang','','[]','孤舟微月對楓林，分付鳴箏與客心。',32,'全唐诗/poet.tang.6000.json','["孤舟微月對楓林，分付鳴箏與客心。", "嶺色千重萬重雨，斷絃收與淚痕深。"]'),
('d4cf1877-336f-42e8-be4d-5164d41e698a','梁苑','王昌齡','唐','唐诗','tang','','[]','梁園秋竹古時烟，城外風悲欲暮天。',32,'全唐诗/poet.tang.6000.json','["梁園秋竹古時烟，城外風悲欲暮天。", "萬乘旌旗何處在？平臺賓客有誰憐。"]'),
('ddb632ea-fedf-4c02-8eec-770487b01d18','武陵龍興觀黃道士房問易因題','王昌齡','唐','唐诗','tang','','[]','齋心問易太陽宮，八卦真形一氣中。',32,'全唐诗/poet.tang.6000.json','["齋心問易太陽宮，八卦真形一氣中。", "仙老言餘鶴飛去，玉清壇上雨濛濛。"]'),
('8e03215e-a131-48cf-9e89-3544a6cdc967','送魏二','王昌齡','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u666f", "\u53cb\u60c5"]','醉別江樓橘柚香，江風引雨入舟涼。',32,'全唐诗/poet.tang.6000.json','["醉別江樓橘柚香，江風引雨入舟涼。", "憶君遙在瀟湘月，愁聽清猿夢裏長。"]'),
