('06fbf086-4bf5-46ce-aa6e-4ba5f8c8b4b1','留別司馬太守','王昌齡','唐','唐诗','tang','','[]','辰陽太守念王孫，遠謫沅谿何可論。',32,'全唐诗/poet.tang.6000.json','["辰陽太守念王孫，遠謫沅谿何可論。", "黃鶴青雲當一舉，明珠吐著抱君恩。"]'),
('12c81418-a970-476b-a48d-698a7bf84a58','盧溪主人','王昌齡','唐','唐诗','tang','','[]','武陵溪口駐扁舟，溪水隨君向北流。',32,'全唐诗/poet.tang.6000.json','["武陵溪口駐扁舟，溪水隨君向北流。", "行到荆門上三峽，莫將孤月對猿愁。"]'),
('ceb0c2f7-ffaf-4fee-a995-10cda09ea1e1','送程六','王昌齡','唐','唐诗','tang','','[]','冬夜傷離在五溪，青魚雪落鱠橙虀。',32,'全唐诗/poet.tang.6000.json','["冬夜傷離在五溪，青魚雪落鱠橙虀。", "武岡前路看斜月，片片舟中雲向西。"]'),
('e6b1b4f5-49c9-47d5-9e05-ebd77e98bdc8','送朱越','王昌齡','唐','唐诗','tang','','[]','遠別舟中蔣山暮，君行舉首燕城路。',32,'全唐诗/poet.tang.6000.json','["遠別舟中蔣山暮，君行舉首燕城路。", "薊門秋月隱黃雲，期向金陵醉江樹。"]'),
('b3d5c955-93ef-4b75-a83b-0d23b9e959bd','別辛漸','王昌齡','唐','唐诗','tang','','[]','別館蕭條風雨寒，扁舟月色渡江看。',32,'全唐诗/poet.tang.6000.json','["別館蕭條風雨寒，扁舟月色渡江看。", "酒酣不識關西道，却望春江雲尚殘。"]'),
('789c0699-8187-42a6-b910-fb9b999d75bd','送柴侍御','王昌齡','唐','唐诗','tang','','[]','流水通波接武岡，送君不覺有離傷。',32,'全唐诗/poet.tang.6000.json','["流水通波接武岡，送君不覺有離傷。", "青山一道同雲雨，眀月何曽是兩鄉。"]'),
('f4edca98-5fd3-4ddd-9702-aa7d2f367947','送萬大歸長沙','王昌齡','唐','唐诗','tang','','[]','桂陽秋水長沙縣，楚竹離聲爲君變。',32,'全唐诗/poet.tang.6000.json','["桂陽秋水長沙縣，楚竹離聲爲君變。", "青山隱隱孤舟微，白鶴雙飛忽相見。"]'),
('27e987a5-b66b-4738-baf5-68e205f3c08e','送吳十九往沅陵','王昌齡','唐','唐诗','tang','','[]','沅江流水到辰陽，谿口逢君驛路長。',32,'全唐诗/poet.tang.6000.json','["沅江流水到辰陽，谿口逢君驛路長。", "遠謫誰知望雷雨，明年春水共還鄉。"]'),
('70205727-903d-4bde-8c28-07e9bf09d538','別皇甫五','王昌齡','唐','唐诗','tang','','[]','漵浦潭陽隔楚山，離尊不用起愁顏。',32,'全唐诗/poet.tang.6000.json','["漵浦潭陽隔楚山，離尊不用起愁顏。", "明祠靈響期昭應，天澤俱從此路還。"]'),
('82f43aa2-768a-47e3-a45f-acbb1bab2f6a','送崔參軍往龍溪','王昌齡','唐','唐诗','tang','','[]','龍溪只在龍標上，秋月孤山兩相向。',32,'全唐诗/poet.tang.6000.json','["龍溪只在龍標上，秋月孤山兩相向。", "譴謫離心是丈夫，鴻恩共侍春江漲。"]'),
('6138239c-63b4-4622-a5ca-279a8031be4b','送鄭判官','王昌齡','唐','唐诗','tang','','[]','東楚吳山驛樹微，軺車銜命奉恩輝。',32,'全唐诗/poet.tang.6000.json','["東楚吳山驛樹微，軺車銜命奉恩輝。", "英僚攜出新豐酒，半道遙看驄馬歸。"]'),
('5e0db2d1-597f-4634-a8e8-bd1c907824ba','送姚司法歸吳','王昌齡','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','吳掾留觴楚郡心，洞庭秋雨海門陰。',32,'全唐诗/poet.tang.6000.json','["吳掾留觴楚郡心，洞庭秋雨海門陰。", "但令意遠扁舟近，不道滄江百丈深。"]'),
('f893ef56-fa7c-49ef-a8aa-fa2cb9b3fc52','送高三之桂林','王昌齡','唐','唐诗','tang','','[]','留君夜飲對瀟湘，從此歸舟客夢長。',32,'全唐诗/poet.tang.6000.json','["留君夜飲對瀟湘，從此歸舟客夢長。", "嶺上梅花侵雪暗，歸時還拂桂花香。"]'),
('159c125a-24c6-4756-bb38-8f6a893ae608','旅望','王昌齡','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u6292\u60c5"]','白花原頭望京師，黃河水流無盡時。',32,'全唐诗/poet.tang.6000.json','["白花原頭望京師，黃河水流無盡時。", "窮秋曠野行人絕，馬首東來知是誰。"]'),
('6298051e-adce-4496-809f-634dcf2a1125','題朱鍊師山房','王昌齡','唐','唐诗','tang','','[]','叩齒焚香出世塵，齋壇鳴磬步虛人。',32,'全唐诗/poet.tang.6000.json','["叩齒焚香出世塵，齋壇鳴磬步虛人。", "百花仙醞能留客，一飯胡麻度幾春。"]'),
('4b0c70cb-8ae5-4ffe-867e-3835b1352408','武陵開元觀黃鍊師院三首 一','王昌齡','唐','唐诗','tang','','[]','松間白髮黃尊師，童子燒香禹步時。',32,'全唐诗/poet.tang.6000.json','["松間白髮黃尊師，童子燒香禹步時。", "欲訪桃源入溪路，忽聞雞犬使人疑。"]'),
('31370c6a-1ac6-4416-884d-32eddb837892','武陵開元觀黃鍊師院三首 二','王昌齡','唐','唐诗','tang','','[]','先賢盛說桃花源，塵忝何堪武陵郡。',32,'全唐诗/poet.tang.6000.json','["先賢盛說桃花源，塵忝何堪武陵郡。", "聞道秦時避地人，至今不與人通問。"]'),
('74430fb7-b24d-4751-9904-4fa4a574788a','武陵開元觀黃鍊師院三首 三','王昌齡','唐','唐诗','tang','','[]','山觀空虛清靜門，從官役吏擾塵喧。',32,'全唐诗/poet.tang.6000.json','["山觀空虛清靜門，從官役吏擾塵喧。", "暫因問俗到真境，便欲投誠依道源。"]'),
('0305b271-93d4-435e-ab64-43cb17ccd5e4','河上老人歌','王昌齡','唐','唐诗','tang','','[]','河上老人坐古槎，合丹只用青蓮花。',32,'全唐诗/poet.tang.6000.json','["河上老人坐古槎，合丹只用青蓮花。", "至今八十如四十，口道滄溟是我家。"]'),
('3195d94e-02ec-4277-8cd9-6afff518cb82','春怨','王昌齡','唐','唐诗','tang','','[]','音書杜絕白狼西，桃李無顏黃鳥啼。',32,'全唐诗/poet.tang.6000.json','["音書杜絕白狼西，桃李無顏黃鳥啼。", "寒雁春深歸去盡，出門腸斷草萋萋。"]'),
('3e4a693d-49d2-4791-bb34-f49ddd202d49','句','王昌齡','唐','唐诗','tang','','[]','朝薦抱良策，獨倚江城樓。',82,'全唐诗/poet.tang.6000.json','["朝薦抱良策，獨倚江城樓。", "昨從金陵邑，遠謫沅溪濱。", "娟魄已三孕。", "駕幸溫泉日，嚴霜子月初。", "長亭酒未醒，千里風動地。", "蒼荻寒滄江，石頭岸邊飲。", "天仗森森練雪凝，身騎鐵驄自臂鷹。"]'),
('5c83eace-eff6-404e-9186-bb5407c4a0bb','送陸擢','常建','唐','唐诗','tang','','[]','聖代多才俊，陸生何考槃。',48,'全唐诗/poet.tang.6000.json','["聖代多才俊，陸生何考槃。", "南山高松樹，不合空摧殘。", "九月湖上別，北風秋雨寒。", "殷勤歎孤鳳，早食金琅玕。"]'),
('e5db693e-8b72-43e3-aefa-2d56bf112d61','送李十一尉臨溪','常建','唐','唐诗','tang','','[]','泠泠花下琴，君唱渡江吟。',48,'全唐诗/poet.tang.6000.json','["泠泠花下琴，君唱渡江吟。", "天際一帆影，預懸離別心。", "以言神仙尉，因致瑤華音。", "回軫撫商調，越溪澄碧林。"]'),
('0c965b46-4730-40b0-9b01-f117a107cfb7','江上琴興','常建','唐','唐诗','tang','','[]','江上調玉琴，一弦清一心。',48,'全唐诗/poet.tang.6000.json','["江上調玉琴，一弦清一心。", "泠泠七弦遍，萬木澄幽陰。", "能使江月白，又令江水深。", "始知梧桐枝，可以徽黃金。"]'),
('1ce9062d-4aed-4cb1-9dd7-ad3c723be7c7','湖中晚霽','常建','唐','唐诗','tang','','[]','湖廣舟自輕，江天欲澄霽。',120,'全唐诗/poet.tang.6000.json','["湖廣舟自輕，江天欲澄霽。", "是時清楚望，氣色猶霾曀。", "踟躕金霞白，波上日初麗。", "煙虹落鏡中，樹木生天際。", "杳杳涯欲辨，蒙蒙雲復閉。", "言乘星漢明，又覩寰瀛勢。", "微興從此愜，悠然不知歲。", "試歌滄浪清，遂覺乾坤細。", "豈念客衣薄，將期永投袂。", "遲回漁父間，一鴈聲嘹唳。"]'),
('c854a853-b015-4848-823b-a786659d33b3','宿王昌齡隱居','常建','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9690\u9038", "\u4e94\u8a00\u53e4\u8bd7", "\u5c71\u6c34"]','清溪深不測，隱處唯孤雲。',48,'全唐诗/poet.tang.6000.json','["清溪深不測，隱處唯孤雲。", "松際露微月，清光猶爲君。", "茅亭宿花影，藥院滋苔紋。", "余亦謝時去，西山鸞鶴羣。"]'),
('0cd46838-b0ae-4a8a-bc10-4366c585f4a1','送楚十少府','常建','唐','唐诗','tang','','[]','微風吹霜氣，寒影明前除。',72,'全唐诗/poet.tang.6000.json','["微風吹霜氣，寒影明前除。", "落日未能別，蕭蕭林木虛。", "愁煙閉千里，仙尉其何如。", "因送別鶴操，贈之雙鯉魚。", "鯉魚在金盤，別鶴哀有餘。", "心事則如此，請君開素書。"]'),
('b393f0d7-de43-49ae-8ebb-37f0b3efc919','張山人彈琴','常建','唐','唐诗','tang','','[]','君去芳草綠，西峰彈玉琴。',96,'全唐诗/poet.tang.6000.json','["君去芳草綠，西峰彈玉琴。", "豈惟丘中賞，兼得清煩襟。", "朝從山口還，出嶺聞清音。", "了然雲霞氣，照見天地心。", "玄鶴下澄空，翩翩舞松林。", "改弦扣商聲，又聽飛龍吟。", "稍覺此身妄，漸知仙事深。", "其將鍊金鼎，永矣投吾簪。"]'),
('ab1c7011-0dd3-4efc-8996-56c111c4a260','白湖寺後溪宿雲門','常建','唐','唐诗','tang','','[]','落日山水清，亂流鳴淙淙。',156,'全唐诗/poet.tang.6000.json','["落日山水清，亂流鳴淙淙。", "舊蒲雨抽節，新花水對窓。", "溪中日已沒，歸鳥多爲雙。", "杉松引直路，出谷臨前湖。", "洲渚晚色靜，又觀花與蒲。", "入溪復登嶺，草淺寒流速。", "圓月明高峰，春山因獨宿。", "松陰澄初夜，曙色分遠目。", "日出城南隅，青青媚川陸。", "亂花覆東郭，碧氣銷長林。", "四郊一清影，千里歸寸心。", "前瞻王程促，却戀雲門深。", "畢景有餘興，到家彈玉琴。"]'),
('c16709fd-1a50-42d7-82b9-92f204491289','閑齋臥病行藥至山館稍次湖亭二首 一','常建','唐','唐诗','tang','','[]','旬時結陰霖，簾外初白日。',36,'全唐诗/poet.tang.6000.json','["旬時結陰霖，簾外初白日。", "齋沐清病容，心魂畏虛室。", "閑梅照前戶，明鏡悲舊質。"]'),
('c8e319c5-6407-4397-b9c9-67f29068497b','閑齋臥病行藥至山館稍次湖亭二首 二','常建','唐','唐诗','tang','','[]','行藥至石壁，東風變萌芽。',48,'全唐诗/poet.tang.6000.json','["行藥至石壁，東風變萌芽。", "主人門外綠，小隱湖中花。", "時物堪獨往，春帆宜別家。", "辭君嚮滄海，爛熳從天涯。"]'),
('95bccdb8-832d-43cf-a33c-2f92f757af1b','塞上曲','常建','唐','唐诗','tang','','[]','翩翩雲中使，來問太原卒。',48,'全唐诗/poet.tang.6000.json','["翩翩雲中使，來問太原卒。", "百戰苦不歸，刀頭怨明月。", "塞雲隨陣落，寒日傍城沒。", "城下有寡妻，哀哀哭枯骨。"]'),
('113e4509-3dcf-4327-92a2-40f723af7a8a','仙谷遇毛女意知是秦宮人','常建','唐','唐诗','tang','','[]','溪口水石淺，泠泠明藥叢。',144,'全唐诗/poet.tang.6000.json','["溪口水石淺，泠泠明藥叢。", "入溪雙峰峻，松栝疎幽風。", "垂嶺枝嫋嫋，翳泉花濛濛。", "夤緣霽人目，路盡心彌通。", "盤石橫陽崖，前流殊未窮。", "回潭清雲影，瀰漫長天空。", "水邊一神女，千歲爲玉童。", "羽毛經漢代，珠翠逃秦宮。", "目覿神已寓，鶴飛言未終。", "祈君青雲祕，願謁黃仙翁。", "嘗以耕玉田，龍鳴西頂中。", "金梯與天接，幾日來相逢。"]'),
('e65e92d4-a81f-40e1-9ba3-dad53597f220','夢太白西峰','常建','唐','唐诗','tang','','[]','夢寐昇九崖，杳靄逢元君。',96,'全唐诗/poet.tang.6000.json','["夢寐昇九崖，杳靄逢元君。", "遺我太白峰，寥寥辭垢氛。", "結宇在星漢，宴林閉氤氳。", "簷楹覆餘翠，巾舄生片雲。", "時往溪水間，孤亭晝仍曛。", "松峰引天影，石瀨清霞文。", "恬目緩舟趣，霽心投鳥羣。", "春風又搖櫂，潭島花紛紛。"]'),
('b149e1ae-86b7-4843-a1e2-f02fa57f6ea3','鄂渚招王昌齡張僨','常建','唐','唐诗','tang','','[]','刈蘆曠野中，沙土飛黃雲。',144,'全唐诗/poet.tang.6000.json','["刈蘆曠野中，沙土飛黃雲。", "天晦無精光，茫茫悲遠君。", "楚山隔湘水，湖畔落日曛。", "春鴈又北飛，音書固難聞。", "謫居未爲歎，讒枉何由分。", "午日逐蛟龍，宜爲弔冤文。", "翻覆古共然，名宦安足云。", "貧士任枯槁，捕魚清江濆。", "有時荷鉏犂，曠野自耕耘。", "不然春山隱，溪澗花氤氳。", "山鹿自有場，賢達亦顧羣。", "二賢歸去來，世上徒紛紛。"]'),
('0c8d2ff2-b449-4af8-93d5-d8f6abd96362','春詞二首 一','常建','唐','唐诗','tang','','[]','菀菀黃柳絲，濛濛雜花垂。',36,'全唐诗/poet.tang.6000.json','["菀菀黃柳絲，濛濛雜花垂。", "日高紅妝臥，倚對春光遲。", "寧知傍淇水，騕褭黃金羈。"]'),
('b308cc03-0433-4d04-b6a3-8f5664fa87a8','春詞二首 二','常建','唐','唐诗','tang','','[]','翳翳陌上桑，南枝交北堂。',36,'全唐诗/poet.tang.6000.json','["翳翳陌上桑，南枝交北堂。", "美人金梯出，素手自提筐。", "非但畏蠶飢，盈盈嬌路傍。"]'),
('720a581a-cbaa-49ae-ad44-65eace499018','晦日馬鐙曲稍次中流作','常建','唐','唐诗','tang','','[]','夜寒宿蘆葦，曉色明西林。',72,'全唐诗/poet.tang.6000.json','["夜寒宿蘆葦，曉色明西林。", "初日在川上，便澄遊子心。", "秦天無纖翳，郊野浮春陰。", "波靜隨釣魚，舟小綠水深。", "出浦見千里，曠然諧遠尋。", "扣船應漁父，因唱滄浪吟。"]'),
('6ad90448-eba6-4c79-9092-3f17e2807f09','古意','常建','唐','唐诗','tang','','[]','牧馬古道傍，道傍多古墓。',48,'全唐诗/poet.tang.6000.json','["牧馬古道傍，道傍多古墓。", "蕭條愁殺人，蟬鳴白楊樹。", "迴頭望京邑，合沓生塵霧。", "富貴安可常，歸來保貞素。"]'),
('6225c38b-8e85-4f74-b5b8-34cd1038a85b','宿五度溪仙人得道處','常建','唐','唐诗','tang','','[]','五度溪上花，生根依兩崖。',72,'全唐诗/poet.tang.6000.json','["五度溪上花，生根依兩崖。", "二月尋片雲，願宿秦人家。", "上見懸崖崩，下見白水湍。", "仙人彈碁處，石上青蘿盤。", "無處求玉童，翳翳唯林巒。", "前溪遇新月，聊取玉琴彈。"]'),
('a4ef2905-143e-4c53-84c1-aeb7a87fcdb9','西山','常建','唐','唐诗','tang','','[]','一身爲輕舟，落日西山際。',120,'全唐诗/poet.tang.6000.json','["一身爲輕舟，落日西山際。", "常隨去帆影，遠接長天勢。", "物象歸餘清，林巒分夕麗。", "亭亭碧流暗，日入孤霞繼。", "渚日遠陰映，湖雲尚明霽。", "林昏楚色來，岸遠荆門閉。", "至夜轉清逈，蕭蕭北風厲。", "沙邊鴈鷺泊，宿處蒹葭蔽。", "圓月逗前浦，孤琴又搖曳。", "泠然夜遂深，白露霑人袂。"]'),
('07095ed9-e671-48e1-9255-75aaafff2bd7','春詞','常建','唐','唐诗','tang','','[]','階下草猶短，牆頭梨花白。',36,'全唐诗/poet.tang.6000.json','["階下草猶短，牆頭梨花白。", "織女高樓上，停梭顧行客。", "問君在何所，青鳥舒錦翮。"]'),
('4e4bd839-4acb-4834-82ac-e13d881ab964','贈三侍御','常建','唐','唐诗','tang','','["\u957f\u6c5f"]','高山臨大澤，正月蘆花乾。',192,'全唐诗/poet.tang.6000.json','["高山臨大澤，正月蘆花乾。", "陽色薰兩崖，不改青松寒。", "士賢守孤貞，古來皆共難。", "明君錯甚才，臺上飛三鸞。", "操與霜雪明，量與江海寬。", "束身視天涯，安能窮波瀾。", "孤鶴在枳棘，一枝非所安。", "逸翮望絕霄，見欲凌雲端。", "層臺何其高，山石流洪湍。", "固知非天池，鳴躍同所歡。", "誰念獨枯槁，四十長江干。", "責躬貴知己，效拙從一官。", "折翮悲高風，苦飢候朝飡。", "湖月映大海，天空何漫漫。", "托身未知所，謀道庶不刊。", "吟彼喬木詩，一夕常三歎。"]'),
('bad65dba-7a25-45a7-8d7e-63d3c3eba0f6','第三峰','常建','唐','唐诗','tang','','[]','西山第三頂，茅宇依雙松。',120,'全唐诗/poet.tang.6000.json','["西山第三頂，茅宇依雙松。", "杳杳欲至天，雲梯升幾重。", "瑩魄澄玉虛，以求鸞鶴蹤。", "逶迤非天人，執節乘赤龍。", "旁映白日光，縹緲輕霞容。", "孤輝上煙霧，餘影明心胸。", "願與黃麒麟，欲飛而莫從。", "因寂清萬象，輕雲自中峰。", "山暝學棲鳥，月來隨暗蛬。", "尋空靜餘響，嫋嫋雲溪鐘。"]'),
('f8f715e7-913e-4f72-b64b-f7fee66c4e06','古興','常建','唐','唐诗','tang','','["\u957f\u6c5f"]','漢上逢老翁，江口爲僵屍。',144,'全唐诗/poet.tang.6000.json','["漢上逢老翁，江口爲僵屍。", "白髮沾黃泥，遺骸集烏鴟。", "機巧自此忘，精魄今何之。", "風吹釣竿折，魚躍安能施。", "白水明汀洲，菰蒲冒深陂。", "唯留扁舟影，繫在長江湄。", "突兀枯松枝，悠揚女蘿絲。", "託身難憑依，生死焉相知。", "徧觀今時人，舉世皆爾爲。", "將軍死重圍，漢卒猶爭馳。", "百馬同一銜，萬輪同一規。", "名與身孰親，君子宜固思。"]'),
('8ce260b0-4dc4-43aa-b99a-c8dfc898d16d','高樓夜彈箏','常建','唐','唐诗','tang','','[]','高樓百餘尺，直上江水平。',48,'全唐诗/poet.tang.6000.json','["高樓百餘尺，直上江水平。", "明月照人苦，開簾彈玉箏。", "山高猿狖急，天靜鴻鴈鳴。", "曲度猶未終，東峰霞半生。"]'),
('c821bad8-1488-4a70-a291-3194bdf98869','客有自燕而歸哀其老而贈之','常建','唐','唐诗','tang','','[]','羸馬朝自燕，一身爲二連。',96,'全唐诗/poet.tang.6000.json','["羸馬朝自燕，一身爲二連。", "憶親拜孤冢，移葬雙陵前。", "幽願從此畢，劒心因獲全。", "孟冬寒氣盛，撫轡告言旋。", "碣石海北門，餘寇惟朝鮮。", "離離一寒騎，嫋嫋馳白天。", "生別皆自取，況爲士卒先。", "寸心漁陽興，落日旌竿懸。"]'),
('0ad743d3-64f7-4c13-b8a7-b6bba3223219','白龍窟汎舟寄天台學道者','常建','唐','唐诗','tang','','[]','夕映翠山深，餘暉在龍窟。',120,'全唐诗/poet.tang.6000.json','["夕映翠山深，餘暉在龍窟。", "扁舟滄浪意，澹澹花影沒。", "西浮入天色，南望對雲闕。", "因憶莓苔峰，初陽濯玄髮。", "泉蘿兩幽映，松鶴間清越。", "碧海瑩子神，玉膏澤人骨。", "忽然爲枯木，微興遂如兀。", "應寂中有天，明心外無物。", "環迴從所汎，夜靜猶不歇。", "澹然意無限，身與波上月。"]'),
('ed156f96-68db-4e04-a18c-661ebc02fcb8','張天師草堂','常建','唐','唐诗','tang','','[]','靈溪宴清宇，傍倚枯松根。',120,'全唐诗/poet.tang.6000.json','["靈溪宴清宇，傍倚枯松根。", "花藥繞方丈，瀑泉飛至門。", "四氣閉炎熱，兩崖改明昏。", "夜深月蹔皎，亭午朝始暾。", "信是天人居，幽幽寂無喧。", "萬壑應鳴磬，諸峰接一魂。", "遂登仙子谷，因醉田生樽。", "時節開玉書，窅映飛天言。", "心化便無影，目精焉累煩。", "忽而與霄漢，寥落空南軒。"]'),
('46d184bf-6716-4148-a817-ddae0ece7ef0','古意三首 一','常建','唐','唐诗','tang','','[]','二妃方訪舜，萬里南方懸。',84,'全唐诗/poet.tang.6000.json','["二妃方訪舜，萬里南方懸。", "遠道隔江漢，孤舟無歲年。", "不知蒼梧處，氣盡呼青天。", "愁淚變楚竹，蛾眉喪湘川。", "後人立爲廟，累世稱其賢。", "過客設祠祭，孤狸來坐邊。", "懷古未忍還，猿吟徹空山。"]'),
('afa12db7-68c8-42f5-8338-9878438f8237','古意三首 二','常建','唐','唐诗','tang','','[]','明月照高閣，綵女褰羅幕。',96,'全唐诗/poet.tang.6000.json','["明月照高閣，綵女褰羅幕。", "歌舞臨碧雲，簫聲沸珠箔。", "青鸞臨南海，天上雙白鶴。", "萬里齊翼飛，意求君門樂。", "玉霄九重閉，金鎖夜不開。", "兩翅自無力，愁鳴雲外來。", "態深入空貴，世屈無良媒。", "俛仰顧中禁，東飛白玉臺。"]'),
('a922a9e2-666a-4682-8f6d-f715262fb373','古意三首 三','常建','唐','唐诗','tang','','[]','楚王竟何去，獨自留巫山。',72,'全唐诗/poet.tang.6000.json','["楚王竟何去，獨自留巫山。", "偏使世人見，迢迢江漢間。", "駐舟春溪裏，皆願拜靈顏。", "寤寐見神女，金沙鳴珮環。", "閑豔絕世姿，令人氣力微。", "含笑竟不語，化作朝雲飛。"]'),
('89353814-9e6b-4241-9b7f-2110453c296b','漁浦','常建','唐','唐诗','tang','','[]','春至百草綠，陂澤聞鶬鶊。',72,'全唐诗/poet.tang.6000.json','["春至百草綠，陂澤聞鶬鶊。", "別家投釣翁，今世滄浪情。", "漚紵爲緼袍，折麻爲長纓。", "榮譽失本真，怪人浮此生。", "碧水月自闊，安流淨而平。", "扁舟與天際，獨往誰能名。"]'),
('1a94f81f-2c0d-4db5-bb7a-8ed7e791e7d5','空靈山應田叟','常建','唐','唐诗','tang','','[]','湖南無村落，山舍多黃茆。',144,'全唐诗/poet.tang.6000.json','["湖南無村落，山舍多黃茆。", "淳朴如太古，其人居鳥巢。", "牧童唱巴歌，野老亦獻嘲。", "泊舟問溪口，言語皆啞咬。", "土俗不尚農，豈暇論肥磽。", "莫傜射禽獸，浮客烹魚鮫。", "余亦罘罝人，獲麋今尚苞。", "敬君中國來，願以充其庖。", "日入聞虎鬬，空山滿咆哮。", "懷人雖共安，異域終難交。", "白水可洗心，采薇可爲肴。", "曳策背落日，江風鳴梢梢。"]'),
('4e6396b5-568c-4eca-b3d1-dcf62290c62e','太公哀晚遇','常建','唐','唐诗','tang','','[]','日出渭流白，文王畋獵時。',144,'全唐诗/poet.tang.6000.json','["日出渭流白，文王畋獵時。", "釣翁在蘆葦，川澤無熊羆。", "詔書起遺賢，匹馬令致辭。", "因稱江海人，臣老筋力衰。", "遲遲詣天車，快快悟靈龜。", "兵馬更不獵，君臣皆共怡。", "同車至咸陽，心影無磷緇。", "四牡玉墀下，一言爲帝師。", "王侯擁朱門，軒蓋曜長逵。", "古來榮華人，遭遇誰知之。", "落日懸桑榆，光景有頓虧。", "倏忽天地人，雖貴將何爲。"]'),
('74a19b6a-1837-4633-bb06-5d8027229cb5','昭君墓','常建','唐','唐诗','tang','','[]','漢宮豈不死，異域傷獨沒。',48,'全唐诗/poet.tang.6000.json','["漢宮豈不死，異域傷獨沒。", "萬里馱黃金，蛾眉爲枯骨。", "迴車夜出塞，立馬皆不發。", "共恨丹青人，墳上哭明月。"]'),
('c773c84d-c788-4650-8772-df213d4c0bb0','弔王將軍墓','常建','唐','唐诗','tang','','[]','嫖姚北伐時，深入強千里。',48,'全唐诗/poet.tang.6000.json','["嫖姚北伐時，深入強千里。", "戰餘落日黃，軍敗鼓聲死。", "嘗聞漢飛將，可奪單于壘。", "今與山鬼鄰，殘兵哭遼水。"]'),
('a7f07caf-48e3-444b-bc41-d7dc56175fd8','古意','常建','唐','唐诗','tang','','[]','井底玉冰洞地明，琥珀轆轤青絲索。',64,'全唐诗/poet.tang.6000.json','["井底玉冰洞地明，琥珀轆轤青絲索。", "仙人騎鳳披彩霞，挽上銀瓶照天閣。", "黃金作身雙飛龍，口銜明月噴芙蓉。", "一時渡海望不見，曉上青樓十二重。"]'),
('d76ad288-4ed5-47df-b27d-09b8d84eb883','古興','常建','唐','唐诗','tang','','[]','轆轤井上雙梧桐，飛鳥銜花日將沒。',64,'全唐诗/poet.tang.6000.json','["轆轤井上雙梧桐，飛鳥銜花日將沒。", "深閨女兒莫愁年，玉指泠泠怨金碧。", "石榴裙裾蛺蝶飛，見人不語顰蛾眉。", "青絲素絲紅綠絲，織成錦衾當爲誰。"]'),
('314fe39a-f774-497d-b473-d3e46252e1cf','張公子行','常建','唐','唐诗','tang','','[]','日出乘釣舟，嫋嫋持釣竿。',80,'全唐诗/poet.tang.6000.json','["日出乘釣舟，嫋嫋持釣竿。", "涉淇傍荷花，驄馬閑金鞍。", "俠客白雲中，腰間懸轆轤。", "出門事嫖姚，爲君西擊胡。", "胡兵漢騎相馳逐，轉戰孤軍西海北。", "百尺旌竿沈黑雲，邊笳落日不堪聞。"]'),
('5540f756-f737-4bbd-82da-4a3cc9ca1681','題破山寺後禪院','常建','唐','唐诗','tang','','[]','清晨入古寺，初日照高林。',48,'全唐诗/poet.tang.6000.json','["清晨入古寺，初日照高林。", "竹逕通幽處，禪房花木深。", "山光悅鳥性，潭影空人心。", "萬籟此都寂，但餘鐘磬音。"]'),
('cd7452c9-5a5f-4f8e-95b4-bc6298581eed','送李大都護','常建','唐','唐诗','tang','','[]','單于雖不戰，都護事邊深。',48,'全唐诗/poet.tang.6000.json','["單于雖不戰，都護事邊深。", "君執幕中秘，能爲高士心。", "海頭近初月，磧裏多愁陰。", "西望郭猶子，將分淚滿襟。"]'),
('ee8adc18-110d-4f91-9664-dea75f1d9034','潭州留別','常建','唐','唐诗','tang','','[]','賢達不相識，偶然交已深。',48,'全唐诗/poet.tang.6000.json','["賢達不相識，偶然交已深。", "宿帆謁郡佐，悵別依禪林。", "湘水流入海，楚雲千里心。", "望君杉松夜，山月清猿吟。"]'),
('1d341a95-4bf3-47c5-8582-a9338a141ce9','聽琴秋夜贈寇尊師','常建','唐','唐诗','tang','','[]','琴當秋夜聽，況是洞中人。',48,'全唐诗/poet.tang.6000.json','["琴當秋夜聽，況是洞中人。", "一指指應法，一聲聲爽神。", "寒蟲臨砌急，清吹褭燈頻。", "何必鍾期耳，高閑自可親。"]'),
('9e4f3eca-126b-4c57-9e4d-f99ca89a1590','泊舟盱眙','常建','唐','唐诗','tang','','[]','泊舟淮水次，霜降夕流清。',48,'全唐诗/poet.tang.6000.json','["泊舟淮水次，霜降夕流清。", "夜久潮侵岸，天寒月近城。", "平沙依鴈宿，候館聽雞鳴。", "鄉國雲霄外，誰堪羈旅情。"]'),
('07dae002-049f-4304-bf8f-d63b531a804d','江行','常建','唐','唐诗','tang','','[]','平湖四無際，此夜泛孤舟。',48,'全唐诗/poet.tang.6000.json','["平湖四無際，此夜泛孤舟。", "明月異方意，吳歌令客愁。", "鄉園碧雲外，兄弟淥江頭。", "萬里無歸信，傷心看斗牛。"]'),
('6d51ad8f-fc5c-4858-b56a-6301110f7581','燕居','常建','唐','唐诗','tang','','[]','青苔常滿路，流水復入林。',48,'全唐诗/poet.tang.6000.json','["青苔常滿路，流水復入林。", "遠與市朝隔，日聞雞犬深。", "寥寥丘中想，渺渺湖上心。", "嘯傲轉無欲，不知成陸沈。"]'),
('919f52f1-ac12-45ff-8e7b-5eab356e2851','送宇文六','常建','唐','唐诗','tang','','["\u9001\u522b", "\u6625\u5929", "\u5199\u666f", "\u6101\u82e6"]','花映垂楊漢水清，微風林裏一枝輕。',32,'全唐诗/poet.tang.6000.json','["花映垂楊漢水清，微風林裏一枝輕。", "即今江北還如此，愁殺江南離別情。"]'),
('59c1e828-a843-4397-8704-683245fc63c7','落第長安','常建','唐','唐诗','tang','','[]','家園好在尚留秦，耻作明時失路人。',32,'全唐诗/poet.tang.6000.json','["家園好在尚留秦，耻作明時失路人。", "恐逢故里鶯花笑，且向長安度一春。"]'),
('a41d66f5-0ea7-4958-a87e-3bb677936fec','塞下','常建','唐','唐诗','tang','','[]','鐵馬胡裘出漢營，分麾百道救龍城。',32,'全唐诗/poet.tang.6000.json','["鐵馬胡裘出漢營，分麾百道救龍城。", "左賢未遁旌竿折，過在將軍不在兵。"]'),
('f21311f0-f008-4418-b7d0-8077797c809c','題法院','常建','唐','唐诗','tang','','[]','勝景門閑對遠山，竹深松老半含煙。',32,'全唐诗/poet.tang.6000.json','["勝景門閑對遠山，竹深松老半含煙。", "皓月殿中三度磬，水晶宮裏一僧禪。"]'),
('3e42b317-cf60-444c-acce-85a2337fcd79','嶺猿','常建','唐','唐诗','tang','','[]','杳杳褭褭清且切，鷓鴣飛處又斜陽。',32,'全唐诗/poet.tang.6000.json','["杳杳褭褭清且切，鷓鴣飛處又斜陽。", "相思嶺上相思淚，不到三聲合斷腸。"]'),
('b720c5ef-f568-4560-8cef-07504b9bf710','三日尋李九莊','常建','唐','唐诗','tang','','[]','雨歇楊林東渡頭，永和三日盪輕舟。',32,'全唐诗/poet.tang.6000.json','["雨歇楊林東渡頭，永和三日盪輕舟。", "故人家在桃花岸，直到門前溪水流。"]'),
('e024d8a0-f723-4e71-afaa-0ad5b3cab9cb','塞下曲四首 一','常建','唐','唐诗','tang','','["\u53cb\u597d", "\u6c11\u65cf", "\u548c\u5e73", "\u8fb9\u585e"]','玉帛朝回望帝鄉，烏孫歸去不稱王。',32,'全唐诗/poet.tang.6000.json','["玉帛朝回望帝鄉，烏孫歸去不稱王。", "天涯靜處無征戰，兵氣銷爲日月光。"]'),
('853b888e-e5c3-4e81-817f-231e2a0268eb','塞下曲四首 二','常建','唐','唐诗','tang','','[]','北海陰風動地來，明君祠上望龍堆。',32,'全唐诗/poet.tang.6000.json','["北海陰風動地來，明君祠上望龍堆。", "髑髏皆是長城卒，日暮沙場飛作灰。"]'),
('b100bff8-009f-40b8-83bd-9b8a7baa80c3','塞下曲四首 三','常建','唐','唐诗','tang','','["\u9ec4\u6cb3"]','龍鬬雌雄勢已分，山崩鬼哭恨將軍。',32,'全唐诗/poet.tang.6000.json','["龍鬬雌雄勢已分，山崩鬼哭恨將軍。", "黃河直北千餘里，冤氣蒼茫成黑雲。"]'),
('fc45c575-e72c-4018-bc4c-283d06fe3ac2','塞下曲四首 四','常建','唐','唐诗','tang','','[]','因嫁單于怨在邊，蛾眉萬古葬胡天。',32,'全唐诗/poet.tang.6000.json','["因嫁單于怨在邊，蛾眉萬古葬胡天。", "漢家此去三千里，青冢常無草木煙。"]'),
('633a03fa-64cf-445f-bb15-375f23a1fb03','戲題湖上','常建','唐','唐诗','tang','','[]','湖上老人坐磯頭，湖裏桃花水却流。',32,'全唐诗/poet.tang.6000.json','["湖上老人坐磯頭，湖裏桃花水却流。", "竹竿嫋嫋白波際，不知何者吞吾鈎。"]'),
('83763f28-847b-4d87-bc73-806a44aceeab','吳故宮','常建','唐','唐诗','tang','','[]','越女歌長君且聽，芙蓉香滿水邊城。',32,'全唐诗/poet.tang.6000.json','["越女歌長君且聽，芙蓉香滿水邊城。", "豈知一日終非主，猶自如今有怨聲。"]'),
('0998d479-5f24-4e6f-b765-4e844c616c87','從軍行','杜頠','唐','唐诗','tang','','[]','秋草馬蹄輕，角弓持弦急。',96,'全唐诗/poet.tang.6000.json','["秋草馬蹄輕，角弓持弦急。", "去爲龍城候，正值胡兵襲。", "軍氣橫大荒，戰酣日將入。", "長風金鼓動，白露鐵衣濕。", "四起愁邊聲，南轅時佇立。", "斷蓬孤自轉，寒雁飛相及。", "萬里雲沙漲，平川冰霰溢。", "夜聞漢使歸，獨向刀環泣。"]'),
('02ff3c25-350b-473d-9a94-33a8d394510a','故絳行','杜頠','唐','唐诗','tang','','[]','君不見銅鞮觀，數里城池已蕪漫。',62,'全唐诗/poet.tang.6000.json','["君不見銅鞮觀，數里城池已蕪漫。", "君不見虒祁宮，幾重臺榭亦微濛。", "介馬兵車全盛時，歌童舞女妖豔姿。", "一代繁華皆共絕，九原唯望冢纍纍。"]'),
('10d575b4-bb09-484e-9d32-6764aceb5431','少年行三首 一','李嶷','唐','唐诗','tang','','[]','十八羽林郎，戎衣侍漢王。',36,'全唐诗/poet.tang.6000.json','["十八羽林郎，戎衣侍漢王。", "臂鷹金殿側，挾彈玉輿傍。", "馳道春風起，陪游出建章。"]'),
('ea4d86e4-7e99-4404-8373-20ab148106ff','少年行三首 二','李嶷','唐','唐诗','tang','','[]','侍獵長楊下，承恩更射飛。',36,'全唐诗/poet.tang.6000.json','["侍獵長楊下，承恩更射飛。", "塵生馬影滅，箭落雁行稀。", "薄暮隨天仗，聯翩入瑣闈。"]'),
('4ad8c14b-6ff5-4140-8ef0-2293c9019aa0','少年行三首 三','李嶷','唐','唐诗','tang','','[]','玉劒膝邊橫，金杯馬上傾。',36,'全唐诗/poet.tang.6000.json','["玉劒膝邊橫，金杯馬上傾。", "朝遊茂陵道，夜宿鳳凰城。", "豪吏多猜忌，無勞問姓名。"]'),
('8d3a6bc0-2f88-486c-9c67-389315f8cf44','淮南秋夜呈周偘','李嶷','唐','唐诗','tang','','[]','天淨河漢高，夜閑砧杵發。',48,'全唐诗/poet.tang.6000.json','["天淨河漢高，夜閑砧杵發。", "清秋忽如此，離恨應難歇。", "風亂池上萍，露光竹間月。", "與君共遊處，勿作他鄉別。"]'),
('faf772a9-2cb6-4a3c-b785-6a0c98cad64e','林園秋夜作','李嶷','唐','唐诗','tang','','[]','林臥避殘暑，白雲長在天。',48,'全唐诗/poet.tang.6000.json','["林臥避殘暑，白雲長在天。", "賞心既如此，對酒非徒然。", "月色徧秋露，竹聲兼夜泉。", "涼風懷袖裏，茲意與誰傳。"]'),
('65fa0e28-d352-4d6e-8960-6da901fa11e6','讀前漢外戚傳','李嶷','唐','唐诗','tang','','[]','人錄尚書事，家臨御路傍。',48,'全唐诗/poet.tang.6000.json','["人錄尚書事，家臨御路傍。", "鑿池通渭水，避暑借明光。", "印綬妻封邑，軒車子拜郎。", "寵因宮掖裏，勢極必先亡。"]'),
('02e8f924-0c33-4a86-9266-2a13abe5c696','春怨','崔亘','唐','唐诗','tang','','[]','夜盡夢初驚，紗窗早霧明。',48,'全唐诗/poet.tang.6000.json','["夜盡夢初驚，紗窗早霧明。", "曉妝脂粉薄，春服綺羅輕。", "妾有今朝恨，君無舊日情。", "愁來理弦管，皆是斷腸聲。"]'),
('8578a667-3a00-467d-bac5-9221d94d826c','古歌二首 一','蔣維翰','唐','唐诗','tang','','[]','美人怨何深，含情倚金閣。',24,'全唐诗/poet.tang.6000.json','["美人怨何深，含情倚金閣。", "不嚬復不語，紅淚雙雙落。"]'),
('2af05db1-1539-4f04-bd9e-e0edb8c2c383','古歌二首 二','蔣維翰','唐','唐诗','tang','','[]','美人閉紅燭，獨作裁新錦。',24,'全唐诗/poet.tang.6000.json','["美人閉紅燭，獨作裁新錦。", "頻放剪刀聲，夜寒知未寢。"]'),
('e4718069-a1f2-4fb2-8616-155260b0953f','春夜裁縫','蔣維翰','唐','唐诗','tang','','[]','珠箔因風起，飛蛾入最能。',24,'全唐诗/poet.tang.6000.json','["珠箔因風起，飛蛾入最能。", "不教人夜作，方便殺明燈。"]'),
('127fe4ff-3d28-41fa-adb7-7f0822e1c30c','春女怨','蔣維翰','唐','唐诗','tang','','[]','白玉堂前一樹梅，今朝忽見數花開。',32,'全唐诗/poet.tang.6000.json','["白玉堂前一樹梅，今朝忽見數花開。", "兒家門戶尋常閉，春色因何入得來。"]'),
('a54dc2be-9c56-4723-8f35-1d358cfc3ea6','怨歌','蔣維翰','唐','唐诗','tang','','[]','百尺珠樓臨狹斜，新妝能唱美人車。',32,'全唐诗/poet.tang.6000.json','["百尺珠樓臨狹斜，新妝能唱美人車。", "皆言賤妾紅顏好，要自狂夫不憶家。"]'),
('e10145cb-2c2f-43bc-bdf6-bb94e0c7a40f','小山歌','萬楚','唐','唐诗','tang','','[]','人說淮南有小山，淮王昔日此登仙。',128,'全唐诗/poet.tang.6000.json','["人說淮南有小山，淮王昔日此登仙。", "城中雞犬皆飛去，山上壇場今宛然。", "世人貴身不貴壽，共笑華陽洞天口。", "不知金石變長年，謾在人間戀攜手。", "君能舉帆至淮南，家住盱眙余先諳。", "桐柏亂流平入海，茱萸一曲沸成潭。", "憶記來時魂悄悄，想見仙山衆峰小。", "今日長歌思不堪，君行爲報三青鳥。"]'),
('3e8a3b21-2b60-4a23-9aaa-2c25e113518a','題江潮莊壁','萬楚','唐','唐诗','tang','','[]','田家喜秋熟，歲[晏]林葉稀。',50,'全唐诗/poet.tang.6000.json','["田家喜秋熟，歲[晏]林葉稀。", "禾黍積場圃，𣙁梨垂戶扉。", "野閑犬時吠，日暮牛自歸。", "時復落花酒，茅齋堪解衣。"]'),
('9bcc5817-9e08-4811-a05f-a9b346151cd8','詠簾','萬楚','唐','唐诗','tang','','[]','玳瑁昔稱華，玲瓏薄絳紗。',48,'全唐诗/poet.tang.6000.json','["玳瑁昔稱華，玲瓏薄絳紗。", "鉤銜門勢曲，節亂水紋斜。", "日弄長飛鳥，風搖不卷花。", "自當分內外，非是爲驕奢。"]'),
('f110f0c4-fbae-4e1b-80bb-52ee4bbe33b6','茱萸女','萬楚','唐','唐诗','tang','','[]','山陰柳家女，九日采茱萸。',84,'全唐诗/poet.tang.6000.json','["山陰柳家女，九日采茱萸。", "復得東鄰伴，雙爲陌上姝。", "插枝著高髻，結子置長裾。", "作性常遲緩，非關詫丈夫。", "平明折林樾，日入返城隅。", "俠客要羅袖，行人挑短書。", "蛾眉自有主，年少莫踟躕。"]'),
('97365d11-edc4-47aa-aa05-78654603b652','五日觀妓','萬楚','唐','唐诗','tang','','[]','西施謾道浣春紗，碧玉今時鬬麗華。',64,'全唐诗/poet.tang.6000.json','["西施謾道浣春紗，碧玉今時鬬麗華。", "眉黛奪將萱草色，紅裙妬殺石榴花。", "新歌一曲令人豔，醉舞雙眸斂鬢斜。", "誰道五絲能續命，却令今日死君家。"]'),
('3b69822f-7c9f-4aab-8f7e-274dbd3b229e','驄馬','萬楚','唐','唐诗','tang','','["\u9a6c", "\u5199\u9a6c"]','金絡青驄白玉鞍，長鞭紫陌野遊盤。',64,'全唐诗/poet.tang.6000.json','["金絡青驄白玉鞍，長鞭紫陌野遊盤。", "朝驅東道塵恆滅，暮到河源日未闌。", "汗血每隨邊地苦，蹄傷不憚隴陰寒。", "君能一飲長城窟，爲報天山行路難。"]'),
('22862542-4b60-49e2-984e-5f3a2fd3a45b','題情人藥欄','萬楚','唐','唐诗','tang','','[]','斂眉語芳草，何許太無情。',24,'全唐诗/poet.tang.6000.json','["斂眉語芳草，何許太無情。", "正見離人別，春心相向生。"]'),
('8641e63f-7257-4bb4-aea0-eddbdd97f4f5','河上逢落花','萬楚','唐','唐诗','tang','','[]','河水浮落花，花流東不息。',24,'全唐诗/poet.tang.6000.json','["河水浮落花，花流東不息。", "應見浣紗人，爲道長相憶。"]'),
('d9eb0282-e880-4f7b-8044-f4fd06c529b0','寧王山池','范朝','唐','唐诗','tang','','[]','水勢臨階轉，峰形對路開。',48,'全唐诗/poet.tang.6000.json','["水勢臨階轉，峰形對路開。", "槎從天上得，石是海邊來。", "瑞草分叢種，祥花間色栽。", "舊傳詞賦客，唯見有鄒枚。"]'),
('395eb911-96a8-4ef7-a2f6-7b052971a729','題石甕寺','范朝','唐','唐诗','tang','','[]','勝境宜長望，遲春好散愁。',48,'全唐诗/poet.tang.6000.json','["勝境宜長望，遲春好散愁。", "關連四塞起，河帶八川流。", "複磴承香閣，重巖映彩樓。", "爲臨溫液近，偏美聖君遊。"]'),
('98d7814c-254a-45cd-a24f-fc41ad3bc777','田家','楊顔','唐','唐诗','tang','','[]','小園足生事，尋勝日傾壺。',48,'全唐诗/poet.tang.6000.json','["小園足生事，尋勝日傾壺。", "蒔蔬利於鬻，纔青摘已無。", "四鄰依野竹，日夕采其枯。", "田家心適時，春色徧桑榆。"]'),
('f54ee0d6-5962-49a4-8f61-f7b237d3ba82','後庭怨','王諲','唐','唐诗','tang','','[]','君不見紅閨少女端正時，夭夭桃李仙容姿。',211,'全唐诗/poet.tang.6000.json','["君不見紅閨少女端正時，夭夭桃李仙容姿。", "幸得君王憐巧笑，披香殿裏薦蛾眉。", "蛾眉雙雙人共進，常恐妾身從此擯。", "甄妃爲妬出層宮，班女因猜下長信。", "長信宮門閉不開，昭陽歌吹風送來。", "夢中魂魄猶言是，覺後精神尚未迴。", "念君嬌愛無終始，使妾長啼後庭裏。", "獨立每看斜日盡，孤眠直至殘燈死。", "秋日聞蟲翡翠簾，春晴照面鴛鴦水。", "紅顏舊來花不勝，白髮如今雪相似。", "傳聞紈扇恩未歇，預想蛾眉上初月。", "如君貴僞不貴真，還同棄妾逐新人。", "借問南山松葉意，何如北砌槿花新。"]'),
('ef8d91e8-d06c-47e0-8aeb-3fa9196ef1d1','夜坐看搊箏','王諲','唐','唐诗','tang','','[]','調箏夜坐燈光裏，却挂羅帷露纖指。',64,'全唐诗/poet.tang.6000.json','["調箏夜坐燈光裏，却挂羅帷露纖指。", "朱弦一一聲不同，玉柱連連影相似。", "不知何處學新聲？曲曲彈來未覩名。", "應是石家金谷裏，流傳未滿洛陽城。"]'),
('fc951b61-f1d8-4037-8b21-7f171ec28657','長信怨','王諲','唐','唐诗','tang','','[]','飛燕倚身輕，爭人巧笑名。',48,'全唐诗/poet.tang.6000.json','["飛燕倚身輕，爭人巧笑名。", "生君棄妾意，增妾怨君情。", "日落昭陽壁，秋來長信城。", "寥寥金殿裏，歌吹夜無聲。"]'),
('8da1a43c-1095-4175-9699-33b78b07e39c','閨情','王諲','唐','唐诗','tang','','[]','日暮裁縫歇，深嫌氣力微。',48,'全唐诗/poet.tang.6000.json','["日暮裁縫歇，深嫌氣力微。", "纔能收篋笥，嬾起下簾帷。", "怨坐空然燭，愁眠不解衣。", "昨來頻夢見，夫婿莫應知。"]'),
('27592e5e-c5f9-4826-abdd-d4da555ef66f','十五夜觀燈','王諲','唐','唐诗','tang','','[]','暫得金吾夜，通看火樹春。',48,'全唐诗/poet.tang.6000.json','["暫得金吾夜，通看火樹春。", "停車傍明月，走馬入紅塵。", "妓雜歌偏勝，場移舞更新。", "應須盡記取，說向不來人。"]'),
('492011a3-1deb-45e8-a491-d80057e14f2b','除夜','王諲','唐','唐诗','tang','','["\u6625\u8282"]','今歲今宵盡，明年明日催。',48,'全唐诗/poet.tang.6000.json','["今歲今宵盡，明年明日催。", "寒隨一夜去，春逐五更來。", "氣色空中改，容顏暗裏回。", "風光人不覺，已著後園梅。"]'),
('2bcb3ce0-c2e3-46e6-8e84-4979ad19e132','聞漏','王岳靈','唐','唐诗','tang','','[]','建禮含香處，重城待漏臣。',72,'全唐诗/poet.tang.6000.json','["建禮含香處，重城待漏臣。", "徐聞傳鳳詔，曉唱辨雞人。", "銀箭殘將盡，銅壺漏更新。", "催籌當午夜，移刻及三辰。", "杳杳從天遠，泠泠出禁頻。", "直疑殘漏曙，肅肅對鉤陳。"]'),
('703071c8-eb54-4f94-ad73-a20ed9b37969','送沈芳謁李觀察求仕進','周萬','唐','唐诗','tang','','[]','往日長安路，歡遊不惜年。',48,'全唐诗/poet.tang.6000.json','["往日長安路，歡遊不惜年。", "爲貪盧女曲，用盡沈郎錢。", "身老方投刺，途窮始著鞭。", "猶聞有知己，此去不徒然。"]'),
('08f269ce-00ef-4850-9c43-ba832d916b5d','古塞下曲','陶翰','唐','唐诗','tang','','[]','進軍飛狐北，窮寇勢將變。',72,'全唐诗/poet.tang.6000.json','["進軍飛狐北，窮寇勢將變。", "日落沙塵昏，背河更一戰。", "騂馬黃金勒，琱弓白羽箭。", "射殺左賢王，歸奏未央殿。", "欲言塞下事，天子不召見。", "東出咸陽門，哀哀淚如霰。"]'),
('6b679a77-603e-41c6-af12-2d19d36027e5','燕歌行','陶翰','唐','唐诗','tang','','[]','請君留楚調，聽我吟燕歌。',108,'全唐诗/poet.tang.6000.json','["請君留楚調，聽我吟燕歌。", "家在遼水頭，邊風意氣多。", "出身爲漢將，正值戎未和。", "雪中凌天山，冰上渡交河。", "大小百餘戰，封侯竟蹉跎。", "歸來灞陵下，故舊無相過。", "雄劒委塵匣，空門垂雀羅。", "玉簪還趙女，寶瑟付齊娥。", "昔日不爲樂，時哉今奈何。"]'),
('288028bb-696b-41c1-b0f8-70445a11f6ab','望太華贈盧司倉','陶翰','唐','唐诗','tang','','[]','行吏到西華，乃觀三峯壯。',96,'全唐诗/poet.tang.6000.json','["行吏到西華，乃觀三峯壯。", "削成元氣中，傑出天河上。", "如有飛動色，不知青冥狀。", "巨靈安在哉，厥跡猶可望。", "方此顧行旅，末由飭仙裝。", "葱蘢記星壇，明滅數雲嶂。", "良友垂真契，宿心所微尚。", "敢投歸山吟，霞徑一相訪。"]'),
('1c3b235a-5cff-4fe7-9be3-4fe8bd4223d7','贈鄭員外','陶翰','唐','唐诗','tang','','[]','驄馬拂繡裳，按兵遼水陽。',120,'全唐诗/poet.tang.6000.json','["驄馬拂繡裳，按兵遼水陽。", "西分鴈門騎，北逐樓煩王。", "聞道五軍集，相邀百戰場。", "風沙暗天起，虜騎森已行。", "儒服揖諸將，雄謀吞大荒。", "金門來見謁，朱紱生輝光。", "數年侍御史，稍遷尚書郎。", "人生志氣立，所貴功業昌。", "何必守章句，終年事鉛黃。", "同時獻賦客，尚在東陵傍。"]'),
('7e97baf7-35e2-49e3-8031-262737c209a4','贈房侍御','陶翰','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','志士固不羈，與道常周旋。',180,'全唐诗/poet.tang.6000.json','["志士固不羈，與道常周旋。", "進則天下仰，已之能晏然。", "褐衣東府召，執簡南臺先。", "雄義每特立，犯顏豈圖全。", "謫居東南遠，逸氣吟芳荃。", "適會寥廓趣，清波更夤緣。", "扁舟入五湖，發纜洞庭前。", "浩蕩臨海曲，迢遙濟江壖。", "徵奇忽忘返，遇興將彌年。", "乃悟范生智，足明漁父賢。", "郡臨新安渚，佳賞此城偏。", "日夕對層岫，雲霞映晴川。", "閑居戀秋色，偃臥含貞堅。", "倚伏聊自化，行藏互推遷。", "君其振羽翮，歲晏將沖天。"]'),
('88ff36cb-5849-4f22-be1d-afb31aae2464','晚出伊闕寄河南裴中丞','陶翰','唐','唐诗','tang','','[]','退無偃息資，進無當代策。',108,'全唐诗/poet.tang.6000.json','["退無偃息資，進無當代策。", "冉冉時將暮，坐爲周南客。", "前登闕塞門，永眺伊城陌。", "長川黯已空，千里寒氣白。", "家本渭水西，異日同所適。", "秉志師禽尚，微言祖莊易。", "一辭林壑間，共繫風塵役。", "交朋忽先進，天道何紛劇。", "豈念嘉遯時，依依偶沮溺。"]'),
('6aeb1e03-bf9c-4f60-b55e-15bdba02e071','送朱大出關','陶翰','唐','唐诗','tang','','[]','楚客西上書，十年不得意。',84,'全唐诗/poet.tang.6000.json','["楚客西上書，十年不得意。", "平生相知者，晚節心各異。", "長揖五侯門，拂衣謝中貴。", "丈夫多別離，各有四方事。", "拔劒因高歌，蕭蕭北風至。", "故人有斗酒，是夜共君醉。", "努立強加餐，當年莫相棄。"]'),
('77a9db1a-843a-4f1e-893b-eff8de2e942f','宿天竺寺','陶翰','唐','唐诗','tang','','[]','松柏亂巖口，山西微徑通。',120,'全唐诗/poet.tang.6000.json','["松柏亂巖口，山西微徑通。", "天開一峯見，宮闕生虛空。", "正殿倚霞壁，千樓標石叢。", "夜來猨鳥靜，鐘梵響雲中。", "岑翠映湖月，泉聲亂溪風。", "心超諸境外，了與懸解同。", "明發唯改視，朝日長崖東。", "湖色濃蕩漾，海光漸曈朦。", "葛仙迹尚在，許氏道猶崇。", "獨往古來事，幽懷期二公。"]'),
('52798823-905e-4f6f-8ef6-31a922343af2','出蕭關懷古','陶翰','唐','唐诗','tang','','[]','驅馬擊長劒，行役至蕭關。',122,'全唐诗/poet.tang.6000.json','["驅馬擊長劒，行役至蕭關。", "悠悠五原上，永眺關河前。", "北虜三十萬，此中常控弦。", "秦城亙宇宙，漢帝理旌旃。", "刁斗鳴不息，羽書日夜傳。", "五軍計莫就，三策議空全。", "大漠橫萬里，蕭條絕人煙。", "孤城當瀚海，落日照[祁]連。", "愴矣苦寒奏，懷哉式微篇。", "更悲秦樓月，夜夜出胡天。"]'),
('f7c45ade-6b80-40a6-a621-3e157955d09a','南楚懷古','陶翰','唐','唐诗','tang','','[]','南國久蕪漫，我來空鬱陶。',96,'全唐诗/poet.tang.6000.json','["南國久蕪漫，我來空鬱陶。", "君看章華宮，處處生黃蒿。", "但見陵與谷，豈知賢與豪。", "精魂托古木，寶玉捐江臯。", "倚棹下晴景，迴舟隨晚濤。", "碧雲暮寥落，湖上秋天高。", "往事那堪問，此心徒自勞。", "獨餘湘水上，千載聞離騷。"]'),
('181c920a-cef9-4ffc-a3ba-febc3f6cf910','經殺子谷','陶翰','唐','唐诗','tang','','[]','扶蘇秦帝子，舉代稱其賢。',72,'全唐诗/poet.tang.7000.json','["扶蘇秦帝子，舉代稱其賢。", "百萬猶在握，可爭天下權。", "束身就一劒，壯志皆棄捐。", "塞下有遺跡，千齡人共傳。", "疎蕪盡荒草，寂歷空寒煙。", "到此盡垂淚，非我獨潸然。"]'),
('74cf4e44-0bf1-41af-8198-fe5d5c07f6d2','早過臨淮','陶翰','唐','唐诗','tang','','[]','夜來三渚風，晨過臨淮島。',84,'全唐诗/poet.tang.7000.json','["夜來三渚風，晨過臨淮島。", "湖中海氣白，城上楚雲早。", "鱗鱗魚浦帆，漭漭蘆洲草。", "川路日浩蕩，惄焉心如擣。", "且言任倚伏，何暇念枯槁。", "范子名屢移，蘧公志常保。", "古人去已久，此理今難道。"]'),
('2642d673-aed4-4bf6-bb15-cbb312fcaaba','乘潮至漁浦作','陶翰','唐','唐诗','tang','','[]','艤棹乘早潮，潮來如風雨。',96,'全唐诗/poet.tang.7000.json','["艤棹乘早潮，潮來如風雨。", "樟臺忽已隱，界峯莫及覩。", "崩騰心爲失，浩蕩目無主。", "豗𢟸浪始聞，漾漾入魚浦。", "雲景共澄霽，江山相吞吐。", "偉哉造化工，此事從終古。", "流沫誠足誡，商歌調易苦。", "頗因忠信全，客心猶栩栩。"]'),
('b4a21dc1-a089-4f9b-be25-fa0e4e2ce12b','秋山夕興','陶翰','唐','唐诗','tang','','[]','山月松篠下，月明山景鮮。',48,'全唐诗/poet.tang.7000.json','["山月松篠下，月明山景鮮。", "聊爲高秋酌，復此清夜弦。", "晤語方獲志，栖心亦彌年。", "尚言興未逸，更理逍遙篇。"]'),
('01e8361e-5f66-487f-8291-d4075a3f5808','送集賢學士伊闕史少府敕放歸江東覲省','陶翰','唐','唐诗','tang','','[]','墨客鍾張侶，材高吳越珍。',48,'全唐诗/poet.tang.7000.json','["墨客鍾張侶，材高吳越珍。", "千門來謁帝，駟馬去榮親。", "吏邑沿清洛，鄉山指白蘋。", "歸期應不遠，當及未央春。"]'),
('4b4bc0ca-877b-4720-897d-5df888c3cead','送金卿歸新羅','陶翰','唐','唐诗','tang','','[]','奉義朝中國，殊恩及遠臣。',72,'全唐诗/poet.tang.7000.json','["奉義朝中國，殊恩及遠臣。", "鄉心遙渡海，客路再經春。", "落日誰同望，孤舟獨可親。", "拂波銜木鳥，偶宿泣珠人。", "禮樂夷風變，衣冠漢制新。", "青雲已干呂，知汝重來賓。"]'),
('ca85e40d-6a68-4409-b6de-7b11f643606a','柳陌聽早鶯','陶翰','唐','唐诗','tang','','[]','忽來枝上囀，還似谷中聲。',72,'全唐诗/poet.tang.7000.json','["忽來枝上囀，還似谷中聲。", "乍使香閨靜，偏傷遠客情。", "間關難辨處，斷續若頻驚。", "玉勒留將久，青樓夢不成。", "千門候曉發，萬井報春生。", "徒有知音賞，慙非臯鶴鳴。"]'),
('5eac7283-4608-4d88-b0cb-ee7411c518c3','逢雪宿芙蓉山主人','劉長卿','唐','唐诗','tang','','["\u5c71\u6751", "\u98ce", "\u5199\u96ea", "\u51ac\u5929", "\u5199\u666f", "\u5199\u98ce"]','日暮蒼山遠，天寒白屋貧。',24,'全唐诗/poet.tang.7000.json','["日暮蒼山遠，天寒白屋貧。", "柴門聞犬吠，風雪夜歸人。"]'),
('c301003b-b4ff-43b3-9da0-05b10a9058a6','送張起崔載華之閩中','劉長卿','唐','唐诗','tang','','[]','朝無寒士達，家在舊山貧。',24,'全唐诗/poet.tang.7000.json','["朝無寒士達，家在舊山貧。", "相送天涯裏，憐君更遠人。"]'),
('b197c18b-b43e-413a-b016-8b6c599de9d0','贈秦系徵君','劉長卿','唐','唐诗','tang','','[]','羣公誰讓位，五柳獨知貧。',24,'全唐诗/poet.tang.7000.json','["羣公誰讓位，五柳獨知貧。", "惆悵青山路，煙霞老此人。"]'),
('61660bb7-421b-49fe-b7c1-2e48c81dec48','秦系頃以家事獲謗因出舊山每荷觀察崔公見知欲歸未遂感其流寓詩以贈之','劉長卿','唐','唐诗','tang','','[]','初迷武陵路，復出孟嘗門。',24,'全唐诗/poet.tang.7000.json','["初迷武陵路，復出孟嘗門。", "迴首江南岸，青山與舊恩。"]'),
('393cf16f-f815-4ddb-b5ec-a9133286c25f','夜中對雪贈秦系時秦初與謝氏離婚謝氏在越','劉長卿','唐','唐诗','tang','','[]','月明花滿地，君自憶山陰。',24,'全唐诗/poet.tang.7000.json','["月明花滿地，君自憶山陰。", "誰遣因風起，紛紛亂此心。"]'),
('48920104-8336-4488-8f02-08070809571f','湘妃','劉長卿','唐','唐诗','tang','','[]','帝子不可見，秋風來暮思。',24,'全唐诗/poet.tang.7000.json','["帝子不可見，秋風來暮思。", "嬋娟湘江月，千載空蛾眉。"]'),
('506ffe5f-35eb-4cd1-b50a-de2401932b65','斑竹','劉長卿','唐','唐诗','tang','','[]','蒼梧千載後，斑竹對湘沅。',24,'全唐诗/poet.tang.7000.json','["蒼梧千載後，斑竹對湘沅。", "欲識湘妃怨，枝枝滿淚痕。"]'),
('78f444fc-fa03-47bc-aab9-e48a544a6e20','春草宮懷古','劉長卿','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6000\u53e4\u4f24\u4eca"]','君王不可見，芳草舊宮春。',24,'全唐诗/poet.tang.7000.json','["君王不可見，芳草舊宮春。", "猶帶羅裙色，青青向楚人。"]'),
('ce4c0235-dbbf-49ba-9014-f7a8e24d3399','正朝覽鏡作','劉長卿','唐','唐诗','tang','','[]','憔悴逢新歲，茅扉見舊春。',24,'全唐诗/poet.tang.7000.json','["憔悴逢新歲，茅扉見舊春。", "朝來明鏡裏，不忍白頭人。"]'),
('4d302830-ff62-41d8-a918-a0d810b8f62b','瓜洲道中送李端公南渡後歸揚州道中寄','劉長卿','唐','唐诗','tang','','[]','片帆何處去，匹馬獨歸遲。',24,'全唐诗/poet.tang.7000.json','["片帆何處去，匹馬獨歸遲。", "惆悵江南北，青山欲暮時。"]'),
('539e03bc-d6e5-4053-bf4b-6ea177c61ffa','送張十八歸桐廬','劉長卿','唐','唐诗','tang','','[]','歸人乘野艇，帶月過江村。',24,'全唐诗/poet.tang.7000.json','["歸人乘野艇，帶月過江村。", "正落寒潮水，相隨夜到門。"]'),
('6fe29a18-8fa8-455e-83d7-ddb29a625ce0','過白鶴觀尋岑秀才不遇','劉長卿','唐','唐诗','tang','','[]','不知方外客，何事鎖空房。',24,'全唐诗/poet.tang.7000.json','["不知方外客，何事鎖空房。", "應向桃源裏，教他喚阮郎。"]'),
('72aab9ef-65a9-4a8a-b36b-61932c09ce85','聽彈琴','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6292\u60c5", "\u97f3\u4e50", "\u4e94\u8a00\u7edd\u53e5"]','泠泠七絲上，靜聽松風寒。',24,'全唐诗/poet.tang.7000.json','["泠泠七絲上，靜聽松風寒。", "古調雖自愛，今人多不彈。"]'),
('a3ee12cc-1478-41a5-9cdc-f82a70fa90fb','遊南園偶見在陰牆下葵因以成詠','劉長卿','唐','唐诗','tang','','[]','此地常無日，青青獨在陰。',24,'全唐诗/poet.tang.7000.json','["此地常無日，青青獨在陰。", "太陽偏不及，非是未傾心。"]'),
('e9d2bec9-272c-4d5e-aa67-548ff92c576d','入百丈澗見桃花晚開','劉長卿','唐','唐诗','tang','','[]','百丈深澗裏，過時花欲妍。',24,'全唐诗/poet.tang.7000.json','["百丈深澗裏，過時花欲妍。", "應緣地勢下，遂使春風偏。"]'),
('d0bfa4bd-c34d-4630-a422-e01102755400','送子壻崔真甫李穆往揚州四首 一','劉長卿','唐','唐诗','tang','','[]','渡口發梅花，山中動泉脉。',24,'全唐诗/poet.tang.7000.json','["渡口發梅花，山中動泉脉。", "蕪城春草生，君作揚州客。"]'),
('ed49fd88-07ba-41d6-b957-c983633b2a06','送子壻崔真甫李穆往揚州四首 二','劉長卿','唐','唐诗','tang','','[]','半邏鶯滿樹，新年人獨還。',24,'全唐诗/poet.tang.7000.json','["半邏鶯滿樹，新年人獨還。", "落花逐流水，共到茱萸灣。"]'),
('7980b3d6-850a-4d8c-a4c0-890581f453d6','送子壻崔真甫李穆往揚州四首 三','劉長卿','唐','唐诗','tang','','[]','雁還空渚在，人去落潮翻。',24,'全唐诗/poet.tang.7000.json','["雁還空渚在，人去落潮翻。", "臨水獨揮手，殘陽歸掩門。"]'),
('359da2a4-ee32-42bf-ac5c-a397d47446a9','送子壻崔真甫李穆往揚州四首 四','劉長卿','唐','唐诗','tang','','[]','狎鳥攜稚子，釣魚終老身。',24,'全唐诗/poet.tang.7000.json','["狎鳥攜稚子，釣魚終老身。", "殷勤囑歸客，莫話桃源人。"]'),
('40e43965-68d5-4638-ac93-4561874374de','寄龍山道士許法稜','劉長卿','唐','唐诗','tang','','[]','悠悠白雲裏，獨住青山客。',24,'全唐诗/poet.tang.7000.json','["悠悠白雲裏，獨住青山客。", "林下晝焚香，桂花同寂寂。"]'),
('c26445b5-a433-4cd7-9020-435866b845f9','送方外上人','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9001\u522b", "\u4e94\u8a00\u7edd\u53e5"]','孤雲將野鶴，豈向人間住。',24,'全唐诗/poet.tang.7000.json','["孤雲將野鶴，豈向人間住。", "莫買沃洲山，時人已知處。"]'),
('a746d1f0-a72c-44d2-8b1c-c5c990749257','送靈澈上人','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5c71\u6c34", "\u6292\u60c5", "\u9001\u522b", "\u521d\u4e2d\u53e4\u8bd7", "\u5373\u666f\u6292\u60c5"]','蒼蒼竹林寺，杳杳鐘聲晚。',24,'全唐诗/poet.tang.7000.json','["蒼蒼竹林寺，杳杳鐘聲晚。", "荷笠帶夕陽，青山獨歸遠。"]'),
('e155e372-4f5a-4b99-8944-9143800a81f0','茱萸灣北荅崔載華問','劉長卿','唐','唐诗','tang','','[]','荒涼野店絕，迢遰人煙遠。',24,'全唐诗/poet.tang.7000.json','["荒涼野店絕，迢遰人煙遠。", "蒼蒼古木中，多是隋家苑。"]'),
('2d1a5800-b30e-4ebe-b0ed-6f4557de3b05','赴楚州次自田途中阻淺問張南史','劉長卿','唐','唐诗','tang','','[]','楚城今近遠，積靄寒塘暮。',24,'全唐诗/poet.tang.7000.json','["楚城今近遠，積靄寒塘暮。", "水淺舟且遲，淮潮至何處。"]'),
('103e17e1-7535-448f-8fb0-1060f02881c4','江中對月','劉長卿','唐','唐诗','tang','','[]','空洲夕煙斂，望月秋江裏。',24,'全唐诗/poet.tang.7000.json','["空洲夕煙斂，望月秋江裏。", "歷歷沙上人，月中孤渡水。"]'),
('c90c3eac-cb5c-4664-bebc-2463efe084a1','碧澗別墅喜皇甫侍御相訪','劉長卿','唐','唐诗','tang','','["\u53cb\u60c5"]','荒村帶返照，落葉亂紛紛。',48,'全唐诗/poet.tang.7000.json','["荒村帶返照，落葉亂紛紛。", "古路無行客，寒山獨見君。", "野橋經雨斷，澗水向田分。", "不爲憐同病，何人到白雲。"]'),
('0ae2f0eb-a7d3-4adf-8f0a-5e65b693db70','初到碧澗招明契上人','劉長卿','唐','唐诗','tang','','[]','漸老知身累，初寒曝背眠。',48,'全唐诗/poet.tang.7000.json','["漸老知身累，初寒曝背眠。", "白雲留永日，黃葉減餘年。", "猨護窗前樹，泉澆谷後田。", "沃洲能共隱，不用道林錢。"]'),
('901dfaa4-18f1-41b4-9edb-ccbac8ee3081','送少微上人遊天台','劉長卿','唐','唐诗','tang','','[]','石橋人不到，獨往更迢迢。',48,'全唐诗/poet.tang.7000.json','["石橋人不到，獨往更迢迢。", "乞食山家少，尋鐘野路遙。", "松門風自埽，瀑布雪難消。", "秋夜聞清梵，餘音逐海潮。"]'),
('82fd73c6-4fa4-4858-a4ee-46069dc81ff4','却歸睦州至七里灘下作','劉長卿','唐','唐诗','tang','','[]','南歸猶謫宦，獨上子陵灘。',48,'全唐诗/poet.tang.7000.json','["南歸猶謫宦，獨上子陵灘。", "江樹臨洲晚，沙禽對水寒。", "山開斜照在，石淺亂流難。", "惆悵梅花發，年年此地看。"]'),
('8c020d17-e4cd-4c03-8f61-07f1cff2c88e','對酒寄嚴維','劉長卿','唐','唐诗','tang','','[]','陋巷喜陽和，衰顏對酒歌。',48,'全唐诗/poet.tang.7000.json','["陋巷喜陽和，衰顏對酒歌。", "嬾從華髮亂，閑任白雲多。", "郡簡容垂釣，家貧學弄梭。", "門前七里瀨，早晚子陵過。"]'),
('6556f501-f5b9-4353-bde2-75ec0e1bb616','新年作','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7", "\u6625\u8282", "\u601d\u4e61"]','鄉心新歲切，天畔獨潸然。',48,'全唐诗/poet.tang.7000.json','["鄉心新歲切，天畔獨潸然。", "老至居人下，春歸在客先。", "嶺猨同旦暮，江柳共風煙。", "已是長沙傅，從今又幾年。"]'),
('66162898-981e-4b88-842d-d6bf46fc9b92','朱放自杭州與故里相使君立碑回因以奉簡吏部楊侍郎製文','劉長卿','唐','唐诗','tang','','[]','片石羊公後，淒涼江水濱。',48,'全唐诗/poet.tang.7000.json','["片石羊公後，淒涼江水濱。", "好辭千古事，墮淚萬家人。", "鵩集占書久，鸞回刻篆新。", "不堪相顧恨，文字日生塵。"]'),
('1784c06f-7cdd-4214-a558-fc0bf4ad50bd','送宣尊師醮畢歸越','劉長卿','唐','唐诗','tang','','[]','吹簫江上晚，惆悵別茅君。',48,'全唐诗/poet.tang.7000.json','["吹簫江上晚，惆悵別茅君。", "踏火能飛雪，登刀入白雲。", "晨香長日在，夜磬滿山聞。", "揮手桐溪路，無情水亦分。"]'),
('2dbdaf0e-f20f-44db-a6a1-335807ba034c','送裴使君赴荆南充行軍司馬','劉長卿','唐','唐诗','tang','','[]','盛府南門寄，前程積水中。',48,'全唐诗/poet.tang.7000.json','["盛府南門寄，前程積水中。", "月明臨夏口，山晚望巴東。", "故節辭江郡，寒笳發渚宮。", "漢川風景好，遙羨逐羊公。"]'),
('9309c4dd-fc94-495e-a69c-74a6d70d8812','送裴郎中貶吉州','劉長卿','唐','唐诗','tang','','[]','亂軍交白刃，一騎出黃塵。',48,'全唐诗/poet.tang.7000.json','["亂軍交白刃，一騎出黃塵。", "漢節同歸闕，江帆共逐臣。", "猨愁歧路晚，梅作異方春。", "知己酇侯在，應憐脫粟人。"]'),
('8a19fb3e-67b4-42a3-9074-e26aaff1340b','酬皇甫侍御見寄時前相國姑臧公初臨郡','劉長卿','唐','唐诗','tang','','[]','離別江南北，汀洲葉再黃。',48,'全唐诗/poet.tang.7000.json','["離別江南北，汀洲葉再黃。", "路遙雲共水，砧迥月如霜。", "歲儉依仁政，年衰憶故鄉。", "佇看宣室召，漢法倚張綱。"]'),
('500b3fa0-d2e8-4e1f-8242-da9be65d86e6','月下呈章秀才','劉長卿','唐','唐诗','tang','','[]','自古悲搖落，誰人奈此何。',48,'全唐诗/poet.tang.7000.json','["自古悲搖落，誰人奈此何。", "夜蛬偏傍枕，寒鳥數移柯。", "向老三年謫，當秋百感多。", "家貧惟好月，空媿子猷過。"]'),
('40f57a14-885c-4db2-84f5-fc635d723e3c','酬張夏','劉長卿','唐','唐诗','tang','','[]','幾歲依窮海，頹年惜故陰。',48,'全唐诗/poet.tang.7000.json','["幾歲依窮海，頹年惜故陰。", "劍寒空有氣，松老欲無心。", "玩雪勞相訪，看山正獨吟。", "孤舟且莫去，前路水雲深。"]'),
('ba36b449-c5cc-4693-a2b9-3dd0abaf9f23','送李使君貶連州','劉長卿','唐','唐诗','tang','','[]','獨過長沙去，誰堪此路愁。',48,'全唐诗/poet.tang.7000.json','["獨過長沙去，誰堪此路愁。", "秋風散千騎，寒雨泊孤舟。", "賈誼辭明主，蕭何識故侯。", "漢廷當自召，湘水但空流。"]'),
('ff8c632e-2004-45cf-b225-535b5a49b4b8','秋夜北山精舍觀體如師梵','劉長卿','唐','唐诗','tang','','[]','焚香奏仙唄，向夕遍空山。',48,'全唐诗/poet.tang.7000.json','["焚香奏仙唄，向夕遍空山。", "清切兼秋遠，威儀對月閑。", "靜分巖響荅，散逐海潮還。", "幸得風吹去，隨人到世間。"]'),
('b3f5b941-64bd-4a86-9537-3c57eb1def2f','酬張夏雪夜赴州訪別途中苦寒作','劉長卿','唐','唐诗','tang','','[]','扁舟乘興客，不憚苦寒行。',48,'全唐诗/poet.tang.7000.json','["扁舟乘興客，不憚苦寒行。", "晚暮相依分，江潮欲別情。", "水聲冰下咽，砂路雪中平。", "舊劒鋒鋩盡，應嫌贈脫輕。"]'),
('007496dc-0513-4edf-ad52-800b5b465d04','尋洪尊師不遇','劉長卿','唐','唐诗','tang','','[]','古木無人地，來尋羽客家。',36,'全唐诗/poet.tang.7000.json','["古木無人地，來尋羽客家。", "道書堆玉案，仙帔疊青霞。", "鶴老難知歲，梅寒未作花。"]'),
('0ece17b4-ac43-4bfe-9f47-d7072f4f17d0','喜鮑禪師自龍山至','劉長卿','唐','唐诗','tang','','[]','故居何日下，春草欲芊芊。',48,'全唐诗/poet.tang.7000.json','["故居何日下，春草欲芊芊。", "猶對山中月，誰聽石上泉。", "猨聲知後夜，花發見流年。", "杖錫閑來往，無心到處禪。"]'),
('aad950ba-0815-4343-9925-1507506ff277','送方外上人之常州依蕭使君','劉長卿','唐','唐诗','tang','','[]','宰臣思得度，鷗鳥戀爲羣。',48,'全唐诗/poet.tang.7000.json','["宰臣思得度，鷗鳥戀爲羣。", "遠客迴飛錫，空山臥白雲。", "夕陽孤艇去，秋水兩溪分。", "歸共臨川史，同翻貝葉文。"]'),
('b9a3335c-b94a-4ba3-8dfc-9f832fd03991','宿北山禪寺蘭若','劉長卿','唐','唐诗','tang','','[]','上方鳴夕磬，林下一僧還。',48,'全唐诗/poet.tang.7000.json','["上方鳴夕磬，林下一僧還。", "密行傳人少，禪心對虎閑。", "青松臨古路，白月滿寒山。", "舊識窗前桂，經霜更待攀。"]'),
('c592c1de-0476-4ab0-9dad-1a4940b1f8ec','赴新安別梁侍郎','劉長卿','唐','唐诗','tang','','[]','新安君莫問，此路水雲深。',48,'全唐诗/poet.tang.7000.json','["新安君莫問，此路水雲深。", "江海無行跡，孤舟何處尋。", "青山空向淚，白月豈知心。", "縱有餘生在，終傷老病侵。"]'),
('7acb860f-1938-4345-84f3-ae7ae66736b5','江州留別薛六柳八二員外','劉長卿','唐','唐诗','tang','','[]','江海相逢少，東南別處長。',48,'全唐诗/poet.tang.7000.json','["江海相逢少，東南別處長。", "獨行風嫋嫋，相去水茫茫。", "白首辭同舍，青山背故鄉。", "離心與潮信，每日到潯陽。"]'),
('baae35ca-3c78-41aa-b9c4-61987704e1ff','和州留別穆郎中','劉長卿','唐','唐诗','tang','','[]','播遷悲遠道，搖落感衰容。',48,'全唐诗/poet.tang.7000.json','["播遷悲遠道，搖落感衰容。", "今日猶多難，何年更此逢。", "世交黃葉散，鄉路白雲重。", "明發看煙樹，唯聞江北鐘。"]'),
('baefd967-c1a8-4cef-90a0-f00eced22a78','和州送人歸復郢','劉長卿','唐','唐诗','tang','','[]','因家漢水曲，相送掩柴扉。',48,'全唐诗/poet.tang.7000.json','["因家漢水曲，相送掩柴扉。", "故郢生秋草，寒江澹落暉。", "綠林行客少，赤壁住人稀。", "獨過潯陽去，潮歸人不歸。"]'),
('6a48ee95-6297-47b9-857d-159d7de82277','送金昌宗歸錢塘','劉長卿','唐','唐诗','tang','','[]','新家浙江上，獨泛落潮歸。',48,'全唐诗/poet.tang.7000.json','["新家浙江上，獨泛落潮歸。", "秋水照華髮，涼風生褐衣。", "柴門嘶馬少，藜杖拜人稀。", "惟有陶潛柳，蕭條對掩扉。"]'),
('656605b0-217d-4a61-ae1a-9641450b0021','酬張夏別後道中見寄','劉長卿','唐','唐诗','tang','','[]','離羣方歲晏，謫宦在天涯。',48,'全唐诗/poet.tang.7000.json','["離羣方歲晏，謫宦在天涯。", "暮雪同行少，寒潮欲上遲。", "海鷗知吏傲，砂鶴見人衰。", "只畏生秋草，西歸亦未期。"]'),
('8b8862d6-a78c-49f7-ae59-074505a6e4f9','新安奉送穆諭德歸朝賦得行字','劉長卿','唐','唐诗','tang','','[]','九重宣室召，萬里建溪行。',48,'全唐诗/poet.tang.7000.json','["九重宣室召，萬里建溪行。", "事直皇天在，歸遲白髮生。", "用材身復起，覩聖眼猶明。", "離別寒江上，潺湲若有情。"]'),
('e50e67ef-bea9-4b41-b7af-76b47b35d864','偶然作','劉長卿','唐','唐诗','tang','','[]','野寺長依止，田家或往還。',48,'全唐诗/poet.tang.7000.json','["野寺長依止，田家或往還。", "老農開古地，夕鳥入寒山。", "書劒身同廢，煙霞吏共閑。", "豈能將白髮，扶杖出人間。"]'),
('ddca5ffd-acbb-4325-9941-db2bb6e78493','送州人孫沅自本州却歸句章新營所居','劉長卿','唐','唐诗','tang','','[]','故里歸成客，新家去未安。',48,'全唐诗/poet.tang.7000.json','["故里歸成客，新家去未安。", "詩書滿蝸舍，征稅及漁竿。", "火種山田薄，星居海島寒。", "憐君不得已，步步別離難。"]'),
('b6c2e24e-3811-489a-b120-715922b45ea5','送李員外使還蘇州兼呈前袁州李使君賦得長字袁州即員外之從兄','劉長卿','唐','唐诗','tang','','[]','別離共成怨，衰老更難忘。',48,'全唐诗/poet.tang.7000.json','["別離共成怨，衰老更難忘。", "夜月留同舍，秋風在遠鄉。", "朱弦徐向燭，白髮強臨觴。", "歸獻西陵作，誰知此路長。"]'),
('ecd6acba-1f51-4fb0-96a4-bfefd3cfc1d3','酬李員外從崔錄事載華宿三河戍先見寄','劉長卿','唐','唐诗','tang','','[]','寒江鳴石瀨，歸客夜初分。',48,'全唐诗/poet.tang.7000.json','["寒江鳴石瀨，歸客夜初分。", "人語空山答，猨聲獨戍聞。", "遲來朝及暮，愁去水連雲。", "歲晚心誰在，青山見此君。"]'),
('6f68a9c5-b1af-4a2a-ab15-48f298295bd4','見秦系離婚後出山居作','劉長卿','唐','唐诗','tang','','[]','豈知偕老重，垂老絕良姻。',48,'全唐诗/poet.tang.7000.json','["豈知偕老重，垂老絕良姻。", "郗氏誠難負，朱家自媿貧。", "綻衣留欲故，織錦罷經春。", "何況蘼蕪綠，空山不見人。"]'),
('1b2176f6-c5ae-4dc4-aa48-493d350e4a0b','酬秦系','劉長卿','唐','唐诗','tang','','[]','鶴書猶未至，那出白雲來。',48,'全唐诗/poet.tang.7000.json','["鶴書猶未至，那出白雲來。", "舊路經年別，寒潮每日迴。", "家空歸海燕，人老發江梅。", "最憶門前柳，閑居手自栽。"]'),
('8146e0df-0584-4683-bf5b-219ef3ed15aa','歲日作','劉長卿','唐','唐诗','tang','','[]','建寅迴北斗，看曆占春風。',48,'全唐诗/poet.tang.7000.json','["建寅迴北斗，看曆占春風。", "律變滄江外，年加白髮中。", "春衣試稚子，壽酒勸衰翁。", "今日陽和發，榮枯豈不同。"]'),
('5a0014e4-8a7d-4be0-84aa-e23782b7673b','題元錄事開元所居','劉長卿','唐','唐诗','tang','','[]','幽居蘿薜情，高臥紀綱行。',48,'全唐诗/poet.tang.7000.json','["幽居蘿薜情，高臥紀綱行。", "鳥散秋鷹下，人閑春草生。", "冒風歸野寺，收印出山城。", "今日新安郡，因君水更清。"]'),
('0fcf3c99-a06e-4ab3-a062-3ad8cf69d2a8','送崔載華張起之閩中','劉長卿','唐','唐诗','tang','','[]','不識閩中路，遙知別後心。',48,'全唐诗/poet.tang.7000.json','["不識閩中路，遙知別後心。", "猨聲入嶺切，鳥道問人深。", "旅食過夷落，方言會越音。", "西征開幕府，早晚用陳琳。"]'),
('a7ec5352-5194-4a4c-81cf-54e9914b3e16','送張司直赴嶺南謁張尚書','劉長卿','唐','唐诗','tang','','[]','番禺萬里路，遠客片帆過。',48,'全唐诗/poet.tang.7000.json','["番禺萬里路，遠客片帆過。", "盛府依橫海，荒祠拜伏波。", "人經秋瘴變，鳥墜火雲多。", "誠憚炎洲裏，無如一顧何。"]'),
('efcb8205-baf2-4bd3-9179-750206d357a7','寄會稽公徐侍郎','劉長卿','唐','唐诗','tang','','[]','搖落淮南葉，秋風想越吟。',48,'全唐诗/poet.tang.7000.json','["搖落淮南葉，秋風想越吟。", "皺枚入梁苑，逸少在山陰。", "老鶴無衰貌，寒松有本心。", "聖朝難稅駕，惆悵白雲深。"]'),
('4b53927c-8b42-4e12-84af-4f5ca0b34494','送朱山人放越州賊退後歸山陰別業','劉長卿','唐','唐诗','tang','','[]','越州初罷戰，江上送歸橈。',48,'全唐诗/poet.tang.7000.json','["越州初罷戰，江上送歸橈。", "南渡無來客，西陵自落潮。", "空城垂故柳，舊業廢春苗。", "閭里相逢少，鶯花共寂寥。"]'),
('b3e110ac-074c-4011-b36a-c6f1a2f3b55e','秋夜肅公房喜普門上人自陽羨山至','劉長卿','唐','唐诗','tang','','[]','山棲久不見，林下偶同遊。',48,'全唐诗/poet.tang.7000.json','["山棲久不見，林下偶同遊。", "早晚來香積，何人住沃洲。", "寒禽驚後夜，古木帶高秋。", "却入千峰去，孤雲不可留。"]'),
('d68d86aa-336f-4272-bac8-933c19b7bd2e','送李秘書却赴南中','劉長卿','唐','唐诗','tang','','[]','却到番禺日，應傷昔所依。',48,'全唐诗/poet.tang.7000.json','["却到番禺日，應傷昔所依。", "炎洲百口住，故國幾人歸。", "路識梅花在，家存棣萼稀。", "獨逢迴雁去，猶作舊行飛。"]'),
('6010d0db-7831-4975-9191-81a006ebdb29','過前安宜張明府郊居','劉長卿','唐','唐诗','tang','','[]','寂寥東郭外，白首一先生。',36,'全唐诗/poet.tang.7000.json','["寂寥東郭外，白首一先生。", "解印孤琴在，移家五柳成。", "夕陽臨水釣，春雨向田耕。"]'),
('a32c9f73-f4bf-4b07-8d95-7af35da374ff','使迴次楊柳過元八所居','劉長卿','唐','唐诗','tang','','[]','君家楊柳渡，來往落帆過。',48,'全唐诗/poet.tang.7000.json','["君家楊柳渡，來往落帆過。", "綠竹經寒在，青山欲暮多。", "薜蘿誠可戀，婚嫁復如何。", "無奈閑門外，漁翁夜夜歌。"]'),
('30002005-5251-4efe-97d6-527f823e3f32','送李侍御貶郴州','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭波渺渺，君去弔靈均。',48,'全唐诗/poet.tang.7000.json','["洞庭波渺渺，君去弔靈均。", "幾路三湘水，全家萬里人。", "聽猨明月夜，看柳故年春。", "憶想汀洲畔，傷心向白蘋。"]'),
('ef136ecc-99c0-46e4-a815-7895338fc7f7','寄普門上人','劉長卿','唐','唐诗','tang','','[]','白雲幽臥處，不向世人傳。',48,'全唐诗/poet.tang.7000.json','["白雲幽臥處，不向世人傳。", "聞在千峰裏，心知獨夜禪。", "辛勤羞薄祿，依止愛閑田。", "惆悵王孫草，青青又一年。"]'),
('e2f2e93c-2d8c-467b-98bb-7dbee148d4fb','逢郴州使因寄鄭協律','劉長卿','唐','唐诗','tang','','[]','相思楚天外，夢寐楚猨吟。',36,'全唐诗/poet.tang.7000.json','["相思楚天外，夢寐楚猨吟。", "更落淮南葉，難爲江上心。", "衡陽問人遠，湘水向君深。"]'),
('a4c1ce9e-92a0-4969-bdd9-7d392f780ef2','岳陽館中望洞庭湖','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','萬古巴丘戍，平湖此望長。',48,'全唐诗/poet.tang.7000.json','["萬古巴丘戍，平湖此望長。", "問人何淼淼，愁暮更蒼蒼。", "疊浪浮元氣，中流沒太陽。", "孤舟有歸客，早晚達瀟湘。"]'),
('2fda8185-6cde-41db-bc25-22a10548e1c2','巡去岳陽却歸鄂州使院留別鄭洵侍御先曾謫居此州','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','何事長沙謫，相逢楚水秋。',48,'全唐诗/poet.tang.7000.json','["何事長沙謫，相逢楚水秋。", "暮帆歸夏口，寒雨對巴丘。", "帝子椒漿奠，騷人木葉愁。", "惟憐萬里外，離別洞庭頭。"]'),
('b682db02-1857-4459-8192-c48dcc620291','夏口送屈突司直使湖南','劉長卿','唐','唐诗','tang','','[]','共悲來夏口，何事更南征。',48,'全唐诗/poet.tang.7000.json','["共悲來夏口，何事更南征。", "霧露行人少，瀟湘春草生。", "鶯啼何處夢，猨嘯若爲聲。", "風月新年好，悠悠遠客情。"]'),
('03c7b4f0-1207-45b7-b7c5-592ae37fb94a','代邊將有懷','劉長卿','唐','唐诗','tang','','[]','少年辭魏闕，白首向沙場。',48,'全唐诗/poet.tang.7000.json','["少年辭魏闕，白首向沙場。", "瘦馬戀秋草，征人思故鄉。", "暮笳吹寒月，曉甲帶胡霜。", "自到雲中郡，于今百戰強。"]'),
('24e70dca-d8fd-4fb3-9c0e-5638b95a417d','雨中過員稷巴陵山居贈別','劉長卿','唐','唐诗','tang','','["\u957f\u6c5f", "\u6d1e\u5ead\u6e56"]','憐君洞庭上，白髮向人垂。',48,'全唐诗/poet.tang.7000.json','["憐君洞庭上，白髮向人垂。", "積雨悲幽獨，長江對別離。", "牛羊歸故道，猨鳥聚寒枝。", "明發遙相望，雲山不可知。"]'),
('a24959d4-1c32-43dc-b620-b4a0147d4dbe','送李中丞之襄州','劉長卿','唐','唐诗','tang','','["\u9001\u522b", "\u540c\u60c5", "\u4ee5\u666f\u886c\u60c5", "\u4e94\u8a00\u5f8b\u8bd7"]','流落征南將，曾驅十萬師。',48,'全唐诗/poet.tang.7000.json','["流落征南將，曾驅十萬師。", "罷歸無舊業，老去戀明時。", "獨立三朝識，輕生一劒知。", "茫茫漢江上，日暮復何之。"]'),
('66b1d615-756e-4021-abff-9925ade3a5fb','奉使至申州傷經陷沒','劉長卿','唐','唐诗','tang','','[]','舉目傷蕪沒，何年此戰爭。',48,'全唐诗/poet.tang.7000.json','["舉目傷蕪沒，何年此戰爭。", "歸人失舊里，老將守孤城。", "廢戍山煙出，荒田野火行。", "獨憐溮水上，時亂亦能清。"]'),
('489e4ab4-905e-4176-b1b0-77db5225a9ad','穆陵關北逢人歸漁陽','劉長卿','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5bbd\u6170"]','逢君穆陵路，匹馬向桑乾。',48,'全唐诗/poet.tang.7000.json','["逢君穆陵路，匹馬向桑乾。", "楚國蒼山古，幽州白日寒。", "城池百戰後，耆舊幾家殘。", "處處蓬蒿遍，歸人掩淚看。"]'),
('88488310-3aca-473a-b45b-dea16b51ac26','安州道中經滻水有懷','劉長卿','唐','唐诗','tang','','[]','征途逢滻水，忽似到秦川。',48,'全唐诗/poet.tang.7000.json','["征途逢滻水，忽似到秦川。", "借問朝天處，猶看落日邊。", "映沙晴漾漾，出澗夜濺濺。", "欲寄西歸恨，微波不可傳。"]'),
('a2ef04e6-cf20-42db-9181-9a9670006357','步登夏口古城作','劉長卿','唐','唐诗','tang','','[]','平蕪連古堞，遠客此沾衣。',48,'全唐诗/poet.tang.7000.json','["平蕪連古堞，遠客此沾衣。", "高樹朝光上，空城秋氣歸。", "微明漢水極，搖落楚人稀。", "但見荒郊外，寒鵶暮暮飛。"]'),
('89818a9e-2be9-4f51-8fdd-2a7e0a4b576c','贈別盧司直之閩中','劉長卿','唐','唐诗','tang','','[]','爾來多不見，此去又何之。',48,'全唐诗/poet.tang.7000.json','["爾來多不見，此去又何之。", "華髮同今日，流芳似舊時。", "洲長春色遍，漢廣夕陽遲。", "歲歲王孫草，空憐無處期。"]'),
('2bc39453-cea9-4304-9a1f-13963cacf3fb','酬郭夏人日長沙感懷見贈','劉長卿','唐','唐诗','tang','','[]','舊俗歡猶在，憐君恨獨深。',48,'全唐诗/poet.tang.7000.json','["舊俗歡猶在，憐君恨獨深。", "新年向國淚，今日倚門心。", "歲去隨湘水，春生近桂林。", "流鶯且莫弄，江畔正行吟。"]'),
('7e824af9-c0f0-462b-a88e-5e7e073dab3f','赴巴南書情寄故人','劉長卿','唐','唐诗','tang','','[]','南過三湘去，巴人此路偏。',48,'全唐诗/poet.tang.7000.json','["南過三湘去，巴人此路偏。", "謫居秋瘴裏，歸處夕陽邊。", "直道天何在，愁容鏡亦憐。", "裁書欲誰訴，無淚可潸然。"]'),
('6ff7652a-efd8-4a5a-a9fd-b3387c9dc8b9','餘干旅舍','劉長卿','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u5199\u666f"]','搖落暮天迥，青楓霜葉稀。',48,'全唐诗/poet.tang.7000.json','["搖落暮天迥，青楓霜葉稀。", "孤城向水閉，獨鳥背人飛。", "渡口月初上，鄰家漁未歸。", "鄉心正欲絕，何處擣寒衣。"]'),
('e5dc9238-486b-4b6b-ae92-b56e0865b3a2','登思禪寺上方題修竹茂松','劉長卿','唐','唐诗','tang','','[]','上方幽且暮，臺殿隱蒙籠。',48,'全唐诗/poet.tang.7000.json','["上方幽且暮，臺殿隱蒙籠。", "遠磬秋山裏，清猨古木中。", "衆溪連竹路，諸嶺共松風。", "儻許棲林下，甘成白首翁。"]'),
('2f1d5e58-4123-4607-bef5-4a9aba90ae28','恩敕重推使牒追赴蘇州次前溪館作','劉長卿','唐','唐诗','tang','','[]','漸入雲峰裏，愁看驛路閑。',48,'全唐诗/poet.tang.7000.json','["漸入雲峰裏，愁看驛路閑。", "亂鵶投落日，疲馬向空山。", "且喜憐非罪，何心戀末班。", "天南一萬里，誰料得生還。"]'),
('19b046e8-91a9-478e-8a5d-52a5635c3fd8','北歸次秋浦界清溪館','劉長卿','唐','唐诗','tang','','[]','萬里猨啼斷，孤村客暫依。',48,'全唐诗/poet.tang.7000.json','["萬里猨啼斷，孤村客暫依。", "雁過彭蠡暮，人向宛陵稀。", "舊路青山在，餘生白首歸。", "漸知行近北，不見鷓鴣飛。"]'),
('9d4e5222-0ddb-48f5-8467-2d150fdb025b','謫官後却歸故村將過虎丘悵然有作','劉長卿','唐','唐诗','tang','','[]','萬事依然在，無如歲月何。',48,'全唐诗/poet.tang.7000.json','["萬事依然在，無如歲月何。", "邑人憐白髮，庭樹長新柯。", "故老相逢少，同官不見多。", "唯餘舊山路，惆悵枉帆過。"]'),
('3cb98829-a3fb-4453-b5c4-18fe1d9c1e11','重推後却赴嶺外待進止寄元侍郎','劉長卿','唐','唐诗','tang','','[]','却訪巴人路，難期國士恩。',48,'全唐诗/poet.tang.7000.json','["却訪巴人路，難期國士恩。", "白雲從出岫，黃葉已辭根。", "大造功何薄，長年氣尚冤。", "空令數行淚，來往落湘沅。"]'),
('b9911b4a-fd83-4d4a-9f89-ef9fa2552f25','秋杪江亭有作','劉長卿','唐','唐诗','tang','','[]','寂寞江亭下，江楓秋氣斑。',48,'全唐诗/poet.tang.7000.json','["寂寞江亭下，江楓秋氣斑。", "世情何處澹，湘水向人閑。", "寒渚一孤雁，夕陽千萬山。", "扁舟如落葉，此去未知還。"]'),
('2ca7246a-7f44-4c71-9a63-1f25ff8cb2e2','送鄭司直歸上都','劉長卿','唐','唐诗','tang','','[]','歲歲逢離別，蹉跎江海濱。',48,'全唐诗/poet.tang.7000.json','["歲歲逢離別，蹉跎江海濱。", "宦遊成楚老，鄉思逐秦人。", "馬首歸何日，鶯啼又一春。", "因君報情舊，閑慢欲垂綸。"]'),
('06e4a959-9173-49c1-822d-bdbceaa2e705','送靈澈上人歸嵩陽蘭若','劉長卿','唐','唐诗','tang','','[]','南地隨緣久，東林幾歲空。',48,'全唐诗/poet.tang.7000.json','["南地隨緣久，東林幾歲空。", "暮山門獨掩，春草路難通。", "作梵連松韻，焚香入桂叢。", "唯將舊缾鉢，却寄白雲中。"]'),
('fe1c7bea-e2b8-4c26-9e99-2c7d31ae7213','却赴南邑留別蘇臺知己','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','又過梅嶺上，歲歲此枝寒。',48,'全唐诗/poet.tang.7000.json','["又過梅嶺上，歲歲此枝寒。", "落日孤舟去，青山萬里看。", "猨聲湘水靜，草色洞庭寬。", "已料生涯事，唯應把釣竿。"]'),
('6c312d68-e8d4-41ba-961d-22f391da0e0c','和靈一上人新泉','劉長卿','唐','唐诗','tang','','[]','東林一泉出，復與遠公期。',48,'全唐诗/poet.tang.7000.json','["東林一泉出，復與遠公期。", "石淺寒流處，山空夜落時。", "夢閑聞細響，慮澹對清漪。", "動靜皆無意，唯應達者知。"]'),
('17b85fdb-4ac9-4bf8-978a-b2f460849ded','送李摯赴延陵令','劉長卿','唐','唐诗','tang','','[]','清風季子邑，想見下車時。',50,'全唐诗/poet.tang.7000.json','["清風季子邑，想見下車時。", "向水彈琴靜，看山採菊遲。", "明君加印綬，廉使託惸[嫠]。", "旦暮華陽洞，雲峰若有期。"]'),
('37ae7ba6-4da6-494a-9ca6-1e55154f72b6','奉送裴員外赴上都','劉長卿','唐','唐诗','tang','','[]','彤襜江上遠，萬里詔書催。',48,'全唐诗/poet.tang.7000.json','["彤襜江上遠，萬里詔書催。", "獨過潯陽去，空憐潮信迴。", "離心秋草綠，揮手暮帆開。", "想見秦城路，人看五馬來。"]'),
('4c7ecefc-ee3c-4081-9ff3-d9cdcb6dad24','長沙桓王墓下別李紓張南史','劉長卿','唐','唐诗','tang','','[]','長沙千載後，春草獨萋萋。',48,'全唐诗/poet.tang.7000.json','["長沙千載後，春草獨萋萋。", "流水朝將暮，行人東復西。", "碑苔幾字滅，山木萬株齊。", "佇立傷今古，相看惜解攜。"]'),
('698ce2d2-09ae-42cb-a829-4bc0243d4611','送侯御赴黔中充判官','劉長卿','唐','唐诗','tang','','[]','不識黔中路，今看遣使臣。',48,'全唐诗/poet.tang.7000.json','["不識黔中路，今看遣使臣。", "猨啼萬里客，鳥似五湖人。", "地遠官無法，山深俗豈淳。", "須令荒徼外，亦解懼埋輪。"]'),
('fdc07d9f-95b8-45f7-b1b3-9d272b3416a4','秋日登吳公臺上寺遠眺寺即陳將吳明徹戰場','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u957f\u6c5f", "\u6000\u53e4", "\u79cb\u5929", "\u4e94\u8a00\u5f8b\u8bd7"]','古臺搖落後，秋日望鄉心。',48,'全唐诗/poet.tang.7000.json','["古臺搖落後，秋日望鄉心。", "野寺人來少，雲峰水隔深。", "夕陽依舊壘，寒磬滿空林。", "惆悵南朝事，長江獨至今。"]'),
('26e38d21-8c0c-42c9-9a9f-02d3d1e4972f','淮上送梁二恩命追赴上都','劉長卿','唐','唐诗','tang','','[]','賈生年最少，儒行漢庭聞。',48,'全唐诗/poet.tang.7000.json','["賈生年最少，儒行漢庭聞。", "拜手卷黃紙，迴身謝白雲。", "故關無去客，春草獨隨君。", "淼淼長淮水，東西自此分。"]'),
('d614d131-55bb-4c1a-b1d7-ab2c77ec6568','送崔昇歸上都','劉長卿','唐','唐诗','tang','','[]','舊寺尋遺緒，歸心逐去塵。',48,'全唐诗/poet.tang.7000.json','["舊寺尋遺緒，歸心逐去塵。", "早鶯何處客，古木幾家人。", "白髮經多難，滄洲欲暮春。", "臨期數行淚，爲爾一霑巾。"]'),
('b011c784-ca75-418f-8e66-36c023a8d4b3','過李將軍南鄭林園觀妓','劉長卿','唐','唐诗','tang','','[]','郊原風日好，百舌弄何頻。',48,'全唐诗/poet.tang.7000.json','["郊原風日好，百舌弄何頻。", "小婦秦家女，將軍天上人。", "鴉歸長郭暮，草映大堤春。", "客散垂楊下，通橋車馬塵。"]'),
('62875454-03b8-4d99-983c-c336d16d2cff','送嚴侍御充東畿觀察判官','劉長卿','唐','唐诗','tang','','[]','洛陽征戰後，君去問凋殘。',48,'全唐诗/poet.tang.7000.json','["洛陽征戰後，君去問凋殘。", "雲月臨南至，風霜向北寒。", "故園經亂久，古木隔林看。", "誰訪江城客，年年守一官。"]'),
('6c5f3fb0-c3aa-4854-a816-9da8229860f8','送王端公入奏上都','劉長卿','唐','唐诗','tang','','[]','舊國無家訪，臨歧亦羨歸。',48,'全唐诗/poet.tang.7000.json','["舊國無家訪，臨歧亦羨歸。", "途經百戰後，客過二陵稀。", "秋草通征騎，寒城背落暉。", "行當蒙顧問，吳楚歲頻饑。"]'),
('8ace656a-c4e9-433e-a7c4-d7c0530ae90a','送營田判官鄭侍御赴上都','劉長卿','唐','唐诗','tang','','[]','上國三千里，西還及歲芳。',48,'全唐诗/poet.tang.7000.json','["上國三千里，西還及歲芳。", "故山經亂在，春日送歸長。", "曉奏趨雙闕，秋成報萬箱。", "幸論開濟力，已實海陵倉。"]'),
('690e93f2-146f-4690-b2aa-44ff939da200','送李校書赴東浙幕府','劉長卿','唐','唐诗','tang','','[]','方從大夫後，南去會稽行。',48,'全唐诗/poet.tang.7000.json','["方從大夫後，南去會稽行。", "淼淼滄江外，青青春草生。", "芸香辭亂事，梅吹聽軍聲。", "應訪王家宅，空憐江水平。"]'),
('0b54c525-1950-4456-b859-a11752bee713','清明後登城眺望','劉長卿','唐','唐诗','tang','','[]','風景清明後，雲山睥睨前。',48,'全唐诗/poet.tang.7000.json','["風景清明後，雲山睥睨前。", "百花如舊日，萬井出新煙。", "草色無空地，江流合遠天。", "長安在何處？遙指夕陽邊。"]'),
('48ed2dfa-2e86-49b6-9811-de4204b9e70a','陪王明府泛舟','劉長卿','唐','唐诗','tang','','[]','花縣彈琴暇，樵風載酒時。',48,'全唐诗/poet.tang.7000.json','["花縣彈琴暇，樵風載酒時。", "山含秋色近，鳥度夕陽遲。", "出沒鳧成浪，蒙籠竹亞枝。", "雲峰逐人意，來去解相隨。"]'),
('c61e04e1-972d-4979-bc52-c3a21833c7a9','送度支留後若侍御之歙州便赴信州省覲','劉長卿','唐','唐诗','tang','','[]','國用憂錢穀，朝推此任難。',48,'全唐诗/poet.tang.7000.json','["國用憂錢穀，朝推此任難。", "即山榆莢變，降雨稻花殘。", "林響朝登嶺，江喧夜過灘。", "遙知驄馬色，應待倚門看。"]'),
('87a94bab-3a1d-4cbc-9e07-dd2e0ebc3d42','餘干夜宴奉餞前蘇州韋使君新除婺州作','劉長卿','唐','唐诗','tang','','[]','復拜東陽郡，遙馳北闕心。',48,'全唐诗/poet.tang.7000.json','["復拜東陽郡，遙馳北闕心。", "行春五馬急，向夜一猨深。", "山過康郎近，星看婺女臨。", "幸容棲託分，猶戀舊棠陰。"]'),
('6dc8382f-7407-4962-9a0a-797fa7efde5d','晚次苦竹館却憶干越舊遊','劉長卿','唐','唐诗','tang','','[]','匹馬風塵色，千峰旦暮時。',48,'全唐诗/poet.tang.7000.json','["匹馬風塵色，千峰旦暮時。", "遙看落日盡，獨向遠山遲。", "故驛花臨道，荒村竹映籬。", "誰憐却迴首，步步戀南枝。"]'),
('c5237844-1e9d-4dae-8577-b9c10468eae8','送李二十四移家之江州','劉長卿','唐','唐诗','tang','','[]','煙塵猶滿目，歧路易霑衣。',48,'全唐诗/poet.tang.7000.json','["煙塵猶滿目，歧路易霑衣。", "逋客多南渡，征鴻自北飛。", "九江春草綠，千里暮潮歸。", "別後難相訪，全家隱釣磯。"]'),
('ad8b08e5-782a-4b33-abe6-c910d766f203','送盧判官南湖','劉長卿','唐','唐诗','tang','','[]','漾舟仍載酒，愧爾意相寬。',48,'全唐诗/poet.tang.7000.json','["漾舟仍載酒，愧爾意相寬。", "草色南湖綠，松聲小署寒。", "水禽前後起，花嶼往來看。", "已作滄洲調，無心戀一官。"]'),
('79c60eae-693b-4d94-a448-dd8b6f451937','送張栩扶侍之睦州','劉長卿','唐','唐诗','tang','','[]','遙憶新安舊，扁舟復却還。',48,'全唐诗/poet.tang.7000.json','["遙憶新安舊，扁舟復却還。", "淺深看水石，來往逐雲山。", "入縣餘花在，過門故柳閑。", "東征隨子去，皆隱薜蘿間。"]'),
('9adc8a82-10ff-42a1-9853-f5ac7f4accda','集梁耿開元寺所居院','劉長卿','唐','唐诗','tang','','[]','到君幽臥處，爲我埽莓苔。',48,'全唐诗/poet.tang.7000.json','["到君幽臥處，爲我埽莓苔。", "花雨晴天落，松風終日來。", "路經深竹過，門向遠山開。", "豈得長高枕，中朝正用才。"]'),
('d2a97228-08a4-480c-b241-c1036dda041b','贈西鄰盧少府','劉長卿','唐','唐诗','tang','','[]','籬落能相近，漁樵偶復同。',48,'全唐诗/poet.tang.7000.json','["籬落能相近，漁樵偶復同。", "苔封三徑絕，溪向數家通。", "犬吠寒煙裏，鵶鳴夕照中。", "時因杖藜次，相訪竹林東。"]'),
('ab375fd7-31a4-497d-a6dd-aed44ebd78a1','遊休禪師雙峰寺','劉長卿','唐','唐诗','tang','','[]','雙扉碧峰際，遙向夕陽開。',48,'全唐诗/poet.tang.7000.json','["雙扉碧峰際，遙向夕陽開。", "飛錫方獨往，孤雲何事來。", "寒潭映白月，秋雨上青苔。", "相送東郊外，羞看驄馬回。"]'),
('08015dc2-ff98-43ad-9820-0e50544b2235','廨中見桃花南枝已開北枝未發因寄杜副端','劉長卿','唐','唐诗','tang','','[]','何意同根本，開花每後時。',48,'全唐诗/poet.tang.7000.json','["何意同根本，開花每後時。", "應緣去日遠，獨自發春遲。", "結實恩難忘，無言恨豈知。", "年光不可待，空羨向南枝。"]'),
('bb685144-344b-4b6c-bb3e-18d50349e67e','奉送盧員外之饒州','劉長卿','唐','唐诗','tang','','[]','天書萬里至，旌斾上江飛。',48,'全唐诗/poet.tang.7000.json','["天書萬里至，旌斾上江飛。", "日向鄱陽近，應看吳岫微。", "暮帆何處落？潮水背人歸。", "風土無勞問，南枝黃葉稀。"]'),
('8911634b-be09-40cb-9d3a-9eed1fb9386e','送處士歸州因寄林山人','劉長卿','唐','唐诗','tang','','["\u592a\u6e56"]','陵陽不可見，獨往復如何。',48,'全唐诗/poet.tang.7000.json','["陵陽不可見，獨往復如何。", "舊邑雲山裏，扁舟來去過。", "鳥聲春谷靜，草色太湖多。", "儻宿荆溪夜，相思漁者歌。"]'),
('6061b61d-365c-4c7e-873c-4d0d97a7ace0','移使鄂州次峴陽館懷舊居','劉長卿','唐','唐诗','tang','','[]','多慙恩未報，敢問路何長。',48,'全唐诗/poet.tang.7000.json','["多慙恩未報，敢問路何長。", "萬里通秋雁，千峰共夕陽。", "舊遊成遠道，此去更違鄉。", "草露深山裏，朝朝落客裳。"]'),
('5a5eb28c-ac28-4cb5-8d5a-fdbbc5ddc494','送齊郎中赴海州','劉長卿','唐','唐诗','tang','','[]','華省占星動，孤城望日遙。',48,'全唐诗/poet.tang.7000.json','["華省占星動，孤城望日遙。", "直廬收舊草，行縣及新苗。", "滄海天連水，青山暮與朝。", "閭閻幾家散，應待下車招。"]'),
('cc086050-97dd-4d53-bf1a-ee4a61234fd0','重陽日鄂城樓送屈突司直','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','登高復送遠，惆悵洞庭秋。',48,'全唐诗/poet.tang.7000.json','["登高復送遠，惆悵洞庭秋。", "風景同前古，雲山滿上游。", "蒼蒼來暮雨，淼淼逐寒流。", "今日關中事，蕭何共爾憂。"]'),
('88e85622-e441-4071-83e4-6fb414e97a9a','更被奏留淮南送從弟罷使江東','劉長卿','唐','唐诗','tang','','[]','又作淮南客，還悲木葉聲。',48,'全唐诗/poet.tang.7000.json','["又作淮南客，還悲木葉聲。", "寒潮落瓜步，秋色上蕪城。", "王事何時盡？滄洲羨爾行。", "青山將綠水，惆悵不勝情。"]'),
('e1a6b79d-aa1c-4ec5-b723-47050340fcdb','經漂母墓','劉長卿','唐','唐诗','tang','','[]','昔賢懷一飯，茲事已千秋。',48,'全唐诗/poet.tang.7000.json','["昔賢懷一飯，茲事已千秋。", "古墓樵人識，前朝楚水流。", "渚蘋行客薦，山木杜鵑愁。", "春草茫茫綠，王孫舊此遊。"]'),
('d8cf4a6e-fd28-4331-875f-071856b61ab9','送李端公赴東都','劉長卿','唐','唐诗','tang','','[]','軒轅征戰後，江海別離長。',48,'全唐诗/poet.tang.7000.json','["軒轅征戰後，江海別離長。", "遠客歸何處，平蕪滿故鄉。", "夕陽帆杳杳，舊里樹蒼蒼。", "惆悵蓬山下，瓊枝不可忘。"]'),
('9b781227-6063-43d8-b184-45d06599a8df','送王員外歸朝','劉長卿','唐','唐诗','tang','','[]','往來無盡目，離別要逢春。',48,'全唐诗/poet.tang.7000.json','["往來無盡目，離別要逢春。", "海內罹多事，天涯見近臣。", "芳時萬里客，鄉路獨歸人。", "魏闕心常在，隨君亦向秦。"]'),
('15eef528-7b6e-4136-9f92-9535b52a7abb','送蔣侍御入秦','劉長卿','唐','唐诗','tang','','[]','朝見及芳菲，恩榮出紫微。',48,'全唐诗/poet.tang.7000.json','["朝見及芳菲，恩榮出紫微。", "晚光臨仗奏，春色共西歸。", "楚客移家老，秦人訪舊稀。", "因君鄉里去，爲埽故園扉。"]'),
('86b0b4cb-0ad8-416a-9b97-4c2c830746db','洞庭驛逢郴州使還寄李湯司馬','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭秋水闊，南望過衡峰。',48,'全唐诗/poet.tang.7000.json','["洞庭秋水闊，南望過衡峰。", "遠客瀟湘裏，歸人何處逢。", "孤雲飛不定，落葉去無蹤。", "莫使滄浪叟，長歌笑爾容。"]'),
('34ca954b-a832-4920-a242-1d7464c8768c','送舍弟之鄱陽居','劉長卿','唐','唐诗','tang','','[]','鄱陽寄家處，自別掩柴扉。',48,'全唐诗/poet.tang.7000.json','["鄱陽寄家處，自別掩柴扉。", "故里人何在，滄波孤客稀。", "湖山春草遍，雲木夕陽微。", "南去逢迴鴈，應憐相背飛。"]'),
('168a4b6e-0f9a-4f6f-bcce-2a561a8552b4','送裴二十端公使嶺南','劉長卿','唐','唐诗','tang','','[]','蒼梧萬里路，空見白雲來。',48,'全唐诗/poet.tang.7000.json','["蒼梧萬里路，空見白雲來。", "遠國知何在，憐君去未迴。", "桂林無葉落，梅嶺自花開。", "陸賈千年後，誰看朝漢臺。"]'),
('44f24ab9-5326-4326-a592-ab3e5b1bfa7f','過桃花夫人廟','劉長卿','唐','唐诗','tang','','[]','寂寞應千歲，桃花想一枝。',48,'全唐诗/poet.tang.7000.json','["寂寞應千歲，桃花想一枝。", "路人看古木，江月向空祠。", "雲雨飛何處，山川是舊時。", "獨憐春草色，猶似憶佳期。"]'),
('bede5fef-14d6-481a-b569-604db6dfe58d','鄂渚送池州程使君','劉長卿','唐','唐诗','tang','','[]','蕭蕭五馬動，欲別謝臨川。',48,'全唐诗/poet.tang.7000.json','["蕭蕭五馬動，欲別謝臨川。", "落日蕪湖色，空山梅冶煙。", "江湖通廨舍，楚老拜戈船。", "風化東南滿，行舟來去傳。"]'),
('339be593-55ba-47a6-babc-12070bfec2b9','送友人西上','劉長卿','唐','唐诗','tang','','[]','羈心不自解，有別會霑衣。',48,'全唐诗/poet.tang.7000.json','["羈心不自解，有別會霑衣。", "春草連天積，五陵遠客歸。", "十年經轉戰，幾處便芳菲。", "想見函關路，行人去亦稀。"]'),
('b559fb98-3c91-4f99-a640-4ee33b58df48','送梁郎中赴吉州','劉長卿','唐','唐诗','tang','','[]','遙想廬陵郡，還聽叔度歌。',48,'全唐诗/poet.tang.7000.json','["遙想廬陵郡，還聽叔度歌。", "舊官移上象，新令布中和。", "看竹經霜少，聞猨帶雨多。", "但愁徵拜日，無奈借留何。"]'),
('c6172c14-2aef-4809-bcf5-cc1b1ce67b2d','過湖南羊處士別業','劉長卿','唐','唐诗','tang','','[]','杜門成白首，湖上寄生涯。',48,'全唐诗/poet.tang.7000.json','["杜門成白首，湖上寄生涯。", "秋草蕪三徑，寒塘獨一家。", "鳥歸村落盡，水向縣城斜。", "自有東籬菊，年年解作花。"]'),
('8615fe81-6b98-4851-92c8-416ba9462361','送河南元判官赴河南句當苗稅充百官俸錢','劉長卿','唐','唐诗','tang','','[]','春草長河曲，離心共渺然。',48,'全唐诗/poet.tang.7000.json','["春草長河曲，離心共渺然。", "方收漢家俸，獨向汶陽田。", "鳥雀空城在，榛蕪舊路遷。", "山東征戰苦，幾處有人煙。"]'),
('d18a3083-e675-44b1-9623-cb34d542a4da','夏中崔中丞宅見海紅搖落一花獨開','劉長卿','唐','唐诗','tang','','[]','何事一花殘，閑庭百草闌。',48,'全唐诗/poet.tang.7000.json','["何事一花殘，閑庭百草闌。", "綠滋經雨發，紅豔隔林看。", "竟日餘香在，過時獨秀難。", "共憐芳意晚，秋露未須團。"]'),
('cbc26cb9-8466-4947-b688-1b115f0a5324','使還至菱陂驛渡溮水作','劉長卿','唐','唐诗','tang','','[]','清川已再涉，疲馬共西還。',48,'全唐诗/poet.tang.7000.json','["清川已再涉，疲馬共西還。", "何事行人倦，終年流水閑。", "孤煙飛廣澤，一鳥向空山。", "愁入雲峰裏，蒼蒼閉古關。"]'),
('9919c6c3-d6d9-424f-a1be-e593e1d8388e','送齊郎中典括州','劉長卿','唐','唐诗','tang','','[]','星象移何處，旌麾獨向東。',48,'全唐诗/poet.tang.7000.json','["星象移何處，旌麾獨向東。", "勸耕滄海畔，聽訟白雲中。", "樹色雙溪合，猨聲萬嶺同。", "石門康樂住，幾里枉帆通。"]'),
('88d109af-babd-4c33-b35d-17dce2a690b0','過隱空和尚故居','劉長卿','唐','唐诗','tang','','[]','自從飛錫去，人到沃洲稀。',48,'全唐诗/poet.tang.7000.json','["自從飛錫去，人到沃洲稀。", "林下期何在，山中春獨歸。", "踏花尋舊徑，映竹掩空扉。", "寥落東峰上，猶堪靜者依。"]'),
('dcc318be-3a92-4c4e-a7fe-3930a823b5de','過蕭尚書故居見李花感而成詠','劉長卿','唐','唐诗','tang','','[]','手植已芳菲，心傷故徑微。',48,'全唐诗/poet.tang.7000.json','["手植已芳菲，心傷故徑微。", "往年啼鳥至，今日主人非。", "滿地誰當埽，隨風豈復歸。", "空憐舊陰在，門客共霑衣。"]'),
('97dba3eb-67f0-47d0-9e1e-3ef1f2fdad7d','送袁處士','劉長卿','唐','唐诗','tang','','[]','閑田北川下，靜者去躬耕。',48,'全唐诗/poet.tang.7000.json','["閑田北川下，靜者去躬耕。", "萬里空江菼，孤舟過郢城。", "種荷依野水，移柳待山鶯。", "出處安能問，浮雲豈有情。"]'),
('0d67a8c4-cef8-467e-bf3b-ce0a332613d2','酬李侍御登岳陽見寄','劉長卿','唐','唐诗','tang','','[]','想見孤舟去，無由此路尋。',48,'全唐诗/poet.tang.7000.json','["想見孤舟去，無由此路尋。", "暮帆遙在眼，春色獨何心。", "綠水瀟湘闊，青山鄠杜深。", "誰當北風至，爲爾一開襟。"]'),
('604aa35c-21d2-40e8-b354-2fcb339a3beb','喜晴','劉長卿','唐','唐诗','tang','','[]','曉日西風轉，秋天萬里明。',48,'全唐诗/poet.tang.7000.json','["曉日西風轉，秋天萬里明。", "湖天一種色，林鳥百般聲。", "霽景浮雲滿，遊絲暎水輕。", "今朝江上客，凡慰幾人情。"]'),
('2dd4e4db-95f2-4cdf-984f-5fd413980f06','夏口送徐郎中歸朝','劉長卿','唐','唐诗','tang','','[]','星象南宮遠，風流上客稀。',48,'全唐诗/poet.tang.7000.json','["星象南宮遠，風流上客稀。", "九重思曉奏，萬里見春歸。", "棹發空江響，城孤落日暉。", "離心與楊柳，臨水更依依。"]'),
('c5fa34cf-7151-488c-88ee-a9c439ae7f56','鄂渚聽杜別駕彈胡琴','劉長卿','唐','唐诗','tang','','["\u957f\u6c5f"]','文姬留此曲，千載一知音。',48,'全唐诗/poet.tang.7000.json','["文姬留此曲，千載一知音。", "不解胡人語，空留楚客心。", "聽隨邊草動，意入隴雲深。", "何事長江上，蕭蕭出塞吟。"]'),
('652d2e04-0922-4e01-b3e4-212eee1091de','過鸚鵡洲王處士別業','劉長卿','唐','唐诗','tang','','[]','白首此爲漁，青山對結廬。',48,'全唐诗/poet.tang.7000.json','["白首此爲漁，青山對結廬。", "問人尋野笋，留客饋家蔬。", "古柳依沙發，春苗帶雨鋤。", "共憐芳杜色，終日伴閑居。"]'),
('25724640-0835-4136-9635-e8158a7bbf15','寄萬州崔使君','劉長卿','唐','唐诗','tang','','[]','時艱方用武，儒者任浮沈。',48,'全唐诗/poet.tang.7000.json','["時艱方用武，儒者任浮沈。", "搖落秋江暮，憐君巴峽深。", "丘門多白首，蜀郡滿青襟。", "自解書生詠，愁猨莫夜吟。"]'),
('ad2d3d59-da1d-4291-9693-3f0d32e4f0d2','送馬秀才移家京洛便赴舉','劉長卿','唐','唐诗','tang','','[]','自從爲楚客，不復掃荆扉。',48,'全唐诗/poet.tang.7000.json','["自從爲楚客，不復掃荆扉。", "劒共丹誠在，書隨白髮歸。", "舊遊經亂靜，後進識君稀。", "空把相如賦，何人薦禮闈。"]'),
('823a409e-3a11-4f1a-a669-fc94527c0363','送南特進赴歸行營','劉長卿','唐','唐诗','tang','','[]','聞道軍書至，揚鞭不問家。',48,'全唐诗/poet.tang.7000.json','["聞道軍書至，揚鞭不問家。", "虜雲連白草，漢月到黃沙。", "汗馬河源飲，燒羌隴坻遮。", "翩翩新結束，去逐李輕車。"]'),
('1e653382-12b8-4814-831e-f218553b4571','送道標上人歸南岳','劉長卿','唐','唐诗','tang','','[]','悠然倚孤棹，却憶臥中林。',48,'全唐诗/poet.tang.7000.json','["悠然倚孤棹，却憶臥中林。", "江草將歸遠，湘山獨往深。", "白雲留不住，淥水去無心。", "衡岳千峰亂，禪房何處尋。"]'),
('e51881c0-e9fc-4b5e-a471-f2039bec5a3f','送梁侍御巡永州','劉長卿','唐','唐诗','tang','','[]','蕭蕭江雨暮，客散野亭空。',48,'全唐诗/poet.tang.7000.json','["蕭蕭江雨暮，客散野亭空。", "憂國天涯去，思鄉歲暮同。", "到時猨未斷，迴處水應窮。", "莫望零陵路，千峰萬木中。"]'),
('8fe45936-0c4b-4dcd-9b3b-2a64adb6f309','歲夜喜魏萬成郭夏雪中相尋','劉長卿','唐','唐诗','tang','','[]','新年欲變柳，舊客共霑衣。',48,'全唐诗/poet.tang.7000.json','["新年欲變柳，舊客共霑衣。", "歲夜猶難盡，鄉春又獨歸。", "寒燈映虛牖，暮雪掩閑扉。", "且莫乘船去，平生相訪稀。"]'),
('55932dbd-51d3-4968-9448-5c2f7f09825f','送蔡侍御赴上都','劉長卿','唐','唐诗','tang','','[]','遲遲立駟馬，久客戀瀟湘。',48,'全唐诗/poet.tang.7000.json','["遲遲立駟馬，久客戀瀟湘。", "明日誰同路，新年獨到鄉。", "孤煙向驛遠，積雪去關長。", "秦地看春色，南枝不可忘。"]'),
('dbe1b2ab-b9a2-4a16-9c46-350e16523dda','晦日陪辛大夫宴南亭','劉長卿','唐','唐诗','tang','','[]','月晦逢休澣，年光逐宴移。',48,'全唐诗/poet.tang.7000.json','["月晦逢休澣，年光逐宴移。", "早鶯留客醉，春日爲人遲。", "蓂草全無葉，梅花遍壓枝。", "政閑風景好，莫比峴山時。"]'),
('0e053637-210f-4f95-a3f2-148f414eaa7b','送獨孤判官赴嶺','劉長卿','唐','唐诗','tang','','[]','伏波初樹羽，待爾靜川鱗。',48,'全唐诗/poet.tang.7000.json','["伏波初樹羽，待爾靜川鱗。", "嶺海看飛鳥，天涯問遠人。", "蒼梧雲裏夕，青草嶂中春。", "遙想文身國，迎舟拜使臣。"]'),
('000318db-5cde-4294-a1e4-8170c9e6e7b6','長沙館中與郭夏對雨','劉長卿','唐','唐诗','tang','','[]','長沙積雨晦，深巷絕人幽。',48,'全唐诗/poet.tang.7000.json','["長沙積雨晦，深巷絕人幽。", "潤上春衣冷，聲連暮角愁。", "雲橫全楚地，樹暗古湘洲。", "杳藹江天外，空堂生百憂。"]'),
('340ba0aa-9b16-4092-ab7d-a64e8f7723e1','陪辛大夫西亭宴觀妓','劉長卿','唐','唐诗','tang','','[]','歌舞憐遲日，旌麾映早春。',48,'全唐诗/poet.tang.7000.json','["歌舞憐遲日，旌麾映早春。", "鶯窺隴西將，花對洛陽人。", "醉罷知何事，恩深忘此身。", "任他行雨去，歸路裛香塵。"]'),
('7cb680ab-73c6-41cb-b856-2021c2ce5f93','題魏萬成江亭','劉長卿','唐','唐诗','tang','','[]','蕭條方歲晏，牢落對空洲。',48,'全唐诗/poet.tang.7000.json','["蕭條方歲晏，牢落對空洲。", "才出時人右，家貧湘水頭。", "蒼山隱暮雪，白鳥沒寒流。", "不是蓮花府，冥冥不可求。"]'),
('a8dd9acc-2083-4310-970b-d258bdd023eb','春過裴虬郊園','劉長卿','唐','唐诗','tang','','[]','郊原春欲暮，桃杏落紛紛。',48,'全唐诗/poet.tang.7000.json','["郊原春欲暮，桃杏落紛紛。", "何處隨芳草，留家寄白雲。", "聽鶯情念友，看竹恨無君。", "長嘯高臺上，南風冀爾聞。"]'),
('32ce6bba-527a-480a-8985-a5260ed38928','送韋贊善使嶺南','劉長卿','唐','唐诗','tang','','[]','欲逐樓船將，方安卉服夷。',48,'全唐诗/poet.tang.7000.json','["欲逐樓船將，方安卉服夷。", "炎洲經瘴遠，春水上瀧遲。", "歲貢隨重譯，年芳徧四時。", "番禺靜無事，空詠飲泉詩。"]'),
('ec319906-635a-47f6-bea3-82c168e4a5ce','送喬判官赴福州','劉長卿','唐','唐诗','tang','','[]','揚帆向何處，插羽逐征東。',48,'全唐诗/poet.tang.7000.json','["揚帆向何處，插羽逐征東。", "夷落人煙迥，王程鳥路通。", "江流回澗底，山色聚閩中。", "君去凋殘後，應憐百越空。"]'),
('162079b4-6a53-424f-b25b-40eb047d8fae','送李補闕之上都','劉長卿','唐','唐诗','tang','','[]','獨歸西掖去，難接後塵遊。',48,'全唐诗/poet.tang.7000.json','["獨歸西掖去，難接後塵遊。", "向日三千里，朝天十二樓。", "路看新柳夕，家對舊山秋。", "惆悵離心遠，滄江空自流。"]'),
('e6e4de51-0600-4ae9-938f-f7605e4de8a0','送袁明府之任','劉長卿','唐','唐诗','tang','','[]','既有親人術，還逢試吏年。',48,'全唐诗/poet.tang.7000.json','["既有親人術，還逢試吏年。", "蓬蒿千里閉，村樹幾家全。", "雪覆淮南道，春生潁谷煙。", "何時當莅政，相府待聞天。"]'),
('51cb634a-3685-48f6-b9df-7ccd3a105429','海鹽官舍早春','劉長卿','唐','唐诗','tang','','[]','小邑滄洲吏，新年白首翁。',48,'全唐诗/poet.tang.7000.json','["小邑滄洲吏，新年白首翁。", "一官如遠客，萬事極飄蓬。", "柳色孤城裏，鶯聲細雨中。", "羈心早已亂，何事更春風。"]'),
('277081c8-2f97-4fbb-979f-b972f4e5a949','南湖送徐二十七西上','劉長卿','唐','唐诗','tang','','[]','家在橫塘曲，那能萬里違。',48,'全唐诗/poet.tang.7000.json','["家在橫塘曲，那能萬里違。", "門臨秋水掩，帆帶夕陽飛。", "傲俗宜紗帽，干時倚布衣。", "獨將湖上月，相逐去還歸。"]'),
('353c3796-b91d-4aea-b133-7ecd1d0999a4','曲阿對月別岑況徐說','劉長卿','唐','唐诗','tang','','[]','金陵已蕪沒，函谷復煙塵。',48,'全唐诗/poet.tang.7000.json','["金陵已蕪沒，函谷復煙塵。", "猶見南朝月，還隨上國人。", "白雲心自遠，滄海意相親。", "何事須成別，汀洲欲暮春。"]'),
('b9d028b4-285d-4fd6-a814-cb80b17c2d94','送李侍御貶鄱陽','劉長卿','唐','唐诗','tang','','[]','迴車仍昨日，謫去已秋風。',48,'全唐诗/poet.tang.7000.json','["迴車仍昨日，謫去已秋風。", "干越知何處，雲山只向東。", "暮天江色裏，田鶴稻花中。", "却見鄱陽吏，猶應舊馬驄。"]'),
('99817a07-7174-42a0-b0a5-831be9effd7b','送路少府使東京便應制舉','劉長卿','唐','唐诗','tang','','[]','故人西奉使，胡騎正紛紛。',48,'全唐诗/poet.tang.7000.json','["故人西奉使，胡騎正紛紛。", "舊國無來信，春江獨送君。", "五言淩白雪，六翮向青雲。", "誰念滄州吏，忘機鷗鳥羣。"]'),
('c293bcaf-2279-4f7a-a73c-3b5198d98177','松江獨宿','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭初下葉，孤客不勝愁。',48,'全唐诗/poet.tang.7000.json','["洞庭初下葉，孤客不勝愁。", "明月天涯夜，青山江上秋。", "一官成白首，萬里寄滄洲。", "久被浮名繫，能無媿海鷗。"]'),
('57921126-316b-4967-a828-e08a6ffe74cb','尋白石山真禪師舊草堂','劉長卿','唐','唐诗','tang','','[]','惆悵雲山暮，閑門獨不開。',48,'全唐诗/poet.tang.7000.json','["惆悵雲山暮，閑門獨不開。", "何時飛杖錫，終日閉蒼苔。", "隔嶺春猶在，無人燕亦來。", "誰堪暝投處，空復一猨哀。"]'),
('1285b2d0-b7ad-42fa-981f-bf96b84791cc','送行軍張司馬罷使迴','劉長卿','唐','唐诗','tang','','[]','時危身赴敵，事往任浮沈。',48,'全唐诗/poet.tang.7000.json','["時危身赴敵，事往任浮沈。", "末路三江去，當時百戰心。", "春風吳苑綠，古木剡山深。", "千里滄波上，孤舟不可尋。"]'),
('41a76e28-465d-454d-9be4-08d4293f2708','喜李翰自越至','劉長卿','唐','唐诗','tang','','[]','南浮滄海上，萬里到吳臺。',48,'全唐诗/poet.tang.7000.json','["南浮滄海上，萬里到吳臺。", "久別長相憶，孤舟何處來。", "春風催客醉，江月向人開。", "羨爾無羈束，沙鷗獨不猜。"]'),
('e954d58f-feb2-4392-a31a-9aae9944deed','罪所留繫寄張十四','劉長卿','唐','唐诗','tang','','[]','不見君來久，冤深意未傳。',48,'全唐诗/poet.tang.7000.json','["不見君來久，冤深意未傳。", "冶長空得罪，夷甫豈言錢。", "直道天何在，愁容鏡亦憐。", "因書欲自訴，無淚可潸然。"]'),
('44824d1a-ffc0-4793-b436-134073275e96','送勤照和尚往睢陽赴太守請','劉長卿','唐','唐诗','tang','','[]','燃燈傳七祖，杖錫爲諸侯。',48,'全唐诗/poet.tang.7000.json','["燃燈傳七祖，杖錫爲諸侯。", "來去雲無意，東西水自流。", "青山春滿目，白日夜隨舟。", "知到梁園下，蒼生賴此遊。"]'),
('76da5012-0d84-4f65-9fef-02e32649d455','長門怨','劉長卿','唐','唐诗','tang','','[]','何事長門閉，珠簾只自垂。',48,'全唐诗/poet.tang.7000.json','["何事長門閉，珠簾只自垂。", "月移深殿早，春向後宮遲。", "蕙草生閑地，梨花發舊枝。", "芳菲自恩幸，看著被風吹。"]'),
('749adb62-e238-4e32-9791-b1e9eca0bc83','過橫山顧山人草堂','劉長卿','唐','唐诗','tang','','[]','只見山相掩，誰言路尚通。',48,'全唐诗/poet.tang.7000.json','["只見山相掩，誰言路尚通。", "人來千嶂外，犬吠百花中。", "細草香飄雨，垂楊閑臥風。", "却尋樵徑去，惆悵綠溪東。"]'),
('a4d48d13-f3cb-445a-9e57-65cf82732576','送李校書適越謁杜中丞','劉長卿','唐','唐诗','tang','','[]','江風處處盡，旦暮水空波。',48,'全唐诗/poet.tang.7000.json','["江風處處盡，旦暮水空波。", "搖落行人去，雲山向越多。", "陳蕃懸榻待，謝客枉帆過。", "相見耶溪路，逶迤入薜蘿。"]'),
('5b0dbbd2-8da9-4b1f-903d-e0f0ea79efd8','秋夜雨中諸公過靈光寺所居','劉長卿','唐','唐诗','tang','','[]','晤語青蓮舍，重門閉夕陰。',48,'全唐诗/poet.tang.7000.json','["晤語青蓮舍，重門閉夕陰。", "向人寒燭靜，帶雨夜鐘沈。", "流水從他事，孤雲任此心。", "不能捐斗粟，終日媿瑤琴。"]'),
('5050ffa2-e966-43f5-ac8d-f21c53723073','西庭夜燕喜評事兄拜會','劉長卿','唐','唐诗','tang','','[]','猶是南州吏，江城又一春。',48,'全唐诗/poet.tang.7000.json','["猶是南州吏，江城又一春。", "隔簾湖上月，對酒眼中人。", "棘寺初銜命，梅仙已誤身。", "無心羨榮祿，唯待却垂綸。"]'),
('04af557e-bac8-4fbf-92e7-d8a87fa11038','尋南溪常山道人隱居','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u4e94\u8a00\u5f8b\u8bd7"]','一路經行處，莓苔見履痕。',48,'全唐诗/poet.tang.7000.json','["一路經行處，莓苔見履痕。", "白雲依靜渚，春草閉閑門。", "過雨看松色，隨山到水源。", "溪花與禪意，相對亦忘言。"]'),
('4a5f33bf-639a-479e-bc05-623abbdc4aa6','揚州雨中張十宅觀妓','劉長卿','唐','唐诗','tang','','[]','夜色帶春煙，燈花拂更然。',48,'全唐诗/poet.tang.7000.json','["夜色帶春煙，燈花拂更然。", "殘粧添石黛，豔舞落金鈿。", "掩笑頻欹扇，迎歌乍動弦。", "不知巫峽雨，何事海西邊。"]'),
('ddbe854e-ed66-43eb-8808-31f8a8b2c478','赴宣州使院夜宴寂上人房留辭前蘇州韋使君','劉長卿','唐','唐诗','tang','','[]','白雲乖始願，滄海有微波。',48,'全唐诗/poet.tang.7000.json','["白雲乖始願，滄海有微波。", "戀舊爭趨府，臨危欲負戈。", "春歸花殿暗，秋傍竹房多。", "耐可機心息，其如羽檄何。"]'),
('3aa3bc1a-8bed-467a-a1b1-d61c98aa9f96','送薛承矩秩滿北遊','劉長卿','唐','唐诗','tang','','[]','匹馬向何處，北遊殊未還。',48,'全唐诗/poet.tang.7000.json','["匹馬向何處，北遊殊未還。", "寒雲帶飛雪，日暮雁門關。", "一路傍汾水，數州看晉山。", "知君喜初服，秪愛此身閑。"]'),
('1487452b-5f49-4f4f-9913-1f3ec1cddf95','餞別王十一南遊','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u957f\u6c5f", "\u53cb\u60c5", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7"]','望君煙水闊，揮手淚霑巾。',48,'全唐诗/poet.tang.7000.json','["望君煙水闊，揮手淚霑巾。", "飛鳥沒何處，青山空向人。", "長江一帆遠，落日五湖春。", "誰見汀洲上，相思愁白蘋。"]'),
('b96ed9b0-175f-4a0f-a193-0c89ab696596','送嚴維尉諸暨','劉長卿','唐','唐诗','tang','','[]','愛爾文章遠，還家印綬榮。',48,'全唐诗/poet.tang.7000.json','["愛爾文章遠，還家印綬榮。", "退公兼色養，臨下帶鄉情。", "喬木映官舍，春山宜縣城。", "應憐釣臺石，閑却爲浮名。"]'),
('f18de4b4-2309-4a58-91fb-fbc07f054d61','送李七之莋水謁張相公','劉長卿','唐','唐诗','tang','','[]','惆悵青春晚，慇懃濁酒壚。',48,'全唐诗/poet.tang.7000.json','["惆悵青春晚，慇懃濁酒壚。", "後時長劒澀，斜日片帆孤。", "東閣邀才子，南昌老腐儒。", "梁國舊相識，誰憶臥江湖。"]'),
('c198f744-ce8c-41a2-907d-84012b2e7ced','送崔處士先適越','劉長卿','唐','唐诗','tang','','[]','山陰好雲物，此去又春風。',48,'全唐诗/poet.tang.7000.json','["山陰好雲物，此去又春風。", "越鳥聞花裏，曹娥想鏡中。", "小江潮易滿，萬井水皆通。", "徒羨扁舟客，微官事不同。"]'),
('90e0fc08-1ba8-4395-a94e-9586852c27e2','奉陪使君西庭送淮西魏判官','劉長卿','唐','唐诗','tang','','[]','羽檄催歸恨，春風醉別顏。',48,'全唐诗/poet.tang.7000.json','["羽檄催歸恨，春風醉別顏。", "能邀五馬送，自逐一星還。", "破竹從軍樂，看花聽訟閑。", "遙知用兵處，多在八公山。"]'),
('10ec49e8-146c-41c8-9660-02c275a467f0','獄中見壁畫佛','劉長卿','唐','唐诗','tang','','[]','不謂銜冤處，而能窺大悲。',48,'全唐诗/poet.tang.7000.json','["不謂銜冤處，而能窺大悲。", "獨棲叢棘下，還見雨花時。", "地狹青蓮小，城高白日遲。", "幸親方便力，猶畏毒龍欺。"]'),
('8570f120-231a-4594-abd4-b3cc5071a289','送許拾遺還京','劉長卿','唐','唐诗','tang','','[]','萬里辭三殿，金陵到舊居。',48,'全唐诗/poet.tang.7000.json','["萬里辭三殿，金陵到舊居。", "文星出西掖，卿月在南徐。", "故里驚朝服，高堂捧詔書。", "暫容乘駟馬，誰許戀鱸魚。"]'),
('bce947e4-574d-4fc2-a886-a8a95e907262','送張七判官還京覲省','劉長卿','唐','唐诗','tang','','[]','春蘭方可採，此去葉初齊。',48,'全唐诗/poet.tang.7000.json','["春蘭方可採，此去葉初齊。", "函谷鶯聲裏，秦山馬首西。", "庭闈新栢署，門館舊桃蹊。", "春色長安道，相隨入禁閨。"]'),
('7c0107fd-13f1-4ce7-8248-e774c43db3fd','送孫瑩京監擢第歸蜀覲省','劉長卿','唐','唐诗','tang','','[]','適賀一枝新，旋驚萬里分。',48,'全唐诗/poet.tang.7000.json','["適賀一枝新，旋驚萬里分。", "禮闈稱獨步，太學許能文。", "征馬望春草，行人看暮雲。", "遙知倚門處，江樹正氛氳。"]'),
('63035e67-c1aa-405a-8660-a53c378a933c','送史九赴任寧陵兼呈單父史八時監察五兄初入臺','劉長卿','唐','唐诗','tang','','[]','趨府弟聯兄，看君此去榮。',48,'全唐诗/poet.tang.7000.json','["趨府弟聯兄，看君此去榮。", "春隨千里道，河帶萬家城。", "繡服棠花映，青袍草色迎。", "梁園修竹在，持贈結交情。"]'),
('d03098c5-4d9e-4d06-82d1-a14769d01df3','臥病喜田九見寄','劉長卿','唐','唐诗','tang','','[]','臥來能幾日，春事已依然。',48,'全唐诗/poet.tang.7000.json','["臥來能幾日，春事已依然。", "不解謝公意，翻令靜者便。", "庭陰殘舊雪，柳色帶新年。", "寂寞深村裏，唯君相訪偏。"]'),
('5cb68537-4c65-489f-81a5-132344ccf113','重過宣峰寺山房寄靈一上人','劉長卿','唐','唐诗','tang','','[]','西陵潮信滿，島嶼入中流。',48,'全唐诗/poet.tang.7000.json','["西陵潮信滿，島嶼入中流。", "越客依風水，相思南渡頭。", "寒光生極浦，暮雪映滄洲。", "何事揚帆去，空驚海上鷗。"]'),
('a338939b-2ed2-408b-a6bc-7acdec143f7a','雲門寺訪靈一上人','劉長卿','唐','唐诗','tang','','[]','所思勞日夕，惆悵去西東。',48,'全唐诗/poet.tang.7000.json','["所思勞日夕，惆悵去西東。", "禪客知何在，春山到處同。", "獨行殘雪裏，相見白雲中。", "請近東林寺，窮年事遠公。"]'),
('17154f34-f404-4c8b-85c8-3deb628f1661','送陸羽之茅山寄李延陵','劉長卿','唐','唐诗','tang','','[]','延陵衰草遍，有路問茅山。',48,'全唐诗/poet.tang.7000.json','["延陵衰草遍，有路問茅山。", "雞犬驅將去，煙霞擬不還。", "新家彭澤縣，舊國穆陵關。", "處處逃名姓，無名亦是閑。"]'),
('bbc87b26-3540-4adc-a325-d30f2ba23ee6','寄靈一上人初還雲門','劉長卿','唐','唐诗','tang','','[]','寒霜白雲裏，法侶自相攜。',48,'全唐诗/poet.tang.7000.json','["寒霜白雲裏，法侶自相攜。", "竹逕通城下，松風隔水西。", "方同沃洲去，不作武陵迷。", "髣髴知心處，高峰是會稽。"]'),
('338ed593-fa8b-4004-88c8-9189a6f99f87','寄靈一上人','劉長卿','唐','唐诗','tang','','[]','高僧本姓竺，開士舊名林。',48,'全唐诗/poet.tang.7000.json','["高僧本姓竺，開士舊名林。", "一去春山裏，千峰不可尋。", "新年芳草遍，終日白雲深。", "欲徇微官去，懸知訝此心。"]'),
('b4a6680a-eac3-447a-96b7-47c20c9177b8','送韓司直','劉長卿','唐','唐诗','tang','','[]','遊吳還入越，來往任風波。',48,'全唐诗/poet.tang.7000.json','["遊吳還入越，來往任風波。", "復送王孫去，其如春草何。", "岸明殘雪在，潮滿夕陽多。", "季子楊柳廟，停舟試一過。"]'),
('71964553-851c-4f22-83f2-a521d3b3a15e','酬李郎中夜登蘇州城樓見寄','劉長卿','唐','唐诗','tang','','[]','辛勤萬里道，蕭索九秋殘。',48,'全唐诗/poet.tang.7000.json','["辛勤萬里道，蕭索九秋殘。", "日照閩中夜，天凝海上寒。", "客程無地遠，主意在人安。", "遙寄登樓作，空知行路難。"]'),
('c0e686cd-cf24-4ed8-afaf-8080ac97e567','送人遊越','劉長卿','唐','唐诗','tang','','[]','未習風波事，初爲吳越遊。',48,'全唐诗/poet.tang.7000.json','["未習風波事，初爲吳越遊。", "露霑湖色曉，月照海門秋。", "梅市門何在，蘭亭水尚流。", "西陵待潮處，落日滿扁舟。"]'),
('e8499552-faf7-4418-a512-428a703b6b8f','贈普門上人','劉長卿','唐','唐诗','tang','','[]','支公身欲老，長在沃洲多。',48,'全唐诗/poet.tang.7000.json','["支公身欲老，長在沃洲多。", "惠力堪傳教，禪心久伏魔。", "山雲隨坐夏，江草伴頭陀。", "借問迴心後，賢愚去幾何。"]'),
('8bb386e8-5066-44b5-bb00-8d6b6b70bd8e','送康判官往新安','劉長卿','唐','唐诗','tang','','[]','不向新安去，那知江路長。',48,'全唐诗/poet.tang.7000.json','["不向新安去，那知江路長。", "猨聲近廬霍，水色勝瀟湘。", "驛路收殘雨，漁家帶夕陽。", "何須愁旅泊，使者有輝光。"]'),
('36b4e183-f231-4e3c-9ff3-eeb68a915a45','送顧長','劉長卿','唐','唐诗','tang','','[]','由來山水客，復道向新安。',48,'全唐诗/poet.tang.7000.json','["由來山水客，復道向新安。", "半是乘槎便，全非行路難。", "晨裝林月在，野飯浦沙寒。", "嚴子千年後，何人釣舊灘。"]'),
('0ff46b95-fb09-45d0-80ab-6fc12ce17cb4','九日登李明府北樓','劉長卿','唐','唐诗','tang','','[]','九日登高望，蒼蒼遠樹低。',48,'全唐诗/poet.tang.7000.json','["九日登高望，蒼蒼遠樹低。", "人煙湖草裏，山翠縣樓西。", "霜降鴻聲切，秋深客思迷。", "無勞白衣酒，陶令自相攜。"]'),
('49c0119c-d873-43d1-b625-bd786d10ea87','同諸公登樓','劉長卿','唐','唐诗','tang','','[]','秋草行將暮，登樓客思驚。',48,'全唐诗/poet.tang.7000.json','["秋草行將暮，登樓客思驚。", "千家同霽色，一鴈報寒聲。", "北望無鄉信，東遊滯客行。", "今君佩銅墨，還有越鄉情。"]'),
('9a00c87b-69b6-4627-8830-06062221f811','送友人南遊','劉長卿','唐','唐诗','tang','','[]','不愁尋水遠，自愛逐連山。',48,'全唐诗/poet.tang.7000.json','["不愁尋水遠，自愛逐連山。", "雖在春風裏，猶從芳草間。", "去程何用計，勝事且相關。", "旅逸同羣鳥，悠悠往復還。"]'),
('21d525f5-1980-46f2-abf3-6501563a9aef','送裴二十一','劉長卿','唐','唐诗','tang','','[]','多病長無事，開筵暫送君。',48,'全唐诗/poet.tang.7000.json','["多病長無事，開筵暫送君。", "正愁帆帶雨，莫望水連雲。", "客思閑偏極，川程遠更分。", "不須論早晚，惆悵又離羣。"]'),
('6ef58313-2e18-49cf-90b3-6f96e24c0275','送張判官罷使東歸','劉長卿','唐','唐诗','tang','','[]','白首辭知己，滄洲憶舊居。',48,'全唐诗/poet.tang.7000.json','["白首辭知己，滄洲憶舊居。", "落潮迴野艇，積雪臥官廬。", "范叔寒猶在，周王歲欲除。", "春山數畝地，歸去帶經鉏。"]'),
('2df0e3e0-b9af-4631-a112-d7ac89daf18d','早春','劉長卿','唐','唐诗','tang','','[]','微雨夜來歇，江南春色迴。',48,'全唐诗/poet.tang.7000.json','["微雨夜來歇，江南春色迴。", "本驚時不住，還恐老相催。", "人好千場醉，花無百日開。", "豈堪滄海畔，爲客十年來。"]'),
('f3151345-6219-4360-b666-e62a5b22270d','送青苗鄭判官歸江西','劉長卿','唐','唐诗','tang','','[]','三苗餘古地，五稼滿秋田。',48,'全唐诗/poet.tang.7000.json','["三苗餘古地，五稼滿秋田。", "來問周公稅，歸輸漢俸錢。", "江城寒背日，湓水暮連天。", "南楚凋殘後，疲民賴爾憐。"]'),
('9cfb817b-fca9-487d-8355-fa04144fdeb6','過包尊師山院','劉長卿','唐','唐诗','tang','','[]','賣藥曾相識，吹蕭此復聞。',48,'全唐诗/poet.tang.7000.json','["賣藥曾相識，吹蕭此復聞。", "杏花誰是主，桂樹獨留君。", "漱玉臨丹井，圍碁訪白雲。", "道經今爲寫，不慮惜鵝羣。"]'),
('f64921ce-c218-4962-af65-b79b7e134ee7','故女道士婉儀太原郭氏挽歌詞 一','劉長卿','唐','唐诗','tang','','[]','作範宮闈睦，歸真道藝超。',48,'全唐诗/poet.tang.7000.json','["作範宮闈睦，歸真道藝超。", "馭風仙路遠，背日帝宮遙。", "鸞殿空留處，霓裳已罷朝。", "淮王哀不盡，松柏但蕭蕭。"]'),
('6343e0b2-b4cd-4155-b6b3-55b9f8660d7c','故女道士婉儀太原郭氏挽歌詞 二','劉長卿','唐','唐诗','tang','','[]','宮禁恩長隔，神仙道已分。',48,'全唐诗/poet.tang.7000.json','["宮禁恩長隔，神仙道已分。", "人間驚早露，天上失朝雲。", "逝水年無限，佳城日易曛。", "簫聲將薤曲，哀斷不堪聞。"]'),
('32c9d409-9206-4100-817d-63c395dd832a','少年行','劉長卿','唐','唐诗','tang','','[]','射飛誇侍獵，行樂愛聯鑣。',48,'全唐诗/poet.tang.7000.json','["射飛誇侍獵，行樂愛聯鑣。", "薦枕青蛾豔，鳴鞭白馬驕。", "曲房珠翠合，深巷管弦調。", "日晚春風裏，衣香滿路飄。"]'),
('6d97de54-3443-4dfd-b80f-b1077c2d5171','歸弋陽山居留別盧邵二侍御','劉長卿','唐','唐诗','tang','','[]','渺渺歸何處，沿流附客船。',48,'全唐诗/poet.tang.7000.json','["渺渺歸何處，沿流附客船。", "久依鄱水住，頻稅越人田。", "偶俗機偏少，安閑性所便。", "祗應君少慣，又欲寄林泉。"]'),
('6be8c63b-a2fd-46f5-b0e5-e43fc5305c4d','赴江西湖上贈皇甫曾之宣州','劉長卿','唐','唐诗','tang','','["\u897f\u6e56"]','莫恨扁舟去，川途我更遙。',48,'全唐诗/poet.tang.7000.json','["莫恨扁舟去，川途我更遙。", "東西潮渺渺，離別雨蕭蕭。", "流水通春谷，青山過板橋。", "天涯有來客，遲爾訪漁樵。"]'),
('6034f75a-a1fc-4ed2-aeec-a6f2d1c12c2c','湘中紀行十首 湘妃廟','劉長卿','唐','唐诗','tang','','[]','荒祠古木暗，寂寂此江濆。',48,'全唐诗/poet.tang.7000.json','["荒祠古木暗，寂寂此江濆。", "未作湘南雨，知爲何處雲。", "苔痕斷珠履，草色帶羅裙。", "莫唱迎仙曲，空山不可聞。"]'),
('698569ba-9ce6-4d94-9395-07d86d48634e','湘中紀行十首 斑竹巖','劉長卿','唐','唐诗','tang','','[]','蒼梧在何處，斑竹自成林。',48,'全唐诗/poet.tang.7000.json','["蒼梧在何處，斑竹自成林。", "點點留殘淚，枝枝寄此心。", "寒山響易滿，秋水影偏深。", "欲覓樵人路，蒙籠不可尋。"]'),
('308280bc-9b1b-45fb-9778-723e13dee642','湘中紀行十首 洞山陽','劉長卿','唐','唐诗','tang','','[]','舊日仙成處，荒林客到稀。',48,'全唐诗/poet.tang.7000.json','["舊日仙成處，荒林客到稀。", "白雲將犬去，芳草任人歸。", "空谷無行徑，深山少落暉。", "桃園幾家住，誰爲掃荆扉。"]'),
('7152b1e3-efff-46de-8ab3-34ca517621d9','湘中紀行十首 雲母溪','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','雲母映溪水，溪流知幾春。',48,'全唐诗/poet.tang.7000.json','["雲母映溪水，溪流知幾春。", "深藏武陵客，時過洞庭人。", "白髮慚皎鏡，清光媚奫淪。", "寥寥古松下，歲晚挂頭巾。"]'),
('81fdf606-72d6-438a-9c74-db5e2554a52b','湘中紀行十首 赤沙湖','劉長卿','唐','唐诗','tang','','[]','茫茫葭菼外，一望一霑衣。',48,'全唐诗/poet.tang.7000.json','["茫茫葭菼外，一望一霑衣。", "秋水連天闊，涔陽何處歸。", "沙鷗積暮雪，川日動寒暉。", "楚客來相問，孤舟泊釣磯。"]'),
('a42503d9-d919-48bc-a8ba-51c9bd3aea56','湘中紀行十首 秋雲嶺','劉長卿','唐','唐诗','tang','','[]','山色無定姿，如煙復如黛。',48,'全唐诗/poet.tang.7000.json','["山色無定姿，如煙復如黛。", "孤峰夕陽後，翠嶺秋天外。", "雲起遙蔽虧，江迴頻向背。", "不知今遠近，到處猶相對。"]'),
('141ab67f-ae08-404c-856f-ae5bf31406ab','湘中紀行十首 花石潭','劉長卿','唐','唐诗','tang','','[]','江楓日搖落，轉愛寒潭靜。',48,'全唐诗/poet.tang.7000.json','["江楓日搖落，轉愛寒潭靜。", "水色淡如空，山光復相映。", "人閑流更慢，魚戲波難定。", "楚客往來多，偏知白鷗性。"]'),
('14b9f2ba-3904-4b22-94a0-142c899a01c5','湘中紀行十首 石圍峰','劉長卿','唐','唐诗','tang','','[]','前山帶秋色，獨往秋江晚。',50,'全唐诗/poet.tang.7000.json','["前山帶秋色，獨往秋江晚。", "疊嶂入雲多，孤峰去人遠。", "[夤]緣不可到，蒼翠空在眼。", "渡口問漁家，桃源路深淺。"]'),
('6ea5e8c6-ccb7-4983-98c1-e1bb3daf0c81','湘中紀行十首 浮石瀨','劉長卿','唐','唐诗','tang','','[]','秋月照瀟湘，月明聞盪槳。',48,'全唐诗/poet.tang.7000.json','["秋月照瀟湘，月明聞盪槳。", "石橫晚瀨急，水落寒沙廣。", "衆嶺猨嘯重，空江人語響。", "清暉朝復暮，如待扁舟賞。"]'),
('ef8efd33-5aec-467c-a9f2-f87340dde6ec','湘中紀行十首 橫龍渡','劉長卿','唐','唐诗','tang','','[]','空傳古岸下，曾見蛟龍去。',48,'全唐诗/poet.tang.7000.json','["空傳古岸下，曾見蛟龍去。", "秋水晚沈沈，猶疑在深處。", "亂聲沙上石，倒影雲中樹。", "獨見一扁舟，樵人往來渡。"]'),
('0b7523f5-78da-475b-814b-cf6e43e58eb3','雜詠八首上禮部李侍郎 幽琴','劉長卿','唐','唐诗','tang','','[]','月色滿軒白，琴聲宜夜闌。',48,'全唐诗/poet.tang.7000.json','["月色滿軒白，琴聲宜夜闌。", "飀飀青絲上，靜聽松風寒。", "古調雖自愛，今人多不彈。", "向君投此曲，所貴知音難。"]'),
('4b8b30c9-4f25-458c-bf31-f914ffc9ce99','雜詠八首上禮部李侍郎 晚桃','劉長卿','唐','唐诗','tang','','[]','四月深澗底，桃花方欲然。',48,'全唐诗/poet.tang.7000.json','["四月深澗底，桃花方欲然。", "寧知地勢下，遂使春風偏。", "此意頗堪惜，無言誰爲傳。", "過時君未賞，空媚幽林前。"]'),
('20e1ebca-d690-495d-9280-f75cffa60172','雜詠八首上禮部李侍郎 疲馬','劉長卿','唐','唐诗','tang','','[]','玄黃一疲馬，筋力盡胡塵。',48,'全唐诗/poet.tang.7000.json','["玄黃一疲馬，筋力盡胡塵。", "驤首北風夕，徘徊鳴向人。", "誰憐棄置久，欲與駑駘親。", "猶戀長城外，青青寒草春。"]'),
('bf32721c-143b-44ae-8cec-9c114f17b623','雜詠八首上禮部李侍郎 春鏡','劉長卿','唐','唐诗','tang','','[]','寶鏡凌曙開，含虛淨如水。',48,'全唐诗/poet.tang.7000.json','["寶鏡凌曙開，含虛淨如水。", "獨懸秦臺上，萬象清光裏。", "豈慮高鑒偏，但防流塵委。", "不知娉婷色，回照今何似。"]'),
('ce619ad9-c87f-4719-b56d-8993d7b4ab8c','雜詠八首上禮部李侍郎 古劒','劉長卿','唐','唐诗','tang','','[]','龍泉閑古匣，苔蘚淪此地。',48,'全唐诗/poet.tang.7000.json','["龍泉閑古匣，苔蘚淪此地。", "何意久藏鋒，翻令世人棄。", "鐵衣今正澀，寶刃猶可試。", "儻遇拂拭恩，應知剸犀利。"]'),
('62a877ad-3fc8-4100-b202-41477229be6c','雜詠八首上禮部李侍郎 舊井','劉長卿','唐','唐诗','tang','','[]','舊井依舊城，寒水深洞徹。',48,'全唐诗/poet.tang.7000.json','["舊井依舊城，寒水深洞徹。", "下看百餘尺，一鏡光不滅。", "素綆久未垂，清涼尚含潔。", "豈能無汲引，長訝君恩絕。"]'),
('352facdd-ac75-42aa-8604-624b3ed38096','雜詠八首上禮部李侍郎 白鷺','劉長卿','唐','唐诗','tang','','[]','亭亭常獨立，川上時延頸。',48,'全唐诗/poet.tang.7000.json','["亭亭常獨立，川上時延頸。", "秋水寒白毛，夕陽弔孤影。", "幽姿閑自媚，逸翮思一騁。", "如有長風吹，青雲在俄頃。"]'),
('abc45421-ac3e-491e-845c-eff4daa8ae5e','雜詠八首上禮部李侍郎 寒釭','劉長卿','唐','唐诗','tang','','[]','向夕燈稍進，空堂彌寂寞。',48,'全唐诗/poet.tang.7000.json','["向夕燈稍進，空堂彌寂寞。", "光寒對愁人，時復一花落。", "但恐明見累，何愁暗難托。", "戀君秋夜永，無使蘭膏薄。"]'),
('488b6b71-49c9-468a-8f22-3425eae37daa','寄李侍御','劉長卿','唐','唐诗','tang','','[]','舊國人未歸，芳洲草還碧。',48,'全唐诗/poet.tang.7000.json','["舊國人未歸，芳洲草還碧。", "年年湖上亭，悵望江南客。", "驄馬入關西，白雲獨何適。", "相思煙水外，唯有心不隔。"]'),
('2a3161e7-9c31-432d-b843-107f9f1fac7a','晚泊湘江懷故人','劉長卿','唐','唐诗','tang','','[]','天涯片雲去，遙指帝鄉憶。',48,'全唐诗/poet.tang.7000.json','["天涯片雲去，遙指帝鄉憶。", "惆悵增暮情，瀟湘復秋色。", "扁舟宿何處，落日羨歸翼。", "萬里無故人，江鷗不相識。"]'),
('7dac99dd-58f0-4275-b0f9-9ebaa15b246e','過鄥三湖上書齋','劉長卿','唐','唐诗','tang','','[]','何事東南客，忘機一釣竿。',48,'全唐诗/poet.tang.7000.json','["何事東南客，忘機一釣竿。", "酒香開甕老，湖色對門寒。", "向郭青山送，臨池白鳥看。", "見君能浪跡，予亦厭微官。"]'),
('28fe0cb5-04d4-473d-b1b9-523bf6d957dd','從軍六首 一','劉長卿','唐','唐诗','tang','','[]','迴看虜騎合，城下漢兵稀。',36,'全唐诗/poet.tang.7000.json','["迴看虜騎合，城下漢兵稀。", "白刃兩相向，黃雲愁不飛。", "手中無尺鐵，徒欲突重圍。"]'),
('162bb14f-83e0-4450-a6cd-9fd64bf2d47c','從軍六首 二','劉長卿','唐','唐诗','tang','','[]','目極鴈門道，青青邊草春。',36,'全唐诗/poet.tang.7000.json','["目極鴈門道，青青邊草春。", "一身事征戰，匹馬同苦辛。", "末路成白首，功歸天下人。"]'),
('6e25e90a-ba40-4019-a216-6c2917acf794','從軍六首 三','劉長卿','唐','唐诗','tang','','[]','倚劒白日暮，望鄉登戍樓。',36,'全唐诗/poet.tang.7000.json','["倚劒白日暮，望鄉登戍樓。", "北風吹羌笛，此夜關山愁。", "迴首不無意，滹河空自流。"]'),
('5eff304b-dc1d-42a9-96b2-472a41ddac85','從軍六首 四','劉長卿','唐','唐诗','tang','','[]','黃沙一萬里，白首無人憐。',36,'全唐诗/poet.tang.7000.json','["黃沙一萬里，白首無人憐。", "報國劒已折，歸鄉身幸全。", "單于古臺下，邊色寒蒼然。"]'),
('407d703d-2756-458b-b5a5-da0e8f90dd68','從軍六首 五','劉長卿','唐','唐诗','tang','','[]','落日更蕭條，北風動枯草。',36,'全唐诗/poet.tang.7000.json','["落日更蕭條，北風動枯草。", "將軍追虜騎，夜失陰山道。", "戰敗仍樹勳，韓彭但空老。"]'),
('6f6112f9-e619-4ce6-9d77-ba2a64f2bece','從軍六首 六','劉長卿','唐','唐诗','tang','','[]','草枯秋塞上，望見漁陽郭。',36,'全唐诗/poet.tang.7000.json','["草枯秋塞上，望見漁陽郭。", "胡馬嘶一聲，漢兵淚雙落。", "誰爲吮瘡者，此事今人薄。"]'),
('bfa4f6f9-c928-48a0-882a-b40308585505','龍門八詠 闕口','劉長卿','唐','唐诗','tang','','[]','秋山日搖落，秋水急波瀾。',36,'全唐诗/poet.tang.7000.json','["秋山日搖落，秋水急波瀾。", "獨見魚龍氣，長令煙雨寒。", "誰窮造化力，空向兩崖看。"]'),
('57903765-0883-429a-aa86-584d9b2b7058','龍門八詠 水東渡','劉長卿','唐','唐诗','tang','','[]','山葉傍崖赤，千峰秋色多。',36,'全唐诗/poet.tang.7000.json','["山葉傍崖赤，千峰秋色多。", "夜泉發清響，寒渚生微波。", "稍見沙上月，歸人爭渡河。"]'),
('04daed88-7303-4b95-9402-95bfded35309','龍門八詠 福公塔','劉長卿','唐','唐诗','tang','','[]','寂寞對伊水，經行長未還。',36,'全唐诗/poet.tang.7000.json','["寂寞對伊水，經行長未還。", "東流自朝暮，千載空雲山。", "誰見白鷗鳥，無心洲渚間。"]'),
('4fd2afb8-37e6-49f8-a164-9880fe72f1f2','龍門八詠 遠公龕','劉長卿','唐','唐诗','tang','','[]','松路向精舍，花龕歸老僧。',36,'全唐诗/poet.tang.7000.json','["松路向精舍，花龕歸老僧。", "閑雲隨錫杖，落日低金繩。", "入夜翠微裏，千峰明一燈。"]'),
('a2296a2c-e27b-4864-990e-c48e3eb31c09','龍門八詠 石樓','劉長卿','唐','唐诗','tang','','[]','隱隱見花閣，隔河映青林。',36,'全唐诗/poet.tang.7000.json','["隱隱見花閣，隔河映青林。", "水田秋鴈下，山寺夜鐘深。", "寂寞羣動息，風泉清道心。"]'),
('dd0bcd8e-779c-4de4-9419-89367ce14598','龍門八詠 下山','劉長卿','唐','唐诗','tang','','[]','誰識往來意，孤雲長自閑。',36,'全唐诗/poet.tang.7000.json','["誰識往來意，孤雲長自閑。", "風寒未渡水，日暮更看山。", "木落衆峰出，龍宮蒼翠間。"]'),
('37afabc0-a58f-41c4-9463-f95d69c6aab2','龍門八詠 水西渡','劉長卿','唐','唐诗','tang','','[]','伊水搖鏡光，纖鱗如不隔。',36,'全唐诗/poet.tang.7000.json','["伊水搖鏡光，纖鱗如不隔。", "千龕道傍古，一鳥沙上白。", "何事還山雲，能留向城客。"]'),
('401cd681-5518-40a4-a9ee-e63d17ea107f','龍門八詠 渡水','劉長卿','唐','唐诗','tang','','[]','日暮下山來，千山暮鐘發。',36,'全唐诗/poet.tang.7000.json','["日暮下山來，千山暮鐘發。", "不知波上棹，還弄山中月。", "伊水連白雲，東南遠明滅。"]'),
('51d79199-8a00-456b-9bb2-9ec17eea3a2b','月下聽砧','劉長卿','唐','唐诗','tang','','[]','夜靜掩寒城，清砧發何處？',36,'全唐诗/poet.tang.7000.json','["夜靜掩寒城，清砧發何處？", "聲聲擣秋月，腸斷盧龍戍。", "未得寄征人，愁霜復愁露。"]'),
('eca9c72d-2848-4031-9461-4a4039df5d91','送丘爲赴上都','劉長卿','唐','唐诗','tang','','[]','帝鄉何處是，歧路空垂泣。',36,'全唐诗/poet.tang.7000.json','["帝鄉何處是，歧路空垂泣。", "楚思愁暮多，川程帶潮急。", "潮歸人不歸，獨向空塘立。"]'),
('52aed16e-eafb-4f0d-88d4-20e09fb7ca80','題大理黃主簿湖上高齋','劉長卿','唐','唐诗','tang','','[]','閉門湖水畔，自與白鷗親。',60,'全唐诗/poet.tang.7000.json','["閉門湖水畔，自與白鷗親。", "竟日窗中岫，終年林下人。", "俗輕儒服弊，家厭法官貧。", "多雨茅簷夜，空洲草徑春。", "桃源君莫愛，且作漢朝臣。"]'),
('fa3e46a2-eef6-4b77-a965-d0cba127e082','平蕃曲三首 一','劉長卿','唐','唐诗','tang','','[]','吹角報蕃營，迴軍欲洗兵。',24,'全唐诗/poet.tang.7000.json','["吹角報蕃營，迴軍欲洗兵。", "已教青海外，自築漢家城。"]'),
('1bcdcbdd-8b9e-4d91-9d18-242990e40b3f','平蕃曲三首 二','劉長卿','唐','唐诗','tang','','[]','渺渺戍煙孤，茫茫塞草枯。',24,'全唐诗/poet.tang.7000.json','["渺渺戍煙孤，茫茫塞草枯。", "隴頭那用閉，萬里不防胡。"]'),
('74f91114-cd88-475c-bf98-70314c2e7746','平蕃曲三首 三','劉長卿','唐','唐诗','tang','','[]','絕漠大軍還，平沙獨戍閑。',24,'全唐诗/poet.tang.7000.json','["絕漠大軍還，平沙獨戍閑。", "空留一片石，萬古在燕山。"]'),
('e59f1f46-2be3-479b-87e7-f01ffa539d74','送鄭說之歙州謁薛侍郎','劉長卿','唐','唐诗','tang','','[]','漂泊來千里，謳謠滿百城。',72,'全唐诗/poet.tang.7000.json','["漂泊來千里，謳謠滿百城。", "漢家尊太守，魯國重諸生。", "俗變人難理，江傳水至清。", "船經危石住，路入亂山行。", "老得滄州趣，春傷白首情。", "嘗聞馬南郡，門下有康成。"]'),
('b697cfce-8177-48df-b0a8-d770fa8499af','題獨孤使君湖上林亭','劉長卿','唐','唐诗','tang','','[]','出樹倚朱闌，吹鐃引上官。',72,'全唐诗/poet.tang.7000.json','["出樹倚朱闌，吹鐃引上官。", "老農持鍤拜，時稼捲簾看。", "水對登龍淨，山當建隼寒。", "夕陽湖草動，秋色渚田寬。", "渤海人無事，荆州客獨安。", "謝公何足比，來往石門難。"]'),
('b1cc7c06-6bab-45e6-8a16-e404144f101d','酬滁州李十六使君見贈','劉長卿','唐','唐诗','tang','','[]','滿鏡悲華髮，空山寄此身。',72,'全唐诗/poet.tang.7000.json','["滿鏡悲華髮，空山寄此身。", "白雲家自有，黃卷業長貧。", "嬾任垂竿老，狂因釀黍春。", "桃花迷聖代，桂樹狎幽人。", "幢蓋方臨郡，柴荆忝作鄰。", "但愁千騎至，石路却生塵。"]'),
('26b9cb31-09d8-45ea-8d4f-9d3bdbdf4a25','送嚴維赴河南充嚴中丞幕府','劉長卿','唐','唐诗','tang','','[]','久別耶溪客，來乘使者軒。',72,'全唐诗/poet.tang.7000.json','["久別耶溪客，來乘使者軒。", "用才榮入幕，扶病喜同樽。", "山屐留何處，江帆去獨翻。", "暮情辭鏡水，秋夢識雲門。", "蓮府開花萼，桃園寄子孫。", "何當舉嚴助，徧沐漢朝恩。"]'),
('908bc080-beaa-40f1-9ce5-cab722b30019','酬包諫議佶見寄之什','劉長卿','唐','唐诗','tang','','[]','佐郡媿頑疎，殊方親里閭。',72,'全唐诗/poet.tang.7000.json','["佐郡媿頑疎，殊方親里閭。", "家貧寒未度，身老歲將除。", "過雪山僧至，依陽野客舒。", "藥陳隨遠宦，梅發對幽居。", "落日棲鴞鳥，行人遺鯉魚。", "高文不可和，空媿學相如。"]'),
('10818fd5-8ff5-4256-8615-064e0c9ccb91','棲霞寺東峰尋南齊明徵君故居','劉長卿','唐','唐诗','tang','','[]','山人今不見，山鳥自相從。',72,'全唐诗/poet.tang.7000.json','["山人今不見，山鳥自相從。", "長嘯辭明主，終身臥此峰。", "泉源通石徑，磵戶掩塵容。", "古墓依寒草，前朝寄老松。", "片雲生斷壁，萬壑遍疎鐘。", "惆悵空歸去，猶疑林下逢。"]'),
('5e803c0c-31c5-44d3-8dd2-be3360578a39','奉和趙給事使君留贈李婺州舍人兼謝舍人別駕之什','劉長卿','唐','唐诗','tang','','[]','便道訪情親，東方千騎塵。',72,'全唐诗/poet.tang.7000.json','["便道訪情親，東方千騎塵。", "禁深分直夜，地遠獨行春。", "絳闕辭明主，滄洲識近臣。", "雲山隨候吏，雞犬逐歸人。", "庭顧婆娑老，邦傳蔽芾新。", "玄暉翻佐理，聞到郡齋頻。"]'),
('38241ee3-f448-4411-b490-84c038c323ff','行營酬呂侍御時尚書問罪襄陽軍次漢東境上侍御以州鄰寇賊復有水火迫於征稅詩以見諭','劉長卿','唐','唐诗','tang','','[]','不敢淮南臥，來趨漢將營。',72,'全唐诗/poet.tang.7000.json','["不敢淮南臥，來趨漢將營。", "受辭瞻左鉞，扶疾往前旌。", "井稅鶉衣樂，壺漿鶴髮迎。", "水歸餘斷岸，烽至掩孤城。", "晚日歸千騎，秋風合五兵。", "孔璋才素健，早晚檄書成。"]'),
('5150a64f-f1ed-4fce-a76c-00afcab2de64','登遷仁樓酬子壻李穆','劉長卿','唐','唐诗','tang','','[]','臨風敞麗譙，落日聽吹鐃。',72,'全唐诗/poet.tang.7000.json','["臨風敞麗譙，落日聽吹鐃。", "歸路空迴首，新章已在腰。", "非才受官謗，無政作人謠。", "儉歲安三戶，餘年寄六條。", "春蕪生楚國，古樹過隋朝。", "賴有東牀客，池塘免寂寥。"]'),
('f15966f6-c014-40a1-b09a-1d2af25df2c5','別李氏女子','劉長卿','唐','唐诗','tang','','[]','念爾嫁猶近，稚年那別親。',72,'全唐诗/poet.tang.7000.json','["念爾嫁猶近，稚年那別親。", "臨歧方教誨，所貴和六姻。", "俛首戴荆釵，欲拜淒且嚬。", "本來儒家子，莫恥梁鴻貧。", "漢川若可涉，水清石磷磷。", "天涯遠鄉婦，月下孤舟人。"]'),
('dae41b00-bbdf-4a94-a3ff-c18c4e95c298','長沙早春雪後臨湘水呈同遊諸子','劉長卿','唐','唐诗','tang','','[]','汀洲暖漸淥，煙景淡相和。',72,'全唐诗/poet.tang.7000.json','["汀洲暖漸淥，煙景淡相和。", "舉目方如此，歸心豈奈何。", "日華浮野雪，春色染湘波。", "北渚生芳草，東風變舊柯。", "江山古思遠，猨鳥暮情多。", "君問漁人意，滄浪自有歌。"]'),
('935aa372-f84f-482b-be94-a1c9347b7776','自道林寺西入石路至麓山寺過法崇禪師故居','劉長卿','唐','唐诗','tang','','[]','山僧候谷口，石路拂莓苔。',72,'全唐诗/poet.tang.7000.json','["山僧候谷口，石路拂莓苔。", "深入泉源去，遙從樹杪回。", "香隨青靄散，鐘過白雲來。", "野雪空齋掩，山風古殿開。", "桂寒知自發，松老問誰栽。", "惆悵湘江水，何人更渡杯。"]'),
('06b617aa-b5b4-4a26-8162-4ce3a73c1d4c','和袁郎中破賊後軍行過剡中山水謹上太尉','劉長卿','唐','唐诗','tang','','[]','剡路除荆棘，王師罷鼓鼙。',72,'全唐诗/poet.tang.7000.json','["剡路除荆棘，王師罷鼓鼙。", "農歸滄海畔，圍解赤城西。", "赦罪春陽發，收兵太白低。", "遠峰來馬首，橫笛入猨啼。", "蘭渚催新幄，桃源識故蹊。", "已聞開閣待，誰許臥東溪。"]'),
('18bbdbb6-a942-4c8e-9707-7e082ffa1ef4','送鄭十二還廬山別業','劉長卿','唐','唐诗','tang','','["\u5e90\u5c71"]','潯陽數畝宅，歸臥掩柴關。',72,'全唐诗/poet.tang.7000.json','["潯陽數畝宅，歸臥掩柴關。", "谷口何人待，門前秋草閑。", "忘機賣藥罷，無語杖藜還。", "舊筍成寒竹，空齋向暮山。", "水流經舍下，雲去到人間。", "桂樹花應發，因行寄一攀。"]'),
('ed2b57e5-df5b-4602-9c97-e0b5b5b8b50d','至饒州尋陶十七不在寄贈','劉長卿','唐','唐诗','tang','','[]','謫宦投東道，逢君已北轅。',72,'全唐诗/poet.tang.7000.json','["謫宦投東道，逢君已北轅。", "孤蓬向何處，五柳不開門。", "去國空迴首，懷賢欲訴冤。", "梅枝橫嶺嶠，竹路過湘源。", "月下高秋雁，天南獨夜猨。", "離心與流水，萬里共朝昏。"]'),
('6e1e7be0-dc30-450d-bca7-69234e85b2d4','奉陪鄭中丞自宣州解印與諸姪宴餘干後溪','劉長卿','唐','唐诗','tang','','[]','跡遠親魚鳥，功成厭鼓鼙。',72,'全唐诗/poet.tang.7000.json','["跡遠親魚鳥，功成厭鼓鼙。", "林中阮生集，池上謝公題。", "戶牖垂藤合，藩離插槿齊。", "夕陽山向背，春草水東西。", "度雨諸峰出，看花幾路迷。", "何勞問秦漢，更入武陵溪。"]'),
('5615ec93-8265-4b7c-9d3d-058e76c99566','同諸公袁郎中宴筵喜加章服','劉長卿','唐','唐诗','tang','','[]','手詔來筵上，腰金向粉闈。',72,'全唐诗/poet.tang.7000.json','["手詔來筵上，腰金向粉闈。", "勳名傳舊閣，蹈舞著新衣。", "白社同遊在，滄洲此會稀。", "寒笳發後殿，秋草送西歸。", "世難常摧敵，時閑已息機。", "魯連功可讓，千載一相揮。"]'),
('d1a1e17f-6619-4f7d-9831-afe9c8e601ca','毘陵送鄒結先赴河南充判官','劉長卿','唐','唐诗','tang','','[]','王事相逢少，雲山奈別何。',72,'全唐诗/poet.tang.7000.json','["王事相逢少，雲山奈別何。", "芳年臨水怨，瓜步上潮過。", "客路方經楚，鄉心共渡河。", "凋殘春草在，離亂故城多。", "罷戰逢時泰，輕徭佇俗和。", "東西此分手，惆悵恨煙波。"]'),
('2115d608-8d0a-446c-956c-8d310f4ab0f3','送徐大夫赴廣州','劉長卿','唐','唐诗','tang','','[]','上將壇場拜，南荒羽檄招。',72,'全唐诗/poet.tang.7000.json','["上將壇場拜，南荒羽檄招。", "遠人來百越，元老事三朝。", "霧繞龍山暗，山連象郡遙。", "路分江淼淼，軍動馬蕭蕭。", "畫角知秋氣，樓船逐暮潮。", "當令輸貢賦，不使外夷驕。"]'),
('81147d62-8132-4987-a4fc-6eab94d46d02','九日題蔡國公主樓','劉長卿','唐','唐诗','tang','','[]','主第人何在，重陽客暫尋。',72,'全唐诗/poet.tang.7000.json','["主第人何在，重陽客暫尋。", "水餘龍鏡色，雲罷鳳簫音。", "暗牖藏昏曉，蒼苔換古今。", "晴山卷幔出，秋草閉門深。", "籬菊仍新吐，庭槐尚舊陰。", "年年畫梁燕，來去豈無心。"]'),
('c755dfcb-420c-4ee4-8224-dd1833a6de17','送荀八過山陰舊縣兼寄剡中諸官','劉長卿','唐','唐诗','tang','','[]','訪舊山陰縣，扁舟到海涯。',72,'全唐诗/poet.tang.7000.json','["訪舊山陰縣，扁舟到海涯。", "故林嗟滿歲，春草憶佳期。", "晚景千峰亂，晴江一鳥遲。", "桂香留客處，楓暗泊舟時。", "舊石曹娥篆，空山夏禹祠。", "剡溪多隱吏，君去道相思。"]'),
('756ff877-de47-47d1-a3f9-974f27b18e9d','奉餞元侍郎加豫章採訪兼賜章服','劉長卿','唐','唐诗','tang','','[]','任重兼烏府，時平偃豹韜。',72,'全唐诗/poet.tang.7000.json','["任重兼烏府，時平偃豹韜。", "澄清湘水變，分別楚山高。", "花對彤襜發，霜和白雪操。", "黃金裝舊馬，青草換新袍。", "嶺暗猿啼月，江寒鷺映濤。", "豫章生宇下，無使翳篷蒿。"]'),
('f36b70a5-b185-47b6-a39b-07f8878f2053','奉餞郎中四兄罷餘杭太守承恩加侍御史充行軍司馬赴汝南行營','劉長卿','唐','唐诗','tang','','[]','星使三江上，天波萬里通。',72,'全唐诗/poet.tang.7000.json','["星使三江上，天波萬里通。", "權分金節重，恩借鐵冠雄。", "梅吹前軍發，棠陰舊府空。", "殘春錦障外，初日羽旗東。", "岸柳遮浮鷁，江花隔避驄。", "離心在何處，芳草滿吳宮。"]'),
('4c26804e-1725-4922-a485-5574f6c0dbfb','送賈侍御克復後入京','劉長卿','唐','唐诗','tang','','[]','對酒心不樂，見君動行舟。',72,'全唐诗/poet.tang.7000.json','["對酒心不樂，見君動行舟。", "回看暮帆隱，獨向空江愁。", "晴雲淡初夜，春塘深慢流。", "溫顏風霜霽，喜氣煙塵收。", "馳馹數千里，朝天十二樓。", "因之報親愛，白髮生滄洲。"]'),
('3b610632-ac8e-401c-9c68-625ddb8e1667','會稽王處士草堂壁畫衡霍諸山','劉長卿','唐','唐诗','tang','','[]','粉壁衡霍近，羣峰如可攀。',72,'全唐诗/poet.tang.7000.json','["粉壁衡霍近，羣峰如可攀。", "能令堂上客，見盡湖南山。", "青翠數千仞，飛來方丈間。", "歸雲無處滅，去鳥何時還？", "勝事日相對，主人常獨閑。", "稍看林壑晚，佳氣生重關。"]'),
('85b682be-71a3-4a8a-abbe-bd5934ae549e','惠福寺與陳留諸官茶會','劉長卿','唐','唐诗','tang','','[]','到此機事遣，自嫌塵網迷。',72,'全唐诗/poet.tang.7000.json','["到此機事遣，自嫌塵網迷。", "因知萬法幻，盡與浮雲齊。", "疎竹映高枕，空花隨杖藜。", "香飄諸天外，日隱雙林西。", "傲吏方見狎，真僧幸相攜。", "能令歸客意，不復還東溪。"]'),
('ad6524b0-eae7-4fdf-8129-bc88194abc5c','金陵西泊舟臨江樓','劉長卿','唐','唐诗','tang','','[]','蕭條金陵郭，舊是帝王州。',72,'全唐诗/poet.tang.7000.json','["蕭條金陵郭，舊是帝王州。", "日暮望鄉處，雲邊江樹秋。", "楚雲不可託，楚水只堪愁。", "行客千萬里，滄波朝暮流。", "迢迢洛陽夢，獨臥清川樓。", "異鄉共如此，孤帆難久遊。"]'),
('29c0368f-acb9-49d1-ba9f-e9ee5f3c8254','題靈祐上人法華院木蘭花','劉長卿','唐','唐诗','tang','','[]','庭種南中樹，年華幾度新。',72,'全唐诗/poet.tang.7000.json','["庭種南中樹，年華幾度新。", "已依初地長，獨發舊園春。", "映日成華蓋，搖風散錦茵。", "色空榮落處，香醉往來人。", "菡萏千燈遍，芳菲一雨均。", "高柯儻爲檝，渡海有良因。"]'),
('8a7fb5d2-8d09-4129-a8b8-0aac8c405aba','宿嚴維宅送包佶','劉長卿','唐','唐诗','tang','','[]','江湖同避地，分首自依依。',72,'全唐诗/poet.tang.7000.json','["江湖同避地，分首自依依。", "盡室今爲客，驚秋空念歸。", "歲儲無別墅，寒服羨鄰機。", "草色春橋晚，蟬聲江樹稀。", "夜深宜共醉，時難忍相違。", "何事隨陽雁，汀洲忽背飛。"]'),
('965d3eb4-7c68-405d-b216-42945066d7d8','送從弟貶袁州','劉長卿','唐','唐诗','tang','','[]','何事成遷客，思歸不見鄉。',72,'全唐诗/poet.tang.7000.json','["何事成遷客，思歸不見鄉。", "遊吳經萬里，弔屈向三湘。", "水與荆巫接，山通鄢郢長。", "名羞黃綬繫，身是白眉郎。", "獨結南枝恨，應思北雁行。", "憂來沽楚酒，老鬢莫凝霜。"]'),
('43e0f03e-a137-4285-ad9b-a50dad4ecb79','無錫東郭送友人遊越','劉長卿','唐','唐诗','tang','','[]','客路風霜曉，郊原春興餘。',72,'全唐诗/poet.tang.7000.json','["客路風霜曉，郊原春興餘。", "平蕪不可望，遊子去何如。", "煙水乘湖闊，雲山適越初。", "舊都懷作賦，古穴覓藏書。", "碑缺曹娥宅，林荒逸少居。", "江湖無限意，非獨爲樵漁。"]'),
('762e2c1d-e5d5-47e3-8167-71fd4c0c8d6b','送邵州判官往南','劉長卿','唐','唐诗','tang','','[]','看君發原隰，駟牡志皇皇。',72,'全唐诗/poet.tang.7000.json','["看君發原隰，駟牡志皇皇。", "始罷滄江令，還隨粉署郎。", "海沂軍未息，河兗歲仍荒。", "征稅人全少，榛蕪虜近亡。", "新知行宋遠，相望隔淮長。", "早晚裁書寄，銀鉤佇八行。"]'),
('2fd4d784-6ea3-4707-9a65-719ddbfeed65','出豐縣界寄韓明府','劉長卿','唐','唐诗','tang','','[]','迴首古原上，未能辭舊鄉。',72,'全唐诗/poet.tang.7000.json','["迴首古原上，未能辭舊鄉。", "西風收暮雨，隱隱分芒碭。", "賢友此爲邑，令名滿徐方。", "音容想在眼，暫若升琴堂。", "疲馬顧春草，行人看夕陽。", "自非傳尺素，誰爲論中腸。"]'),
('7cb49e2e-45c9-49d3-8ef0-dbded948d362','別陳留諸官','劉長卿','唐','唐诗','tang','','[]','戀此東道主，能令西上遲。',72,'全唐诗/poet.tang.7000.json','["戀此東道主，能令西上遲。", "徘徊暮郊別，惆悵秋風時。", "上國邈千里，夷門難再期。", "行人望落日，歸馬嘶空陂。", "不愧寶刀贈，維懷瓊樹枝。", "音塵倘未接，夢寐徒相思。"]'),
('feed1bff-0872-43b5-9ae2-8611dbe59db7','觀李湊所畫美人障子','劉長卿','唐','唐诗','tang','','[]','愛爾含天姿，丹青有殊智。',104,'全唐诗/poet.tang.7000.json','["愛爾含天姿，丹青有殊智。", "無間已得象，象外更生意。", "西子不可見，千載無重還。", "空令浣沙態，猶在含毫間。", "一笑豈易得，雙蛾如有情。", "窗風不舉袖，但覺羅衣輕。", "華堂翠幕春風來，內閣金屏曙色開。", "此中一見亂人目，只疑行到雲陽臺。"]'),
('96bd1f67-43ad-44b6-9030-deb2eddedf99','送史判官奏事之靈武兼寄巴西親故','劉長卿','唐','唐诗','tang','','[]','中州日紛梗，天地何時泰。',72,'全唐诗/poet.tang.7000.json','["中州日紛梗，天地何時泰。", "獨有西歸心，遙懸夕陽外。", "故人奉章奏，此去論利害。", "陽雁南渡江，征驂去相背。", "因君欲寄遠，何處問親愛。", "空使滄洲人，相思減衣帶。"]'),
('8a7b52ec-6cea-46b5-a1e1-6ad7eda7ab2b','自鄱陽還道中寄褚徵君','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','南風日夜起，萬里孤帆漾。',72,'全唐诗/poet.tang.7000.json','["南風日夜起，萬里孤帆漾。", "元氣連洞庭，夕陽落波上。", "故人煙水隔，復此遙相望。", "江信久寂寥，楚雲獨惆悵。", "愛君清川口，弄月時櫂唱。", "白首無子孫，一生自疎曠。"]'),
('e3238941-e181-4685-a0d0-c8d55bd5f4dd','石梁湖有寄','劉長卿','唐','唐诗','tang','','[]','故人千里道，滄波一年別。',72,'全唐诗/poet.tang.7000.json','["故人千里道，滄波一年別。", "夜上明月樓，相思楚天闊。", "瀟瀟清秋暮，嫋嫋涼風發。", "湖色淡不流，沙鷗遠還滅。", "煙波日已遠，音問日已絕。", "歲晏空含情，江臯綠芳歇。"]'),
('6f723e68-0ccf-4eea-a9ca-496d17a7449a','送沈少府之任淮南','劉長卿','唐','唐诗','tang','','[]','惜君滯南楚，枳棘徒棲鳳。',72,'全唐诗/poet.tang.7000.json','["惜君滯南楚，枳棘徒棲鳳。", "獨與千里帆，春風遠相送。", "此行山水好，時物亦應衆。", "一鳥飛長淮，百花滿雲夢。", "相期丹霄路，遙聽清風頌。", "勿爲州縣卑，時來自爲用。"]'),
('8859c9be-c859-4a10-972d-b278cb053731','嚴子瀨東送馬處直歸蘇','劉長卿','唐','唐诗','tang','','[]','望君舟已遠，落日潮未退。',72,'全唐诗/poet.tang.7000.json','["望君舟已遠，落日潮未退。", "目送滄海帆，人行白雲外。", "江中遠回首，波上生微靄。", "秋色姑蘇臺，寒流子陵瀨。", "相送苦易散，動別知難會。", "從此日相思，空令減衣帶。"]'),
('15a02240-9c03-4376-87ae-a8388a668b0a','宿懷仁縣南湖寄東海荀處士','劉長卿','唐','唐诗','tang','','[]','向夕歛微雨，晴開湖上天。',84,'全唐诗/poet.tang.7000.json','["向夕歛微雨，晴開湖上天。", "離人正惆悵，新月愁嬋娟。", "佇立白沙曲，相思滄海邊。", "浮雲自來去，此意誰能傳。", "一水不相見，千峰隨客船。", "寒塘起孤雁，夜色分鹽田。", "時復一延首，憶君如眼前。"]'),
('21a572f5-8e1d-4ab2-9c3f-40e3a242361f','初至洞庭懷灞陵別業','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','長安邈千里，日夕懷雙闕。',84,'全唐诗/poet.tang.7000.json','["長安邈千里，日夕懷雙闕。", "已是洞庭人，猶看灞陵月。", "誰堪去鄉意，親戚想天末。", "昨夜夢中歸，煙波覺來闊。", "江臯見芳草，孤客心欲絕。", "豈訝青春來，但傷經時別。", "長天不可望，鳥與浮雲沒。"]'),
('333eb65d-8cbb-4c46-9a58-0b58c8fa4ae3','題蕭郎中開元寺新構幽寂亭','劉長卿','唐','唐诗','tang','','[]','康樂愛山水，賞心千載同。',96,'全唐诗/poet.tang.7000.json','["康樂愛山水，賞心千載同。", "結茅依翠微，伐木開蒙籠。", "孤峰倚青霄，一徑去不窮。", "候客石苔上，禮僧雲樹中。", "曠然見滄洲，自遠來清風。", "五馬留谷口，雙旌薄煙虹。", "沈沈衆香積，眇眇諸天空。", "獨往應未遂，蒼生思謝公。"]'),
('79df0612-509b-4015-a637-b90d251ec8a1','同姜濬題裴式微餘干東齋','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','世事終成夢，生涯欲半過。',96,'全唐诗/poet.tang.7000.json','["世事終成夢，生涯欲半過。", "白雲心已矣，滄海意如何。", "藜杖全吾道，榴花養太和。", "春風騎馬醉，江月釣魚歌。", "散帙看蟲蠹，開門見雀羅。", "遠山終日在，芳草傍人多。", "吏體莊生傲，方言楚俗譌。", "屈平君莫弔，腸斷洞庭波。"]'),
('9a26dd3e-7589-4820-bff3-8aaf2211eb22','贈元容州','劉長卿','唐','唐诗','tang','','[]','擁旌臨合浦，上印臥長沙。',96,'全唐诗/poet.tang.7000.json','["擁旌臨合浦，上印臥長沙。", "海徼長無戍，湘山獨種畬。", "政傳通歲貢，才惜過年華。", "萬里依孤劒，千峰寄一家。", "累徵期旦暮，未起戀煙霞。", "避世歌芝草，休官醉菊花。", "舊遊如夢裏，此別是天涯。", "何事滄波上，漂漂逐海槎。"]'),
('3e1771e6-2fa1-4a25-9401-08e68b560584','夏口送長寧楊明府歸荆南因寄幕府諸公','劉長卿','唐','唐诗','tang','','[]','關西楊太尉，千載德猶聞。',96,'全唐诗/poet.tang.7000.json','["關西楊太尉，千載德猶聞。", "白日俱終老，清風獨至君。", "身承遠祖遺，才出衆人羣。", "舉世貪荆玉，全家戀楚雲。", "向煙帆杳杳，臨水葉紛紛。", "草覆昭丘綠，江從夏口分。", "高名光盛府，異姓寵殊勳。", "百越今無事，南征欲罷軍。"]'),
('d55a0755-ce84-4d96-8197-b445e2f84c9b','奉和杜相公新移長興宅呈元相公','劉長卿','唐','唐诗','tang','','[]','間世生賢宰，同心奉至尊。',96,'全唐诗/poet.tang.7000.json','["間世生賢宰，同心奉至尊。", "功高開北第，機靜灌中園。", "入並蟬冠影，歸分騎士喧。", "窗聞漢宮漏，家識杜陵源。", "獻替常焚藁，優閑獨對萱。", "花香逐荀令，草色對王孫。", "有地先開閣，何人不掃門。", "江湖難自退，明主託元元。"]'),
('581e5a92-6e7f-4d27-9242-221681598fb0','湖南使還留辭辛大夫','劉長卿','唐','唐诗','tang','','[]','王師勞近甸，兵食仰諸侯。',96,'全唐诗/poet.tang.7000.json','["王師勞近甸，兵食仰諸侯。", "天子無南顧，元勳在上遊。", "大才生間氣，盛業拯橫流。", "風景隨搖筆，山川入運籌。", "羽觴交餞席，旄節對歸舟。", "鶯識春深恨，猿知日去愁。", "別離花寂寂，南北水悠悠。", "唯有家兼國，終身共所憂。"]'),
('b3d148a1-fc57-488e-8318-1eb3a1f50c2e','泛曲阿後湖簡同遊諸公','劉長卿','唐','唐诗','tang','','[]','元氣浮積水，沈沈深不流。',96,'全唐诗/poet.tang.7000.json','["元氣浮積水，沈沈深不流。", "春風萬頃綠，映帶至徐州。", "爲客難適意，逢君方暫遊。", "夤緣白蘋際，日暮滄浪舟。", "渡口微月進，林西殘雨收。", "水雲去仍濕，沙鶴鳴相留。", "且習子陵隱，能忘生事憂。", "此中深有意，非爲釣魚鉤。"]'),
('b0d40264-2d5b-4a14-b518-6beb6dc15438','北遊酬孟雲卿見寄','劉長卿','唐','唐诗','tang','','[]','忽忽忘前事，事願能相乖。',84,'全唐诗/poet.tang.7000.json','["忽忽忘前事，事願能相乖。", "衣馬日羸弊，誰辨行與才。", "善道居貧賤，潔服蒙塵埃。", "行行無定止，懔坎難歸來。", "慈母憂疾疹，室家念棲萊。", "幸君夙姻親，深見中外懷。", "俟子惜時節，悵望臨高臺。"]'),
('fac64e67-75fa-4d31-a82a-b3dbe87b96f0','冬夜宿揚州開元寺烈公房送李侍御之江東','劉長卿','唐','唐诗','tang','','[]','遷客投百越，窮陰淮海凝。',96,'全唐诗/poet.tang.7000.json','["遷客投百越，窮陰淮海凝。", "中原馳困獸，萬里棲飢鷹。", "寂寂連宇下，愛君心自弘。", "空堂來霜氣，永夜清明燈。", "發後望煙水，相思勞寢興。", "暮帆背楚郭，江色浮金陵。", "此去爾何恨，近名予未能。", "爐峰若便道，爲訪東林僧。"]'),
('34e1a717-4fd7-4a11-9387-58975a95a8c8','南楚懷古','劉長卿','唐','唐诗','tang','','[]','南國久蕪沒，我來空鬱陶。',96,'全唐诗/poet.tang.7000.json','["南國久蕪沒，我來空鬱陶。", "君看章華宮，處處生蓬蒿。", "但見陵與谷，豈知賢與豪。", "精魂托古木，寶劒捐江臯。", "倚棹下晴景，回舟隨晚濤。", "碧雲暮寥落，湖上秋天高。", "往事那堪問，此心徒自勞。", "獨餘湘水上，千載聞離騷。"]'),
('d9177966-be32-4fa1-a3a8-c23ae2428007','上湖田館南樓憶朱晏','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','漂泊日復日，洞庭今更秋。',96,'全唐诗/poet.tang.7000.json','["漂泊日復日，洞庭今更秋。", "白雲如有意，萬里望孤舟。", "何事愛成別，空令登此樓。", "天光映波動，月影隨江流。", "鶴唳靜寒渚，猿啼深夜洲。", "歸期誠已促，清景仍相留。", "頃者慕獨往，爾來悲遠遊。", "風波自此去，桂水空離憂。"]'),
('7d4b0d05-1f92-4127-9608-6aedbc76ca36','送姚八之句容舊任便歸江南','劉長卿','唐','唐诗','tang','','[]','故人還水國，春色動離憂。',96,'全唐诗/poet.tang.7000.json','["故人還水國，春色動離憂。", "碧草千萬里，滄江朝暮流。", "桃花迷舊路，萍葉蕩歸舟。", "遠戍看京口，空城問石頭。", "折芳佳麗地，望月西南樓。", "猨鳥共孤嶼，煙波連數州。", "誰家過楚老，何處戀江鷗。", "尺素能相報，湖山若箇憂。"]'),
('53d6d62c-51e2-44b1-9ed1-220166a69e32','睢陽贈李司倉','劉長卿','唐','唐诗','tang','','[]','白露變時候，蛬聲暮啾啾。',96,'全唐诗/poet.tang.7000.json','["白露變時候，蛬聲暮啾啾。", "飄飄洛陽客，惆悵梁園秋。", "只爲乏生計，爾來成遠遊。", "一身不家食，萬事從人求。", "且喜接餘論，足堪資小留。", "寒城落日後，砧杵令人愁。", "歸路歲時盡，長河朝夕流。", "非君深意願，誰復能相憂。"]'),
('2325ad26-e0cc-4561-9fa5-727b4810b9b6','杪秋洞庭中懷亡道士謝太虛','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','漂泊日復日，洞庭今更秋。',96,'全唐诗/poet.tang.7000.json','["漂泊日復日，洞庭今更秋。", "青楓亦何意，此夜催人愁。", "惆悵客中月，徘徊江上樓。", "心知楚天遠，目送滄波流。", "羽客久已歿，微言無處求。", "空餘白雲在，容與隨孤舟。", "千里杳難望，一身當獨遊。", "故園復何許，江海徒遲留。"]'),
('1f1d811b-6040-4de8-9a10-003b056d3e0d','同郭參謀詠崔僕射淮南節度使廳前竹','劉長卿','唐','唐诗','tang','','[]','昔種梁王苑，今移漢將壇。',96,'全唐诗/poet.tang.7000.json','["昔種梁王苑，今移漢將壇。", "蒙籠低冕過，青翠捲簾看。", "得地移根遠，經霜抱節難。", "開花成鳳實，嫩笋長魚竿。", "藹藹軍容靜，蕭蕭郡宇寬。", "細音和角暮，疎影上門寒。", "湘浦何年變，山陽幾處殘。", "不知軒屏側，歲晚對袁安。"]'),
('5ebe4220-8778-4f86-9a6d-f91e1feb0ae5','硤石遇雨宴前主簿從兄子英宅','劉長卿','唐','唐诗','tang','','[]','縣城蒼翠裏，客路兩崖開。',96,'全唐诗/poet.tang.7000.json','["縣城蒼翠裏，客路兩崖開。", "硤石雲漠漠，東風吹雨來。", "吾兄此爲吏，薄宦知無媒。", "方寸抱秦鏡，聲名傳楚材。", "折腰五斗間，僶俛隨塵埃。", "秩滿少餘俸，家貧仍散財。", "誰言次東道，暫預傾金罍。", "雖欲少留此，其如歸限催。"]'),
('b2091c2c-9169-4ce2-a2e5-7115bde0e5c2','江中晚釣寄荆南一二相識','劉長卿','唐','唐诗','tang','','[]','楚郭微雨收，荆門遙在目。',96,'全唐诗/poet.tang.7000.json','["楚郭微雨收，荆門遙在目。", "漾舟水雲裏，日暮春江綠。", "霽華靜洲渚，暝色連松竹。", "月出波上時，人歸渡頭宿。", "一身已無累，萬事更何欲。", "漁父自夷猶，白鷗不羈束。", "既憐滄浪水，復愛滄浪曲。", "不見眼中人，相思心斷續。"]'),
('41c095de-597d-4cb0-8daf-cebb1ef9f366','九日岳陽待黃遂張渙','劉長卿','唐','唐诗','tang','','[]','別君頗已久，離念與時積。',96,'全唐诗/poet.tang.7000.json','["別君頗已久，離念與時積。", "楚水空浮煙，江樓望歸客。", "徘徊正佇想，髣髴如暫覿。", "心目徒自親，風波尚相隔。", "青林泊舟處，猿鳥愁孤驛。", "遙見郭外山，蒼然雨中夕。", "季鷹久疎曠，叔度早疇昔。", "反櫂來何遲，黃花候君摘。"]'),
('82499be7-6c67-4df7-9a88-67841e562923','題王少府堯山隱處簡陸鄱陽','劉長卿','唐','唐诗','tang','','[]','故人滄洲吏，深與世情薄。',96,'全唐诗/poet.tang.7000.json','["故人滄洲吏，深與世情薄。", "解印二十年，委身在丘壑。", "買田楚山下，妻子自耕鑿。", "羣動心有營，孤雲本無著。", "因收谿上釣，遂接林中酌。", "對酒春日長，山村杏花落。", "陸生鄱陽令，獨步建溪作。", "早晚休此官，隨君永棲託。"]'),
('ff91b9df-5052-4dd5-866d-7347e1b1dc25','晚次湖口有懷','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','靄然空水合，目極平江暮。',96,'全唐诗/poet.tang.7000.json','["靄然空水合，目極平江暮。", "南望天無涯，孤帆落何處。", "頃爲衡湘客，頗見湖山趣。", "朝氣和楚雲，夕陽映江樹。", "帝鄉勞想望，萬里心來去。", "白髮生扁舟，滄波滿歸路。", "秋風今已至，日夜雁南度。", "木葉辭洞庭，紛紛落無數。"]'),
('4c0ed9d1-f147-4faa-af0e-a226dbf5d25d','陪元侍御遊支硎山寺','劉長卿','唐','唐诗','tang','','[]','支公去已久，寂寞龍華會。',96,'全唐诗/poet.tang.7000.json','["支公去已久，寂寞龍華會。", "古木閉空山，蒼然暮相對。", "林巒非一狀，水石有餘態。", "密竹藏晦明，羣峰爭向背。", "峰峰帶落日，步步入青靄。", "香氣空翠中，猿聲暮雲外。", "留連南臺客，想像西方內。", "因逐溪水還，觀心兩無礙。"]'),
('64352fb2-31b1-424e-ad57-d1314e0f5b65','桂陽西州晚泊古橋村住人','劉長卿','唐','唐诗','tang','','[]','洛陽別離久，江上心可得。',96,'全唐诗/poet.tang.7000.json','["洛陽別離久，江上心可得。", "惆悵增暮情，瀟湘復秋色。", "故山隔何處，落日羨歸翼。", "滄海空自流，白鷗不相識。", "悲蛬滿荆渚，輟櫂徒沾臆。", "行客念寒衣，主人愁夜織。", "帝鄉片雲去，遙寄千里憶。", "南路隨天長，征帆杳無極。"]'),
('d272f191-11c7-4df6-8cfd-2836b2bac9af','夕次檐石湖夢洛陽親故','劉長卿','唐','唐诗','tang','','[]','天涯望不盡，日暮愁獨去。',96,'全唐诗/poet.tang.7000.json','["天涯望不盡，日暮愁獨去。", "萬里雲海空，孤帆向何處。", "寄身煙波裏，頗得湖山趣。", "江氣和楚雲，秋聲亂楓樹。", "如何異鄉縣，日復懷親故。", "遙與洛陽人，相逢夢中路。", "不堪明月裏，更值清秋暮。", "倚棹對滄波，歸心共誰語。"]'),
('0564dcc9-d5cc-4be0-a392-23d05ff966db','按覆後歸睦州贈苗侍御','劉長卿','唐','唐诗','tang','','["\u957f\u6c5f"]','地遠心難達，天高謗易成。',120,'全唐诗/poet.tang.7000.json','["地遠心難達，天高謗易成。", "羊腸留覆轍，虎口脫餘生。", "直氏偷金枉，于家決獄明。", "一言知己重，片議殺身輕。", "日下人誰憶，天涯客獨行。", "年光銷蹇步，秋氣入衰情。", "建德知何在，長江問去程。", "孤舟百口渡，萬里一猿聲。", "落日開鄉路，空山向郡城。", "豈令冤氣積，千古在長平。"]'),
('a4d9d6ad-f1c1-465c-b962-97dd9d5c12a2','奉寄婺州李使君舍人','劉長卿','唐','唐诗','tang','','[]','建隼罷鳴珂，初傳來暮歌。',120,'全唐诗/poet.tang.7000.json','["建隼罷鳴珂，初傳來暮歌。", "漁樵識太古，草樹得陽和。", "東道諸生從，南依遠客過。", "天清婺女出，土厚絳人多。", "永日空相望，流年復幾何。", "崖開當夕照，葉去逐寒波。", "眼暗經難受，身閑劒懶磨。", "似鴞占賈誼，上馬試廉頗。", "窮分安藜藿，衰容勝薜蘿。", "只應隨越鳥，南翥託高柯。"]'),
('ea7c9ab6-c8a8-44d4-885e-43794ae25c84','哭魏兼遂','劉長卿','唐','唐诗','tang','','[]','古今俱此去，脩短竟誰分。',120,'全唐诗/poet.tang.7000.json','["古今俱此去，脩短竟誰分。", "樽酒空如在，絃琴肯重聞。", "一門同逝水，萬事共浮雲。", "舊館何人宅，空山遠客墳。", "艱危貧且共，少小秀而文。", "獨行依窮巷，全身出亂軍。", "歲時長寂寞，煙月自氛氳。", "壠樹隨人古，山門對日曛。", "汎舟悲向子，留劒贈徐君。", "來去雲陽路，傷心江水濆。"]'),
('ad81d121-40b2-4357-9bfa-f9ef47011a8b','負謫後登干越亭作','劉長卿','唐','唐诗','tang','','[]','天南愁望絕，亭上柳條新。',120,'全唐诗/poet.tang.7000.json','["天南愁望絕，亭上柳條新。", "落日獨歸鳥，孤舟何處人。", "生涯投越徼，世業陷胡塵。", "杳杳鍾陵暮，悠悠鄱水春。", "秦臺悲白首，楚澤怨青蘋。", "草色迷征路，鶯聲傷逐臣。", "獨醒空取笑，直道不容身。", "得罪風霜苦，全生天地仁。", "青山數行淚，滄海一窮鱗。", "牢落機心盡，惟憐鷗鳥親。"]'),
('b49d8c48-7218-4967-a374-99f2d5d14c4a','留題李明府霅溪水堂','劉長卿','唐','唐诗','tang','','[]','寥寥此堂上，幽意復誰論。',120,'全唐诗/poet.tang.7000.json','["寥寥此堂上，幽意復誰論。", "落日無王事，青山在縣門。", "雲峰向高枕，漁釣入前軒。", "晚竹疎簾影，春苔雙履痕。", "荷香隨坐臥，湖色映晨昏。", "虛牖閑生白，鳴琴靜對言。", "暮禽飛上下，春水帶清渾。", "遠岸誰家柳，孤煙何處村。", "謫居投瘴癘，離思過湘沅。", "從此扁舟去，誰堪江浦猿。"]'),
('4ee445ea-eb05-4596-a1b8-8696b375c996','入白沙渚夤緣二十五里至石窟山下懷天台陸山人','劉長卿','唐','唐诗','tang','','[]','遠嶼靄將夕，玩幽行自遲。',120,'全唐诗/poet.tang.7000.json','["遠嶼靄將夕，玩幽行自遲。", "歸人不計日，流水閑相隨。", "輟棹古崖口，捫蘿春景遲。", "偶因回舟次，寧與前山期。", "對此瑤草色，懷君瓊樹枝。", "浮雲去寂寞，白鳥相因依。", "何事愛高隱，但令勞遠思。", "窮年臥海嶠，永望愁天涯。", "吾亦從此去，扁舟何所之？", "迢迢江上帆，千里東風吹。"]'),
('5ff9ef45-3d60-4c80-93a5-7e864d21ef46','禪智寺上方懷演和尚寺即和尚所創','劉長卿','唐','唐诗','tang','','[]','絕巘東林寺，高僧惠遠公。',120,'全唐诗/poet.tang.7000.json','["絕巘東林寺，高僧惠遠公。", "買園隋苑下，持鉢楚城中。", "斗極千燈近，煙波萬井通。", "遠山低月殿，寒木露花宮。", "紺宇焚香淨，滄州擺霧空。", "鴈來秋色裏，曙起早潮東。", "飛錫今何在？蒼生待發蒙。", "白雲翻送客，庭樹自辭風。", "捨筏追開士，迴舟狎釣翁。", "平生江海意，惟共白鷗同。"]'),
('5a8e3904-a09e-44fc-aa52-bda8fba8172a','賈侍郎自會稽使迴篇什盈卷兼蒙見寄一首與余有挂冠之期因書數事率成十韻','劉長卿','唐','唐诗','tang','','[]','江上逢星使，南來自會稽。',120,'全唐诗/poet.tang.7000.json','["江上逢星使，南來自會稽。", "驚年一葉落，按俗五花嘶。", "上國悲蕪梗，中原動鼓鼙。", "報恩看鐵劒，銜命出金閨。", "風物催歸緒，雲峰發詠題。", "天長百越外，潮上小江西。", "鳥道通閩嶺，山光落剡溪。", "暮帆千里思，秋夜一猨啼。", "柏樹榮新壠，桃源憶故蹊。", "若能爲休去，行復草萋萋。"]'),
('412c2a12-0b17-4b10-95f1-0bfb7501177c','秋日夏口涉漢陽獻李相公','劉長卿','唐','唐诗','tang','','[]','日望衡門處，心知漢水濆。',120,'全唐诗/poet.tang.7000.json','["日望衡門處，心知漢水濆。", "偶乘青雀舫，還在白鷗羣。", "間氣生靈秀，先朝翼戴勳。", "藏弓身已退，焚藳事難聞。", "舊業成青草，全家寄白雲。", "松蘿長稚子，風景逐新文。", "山帶寒城出，江依古岸分。", "楚歌悲遠客，羌笛怨孤軍。", "鼎罷調梅久，門看種藥勤。", "十年猶去國，黃葉又紛紛。"]'),
('fe6e4e09-99ef-47c8-8152-f6f7d45a911b','歸沛縣道中晚泊留侯城','劉長卿','唐','唐诗','tang','','[]','訪古此城下，子房安在哉？',120,'全唐诗/poet.tang.7000.json','["訪古此城下，子房安在哉？", "白雲去不反，危堞空崔嵬。", "伊昔楚漢時，頗聞經濟才。", "運籌風塵下，能使天地開。", "蔓草日已積，長松日已摧。", "功名滿青史，祠廟唯蒼苔。", "百里暮程遠，孤舟川上迴。", "進帆東風便，轉岸前山來。", "楚水澹相引，沙鷗閑不猜。", "扣舷從此去，延首仍裴回。"]'),
('efecfa49-79d0-4bcf-86f1-a8d92dce1490','關門望華山','劉長卿','唐','唐诗','tang','','[]','客路瞻太華，三峰高際天。',120,'全唐诗/poet.tang.7000.json','["客路瞻太華，三峰高際天。", "夏雲亙百里，合沓遙相連。", "雷雨飛半腹，太陽在其巔。", "翠微關上近，瀑布林梢懸。", "愛此衆容秀，能令西望偏。", "徘徊忘暝色，泱漭成陰煙。", "會是朝百靈，亦聞會羣仙。", "瓊漿豈易挹，毛女非空傳。", "髣髴仍佇想，幽期如眼前。", "金天有青廟，松柏隱蒼然。"]'),
('80ebc42f-71a1-42be-b0c8-af50686a15a2','奉陪蕭使君入鮑達洞尋靈山寺','劉長卿','唐','唐诗','tang','','[]','山居秋更鮮，秋江相映碧。',120,'全唐诗/poet.tang.7000.json','["山居秋更鮮，秋江相映碧。", "獨臨滄洲路，如待挂帆客。", "遂使康樂侯，披榛著雙屐。", "入雲開嶺道，永日尋泉脈。", "古寺隱青冥，空中寒磬夕。", "蒼苔絕行徑，飛鳥無去跡。", "樹杪下歸人，水聲過幽石。", "任情趣逾遠，移步奇屢易。", "蘿木靜蒙蒙，風煙深寂寂。", "徘徊未能去，畏共桃源隔。"]'),
('3f98875c-1e9e-4396-92a1-58c6b3e64934','孫權故城下懷古兼送友人歸建業','劉長卿','唐','唐诗','tang','','["\u957f\u6c5f"]','雄圖爭割據，神器終不守。',120,'全唐诗/poet.tang.7000.json','["雄圖爭割據，神器終不守。", "上下武昌城，長江竟何有。", "古來壯臺榭，事往悲陵阜。", "寥落幾家人，猶依數株柳。", "威靈絕想像，蕪沒空林藪。", "野徑春草中，郊扉夕陽後。", "逢君從此去，背楚方東走。", "煙際指金陵，潮時過湓口。", "行人已何在，臨水徒揮手。", "惆悵不能歸，孤帆沒雲久。"]'),
('9d3ef9c7-dd5a-4a5b-ad56-0f0b5d60e40f','宿雙峰寺寄盧七李十六','劉長卿','唐','唐诗','tang','','[]','寥寥禪誦處，滿室蟲絲結。',120,'全唐诗/poet.tang.7000.json','["寥寥禪誦處，滿室蟲絲結。", "獨與山中人，無心生復滅。", "徘徊雙峰下，惆悵雙峰月。", "杳杳暮猿深，蒼蒼古松列。", "玩奇不可盡，漸遠更幽絕。", "林暗僧獨歸，石寒泉且咽。", "竹房響輕吹，蘿徑陰餘雪。", "臥澗曉何遲，背巖春未發。", "此遊誠多趣，獨往共誰閱。", "得意空自歸，非君豈能說。"]'),
('12f2bade-8824-489a-a192-903f116c2b53','京口懷洛陽舊居兼寄廣陵二三知己','劉長卿','唐','唐诗','tang','','[]','川闊悲無梁，藹然滄波夕。',120,'全唐诗/poet.tang.7000.json','["川闊悲無梁，藹然滄波夕。", "天涯一飛鳥，日暮南徐客。", "氣混京口雲，潮吞海門石。", "孤帆候風進，夜色帶江白。", "一水阻佳期，相望空脉脉。", "那堪歲芳盡，更使春夢積。", "故國胡塵飛，遠山楚雲隔。", "家人想何在，庭草爲誰碧。", "惆悵空傷情，滄浪有餘跡。", "嚴陵七里灘，攜手同所適。"]'),
('4cbf14a2-39a2-4a43-bb6e-a5b09792363f','登揚州栖靈寺塔','劉長卿','唐','唐诗','tang','','[]','北塔凌空虛，雄觀壓川澤。',120,'全唐诗/poet.tang.7000.json','["北塔凌空虛，雄觀壓川澤。", "亭亭楚雲外，千里看不隔。", "遙對黃金臺，浮輝亂相射。", "盤梯接元氣，半壁棲夜魄。", "稍登諸劫盡，若騁排霄翮。", "向是滄洲人，已爲青雲客。", "雨飛千栱霽，日在萬家夕。", "鳥處高却低，天涯遠如迫。", "江流入空翠，海嶠現微碧。", "向暮期下來，誰堪復行役。"]'),
('83f4d926-2206-4134-a047-88ffedc5e6c2','湖上遇鄭田','劉長卿','唐','唐诗','tang','','[]','故人青雲器，何意常窘迫。',120,'全唐诗/poet.tang.7000.json','["故人青雲器，何意常窘迫。", "三十猶布衣，憐君頭已白。", "誰言此相見，暫得話疇昔。", "舊業今已蕪，還鄉返爲客。", "扁舟伊獨往，斗酒君自適。", "滄洲不可涯，孤帆去無跡。", "杯中忽復醉，湖上生月魄。", "湛湛江色寒，濛濛水雲夕。", "風波易迢遰，千里如咫尺。", "回首人已遙，南看楚天隔。"]'),
('3c74f1d8-75e5-450e-84a2-99ec64b2a36e','雨中登沛縣樓贈表兄郭少府','劉長卿','唐','唐诗','tang','','[]','楚澤秋更遠，雲雷有時作。',120,'全唐诗/poet.tang.7000.json','["楚澤秋更遠，雲雷有時作。", "晚陂帶殘雨，白水昏漠漠。", "佇立收煙氛，洗然靜寥廓。", "卷簾高樓上，萬里看日落。", "爲客頻改弦，辭家尚如昨。", "故山今不見，此鳥那可託。", "小邑務常閑，吾兄宦何薄。", "高標青雲器，獨立滄江鶴。", "惠愛原上情，慇懃丘中諾。", "何當遂良願，歸臥青山郭。"]'),
('5f68a9dc-0b04-4dd7-abe2-0036a2bc2a46','灞東晚晴簡同行薛棄朱訓','劉長卿','唐','唐诗','tang','','[]','客心豁初霽，霽色暝玄灞。',120,'全唐诗/poet.tang.7000.json','["客心豁初霽，霽色暝玄灞。", "西向看夕陽，曈曈映桑柘。", "二賢誠逸足，千里陪征駕。", "古樹枳道傍，人煙杜陵下。", "伊余在羈束，且復隨造化。", "好道當有心，營生苦無暇。", "高賢幸茲偶，英達窮王霸。", "迢遰客王程，裴回主人夜。", "一薫知異質，片玉誰齊價。", "同結丘中緣，塵埃自茲謝。"]'),
('56119c41-80da-44ba-9f29-d65c54bcf8fc','對雨贈濟陰馬少府考城蔣少府兼獻成武五兄南華二兄','劉長卿','唐','唐诗','tang','','[]','繁雲兼家思，彌望連濟北。',120,'全唐诗/poet.tang.7000.json','["繁雲兼家思，彌望連濟北。", "日暮微雨中，州城帶秋色。", "蕭條主人靜，落葉飛不息。", "鄉夢寒更頻，蟲聲夜相逼。", "二賢縱橫器，久滯徒勞職。", "笑語和風騷，雍容事文墨。", "吾兄即時彥，前路良未測。", "秋水百丈清，寒松一枝直。", "此心欲引託，誰爲生羽翼。", "且復頓歸鞍，杯中雪胸臆。"]'),
('9edd5fa0-5202-4d49-9947-bd02db86134f','李侍御河北使回至東京相訪','劉長卿','唐','唐诗','tang','','[]','故人南臺秀，夙擅中朝美。',120,'全唐诗/poet.tang.7000.json','["故人南臺秀，夙擅中朝美。", "擁傳從北來，飛霜日千里。", "貧居幸相訪，顧我柴門裏。", "却訝繡衣人，仍交布衣士。", "王程遽爾迫，別戀從此始。", "濁酒未暇斟，清文頗垂示。", "回瞻驄馬速，但見行塵起。", "日暮汀洲寒，春風渡流水。", "草色官道邊，桃花御溝裏。", "天涯一鳥夕，惆悵知何已。"]'),
('eda78000-f257-4563-ad06-5a6995adcac0','吳中聞潼關失守因奉寄淮南蕭判官','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一鴈飛吳天，羈人傷暮律。',132,'全唐诗/poet.tang.7000.json','["一鴈飛吳天，羈人傷暮律。", "松江風嫋嫋，波上片帆疾。", "木落姑蘇臺，霜收洞庭橘。", "蕭條長洲外，唯見寒山出。", "胡馬嘶秦雲，漢兵亂相失。", "關中因竊據，天下共憂慄。", "南楚有瓊枝，相思怨瑤瑟。", "一身寄滄洲，萬里看白日。", "赴敵甘負戈，論兵勇投筆。", "臨風但攘臂，擇木將委質。", "不如歸遠山，雲臥飯松栗。"]'),
('45fa39a7-d427-4f98-b029-ede01808adfa','哭張員外繼','劉長卿','唐','唐诗','tang','','[]','慟哭鍾陵下，東流與別離。',144,'全唐诗/poet.tang.7000.json','["慟哭鍾陵下，東流與別離。", "二星來不返，雙劒沒相隨。", "獨繼先賢傳，誰刊有道碑。", "故園荒峴曲，旅櫬寄天涯。", "白簡曾連拜，滄洲每共思。", "撫孤憐齒穉，歎逝顧身衰。", "泉壤成終古，雲山若在時。", "秋風鄰笛發，寒日寢門悲。", "世難愁歸路，家貧緩葬期。", "舊賓傷未散，夕臨咽常遲。", "自此辭張邵，何由見戴逵。", "獨聞山吏部，流涕訪孤兒。"]'),
('05c095ff-2f98-48d0-bc8f-af88d637dcbe','登東海龍興寺高頂望海簡演公','劉長卿','唐','唐诗','tang','','[]','朐山壓海口，永望開禪宮。',144,'全唐诗/poet.tang.7000.json','["朐山壓海口，永望開禪宮。", "元氣遠相合，太陽生其中。", "豁然萬里餘，獨爲百川雄。", "白波走雷電，黑霧藏魚龍。", "變化非一狀，晴明分衆容。", "煙開秦帝橋，隱隱橫殘虹。", "蓬島如在眼，羽人那可逢。", "偶聞真僧言，甚與靜者同。", "幽意頗相愜，賞心殊未窮。", "花間午時梵，雲外春山鐘。", "誰念遽成別，自憐歸所從。", "他時相憶處，惆悵西南峯。"]'),
('6569f7e8-47e8-4fc4-9bcd-c394f68df336','奉送從兄罷官之淮南','劉長卿','唐','唐诗','tang','','[]','何事浮溟渤，元戎棄鏌鎁。',144,'全唐诗/poet.tang.7000.json','["何事浮溟渤，元戎棄鏌鎁。", "漁竿吾道在，鷗鳥世情賒。", "玄髮他鄉換，滄洲此路遐。", "泝沿隨桂檝，醒醉任松華。", "離別誰堪道，艱危更可嗟。", "兵鋒搖海內，王命隔天涯。", "鐘漏移長樂，衣冠接永嘉。", "還當拂氛祲，那復臥雲霞。", "溪路漫岡轉，夕陽歸鳥斜。", "萬艘江縣郭，一樹海人家。", "揮袂看朱紱，揚帆指白沙。", "春風獨迴首，愁思極如麻。"]'),
('68a37270-db40-4693-aba6-8c85bb858af0','落第贈楊侍御兼拜員外仍充安大夫判官赴范陽','劉長卿','唐','唐诗','tang','','[]','職副旌旄重，才兼識量通。',144,'全唐诗/poet.tang.7000.json','["職副旌旄重，才兼識量通。", "使車遙肅物，邊策遠和戎。", "擲地金聲著，從軍寶劒雄。", "官成稽古力，名達濟時功。", "肅穆烏臺上，雍容粉署中。", "含香初待漏，持簡舊生風。", "黠吏偏驚隼，貪夫輒避驄。", "且知榮已隔，誰謂道仍同。", "念舊追連茹，謀生任轉蓬。", "泣連三獻玉，瘡懼再傷弓。", "戀土函關外，瞻塵灞水東。", "他時書一札，猶冀問途窮。"]'),
('e40146d6-0947-4ab5-b02a-ad2e922ad560','初貶南巴至鄱陽題李嘉祐江亭','劉長卿','唐','唐诗','tang','','["\u957f\u6c5f"]','巴嶠南行遠，長江萬里隨。',144,'全唐诗/poet.tang.7000.json','["巴嶠南行遠，長江萬里隨。", "不才甘謫去，流水亦何之。", "地遠明君棄，天高酷吏欺。", "清山獨往路，芳草未歸時。", "流落還相見，悲懽話所思。", "猜嫌傷薏苡，愁暮向江籬。", "柳色迎高塢，荷衣照下帷。", "水雲初起重，暮鳥遠來遲。", "白首看長劒，滄洲寄釣絲。", "沙鷗驚小吏，湖月上高枝。", "稚子能吳語，新文怨楚辭。", "憐君不得意，川谷自逶迤。"]'),
('40843ec1-56da-4363-8f1c-c6d294b1ab0a','初貶南巴至鄱陽題李嘉祐江亭','劉長卿','唐','唐诗','tang','','["\u957f\u6c5f"]','南出巴人徼，長江萬里隨。',120,'全唐诗/poet.tang.7000.json','["南出巴人徼，長江萬里隨。", "不才甘謫去，流水亦何之。", "地逺明君棄，天髙酷吏欺。", "青山獨往路，芳草未歸時。", "流落還相見，悲歡話所思。", "猜讒傷薏苡，愁暮向江蘺。", "淚盡㸔長劔，心閑寄釣𢇁。", "水雲初起重，暮鳥逺來遲。", "稚子能吳語，新文怨楚詞。", "憐君不得意，客鬢老南枝。"]'),
('56c7ff04-a62b-41c9-bb78-6b98789d9c4e','自紫陽觀至華陽洞宿侯尊師草堂簡同遊李延年','劉長卿','唐','唐诗','tang','','[]','石門媚煙景，句曲盤江甸。',144,'全唐诗/poet.tang.7000.json','["石門媚煙景，句曲盤江甸。", "南向佳氣濃，數峰遙隱見。", "漸臨華陽口，雲路入蔥蒨。", "七曜懸洞宮，五雲抱仙殿。", "銀函竟誰發，金液徒堪薦。", "千載空桃花，秦人深不見。", "東溪喜相遇，貞白如會面。", "青鳥來去閑，紅霞朝夕變。", "一從換仙骨，萬里乘飛電。", "蘿月延步虛，松花醉閑宴。", "幽人即長往，茂宰應交戰。", "明發歸琴堂，知君嬾爲縣。"]'),
('decb1f34-e449-483e-86eb-2c1748a556d2','奉使新安自桐廬縣經嚴陵釣臺宿七里灘下寄使院諸公','劉長卿','唐','唐诗','tang','','[]','悠然釣臺下，懷古時一望。',144,'全唐诗/poet.tang.7000.json','["悠然釣臺下，懷古時一望。", "江水自潺湲，行人獨惆悵。", "新安從此始，桂檝方蕩漾。", "回轉百里間，青山千萬狀。", "連崖去不斷，對嶺遙相向。", "夾岸黛色愁，沈沈綠波上。", "夕陽留古木，水鳥拂寒浪。", "月下扣舷聲，煙中採菱唱。", "猶憐負羈束，未暇依清曠。", "牽役徒自勞，近名非所向。", "何時故山裏，却醉松花釀。", "回首唯白雲，孤舟復誰訪。"]'),
('31a3525b-78fa-43fe-a706-a176a082cca1','題虎丘寺','劉長卿','唐','唐诗','tang','','[]','青林虎丘寺，林際翠微路。',144,'全唐诗/poet.tang.7000.json','["青林虎丘寺，林際翠微路。", "仰見山僧來，遙從飛鳥處。", "茲峰淪寶玉，千載唯丘墓。", "埋劒人空傳，鑿山龍已去。", "捫蘿披翳薈，路轉夕陽遽。", "虎嘯崖谷寒，猿鳴杉松暮。", "裴回北樓上，江海窮一顧。", "日映千里帆，鴉歸萬家樹。", "蹔因愜所適，果得損外慮。", "庭暗棲閑雲，簷香滴甘露。", "久迷空寂理，多爲繁華故。", "永欲投死生，餘生豈能誤。"]'),
('c6bf0459-45f3-4bd8-82ce-bdbd323f5f09','奉餞鄭中丞罷浙西節度還京','劉長卿','唐','唐诗','tang','','[]','天上移將星，元戎罷龍節。',144,'全唐诗/poet.tang.7000.json','["天上移將星，元戎罷龍節。", "三軍含怨慕，橫吹聲斷絕。", "五馬嘶城隅，萬人臥車轍。", "滄洲浮雲暮，杳杳去帆發。", "回首不問家，歸心遙向闕。", "煙波限吳楚，日夕事淮越。", "弔影失所依，側身隨下列。", "孤蓬飛不定，長劒光未滅。", "綠綺爲誰彈，綠芳堪自擷。", "悵然江南春，獨此湖上月。", "千里懷去思，百憂變華髮。", "頌聲滿江海，今古流不竭。"]'),
('e93915f1-fb55-4fa8-8d41-3f56cee15cb7','送裴四判官赴河西軍試','劉長卿','唐','唐诗','tang','','[]','吏道豈易愜，如君誰與儔。',144,'全唐诗/poet.tang.7000.json','["吏道豈易愜，如君誰與儔。", "逢時將騁驥，臨事無全牛。", "鮑叔幸相知，田蘇頗同遊。", "英資挺孤秀，清論含古流。", "出塞佐持簡，辭家擁鳴騶。", "憲臺貴公舉，幕府資良籌。", "武士佇明試，皇華難久留。", "陽關望天盡，洮水令人愁。", "萬里看一鳥，曠然煙霞收。", "晚花對古戍，春雪含邊州。", "道路難暫隔，音塵那可求。", "他時相望處，明月西南樓。"]'),
('2253e5f4-5e6a-4906-b808-3220cf8ecabe','旅次丹陽郡遇康侍御宣慰召募兼別岑單父','劉長卿','唐','唐诗','tang','','[]','客心暮千里，回首煙花繁。',168,'全唐诗/poet.tang.7000.json','["客心暮千里，回首煙花繁。", "楚水渡歸夢，春江連故園。", "羈人懷上國，驕虜窺中原。", "胡馬暫爲害，漢臣多負恩。", "羽書晝夜飛，海內風塵昏。", "雙鬢日已白，孤舟心且論。", "繡衣從此來，汗馬宣王言。", "憂憤激忠勇，悲歡動黎元。", "南徐爭赴難，發卒如雲屯。", "倚劒看太白，洗兵臨海門。", "故人亦滄洲，少別堪傷魂。", "積翠下京口，歸潮落山根。", "如何天外帆，又此波上尊。", "空使憶君處，鶯聲催淚痕。"]'),
('f8057519-a079-43ec-9faf-f0e9f3c4ca09','客舍贈別韋九建赴任河南韋十七造赴任鄭縣就便覲省','劉長卿','唐','唐诗','tang','','[]','與子頗疇昔，常時仰英髦。',156,'全唐诗/poet.tang.7000.json','["與子頗疇昔，常時仰英髦。", "弟兄盡公器，詩賦凌風騷。", "頃者遊上國，獨能光選曹。", "香名冠二陸，精鑒逢山濤。", "且副倚門望，莫辭趨府勞。", "桃花照綵服，草色連青袍。", "征馬臨素滻，離人傾濁醪。", "華山微雨霽，祠上殘雲高。", "而我倦棲屑，別君良鬱陶。", "春風亦未已，旅思空滔滔。", "拙分甘棄置，窮居長蓬蒿。", "人生未鵾化，物議如鴻毛。", "迢遞兩鄉別，殷勤一寶刀。"]'),
('38a99ebe-b15e-4544-bf96-513eb55c1542','送元八遊汝南','劉長卿','唐','唐诗','tang','','[]','元生實奇邁，幸此論疇昔。',168,'全唐诗/poet.tang.7000.json','["元生實奇邁，幸此論疇昔。", "刀筆素推高，鋒鋩久無敵。", "縱橫濟時意，跌宕過人蹟。", "破產供酒錢，盈門皆食客。", "田園頃失計，資用深相迫。", "生事誠可憂，嚴裝遠何適。", "世情薄恩義，俗態輕窮厄。", "四海金雖多，其如向人惜。", "迢遞朗陵道，悵望都門夕。", "向別伊水南，行看楚雲隔。", "繁蟬動高柳，疋馬嘶平澤。", "潢潦今正深，陂湖未澄碧。", "人生不得已，自可甘形役。", "勿復尊前酒，離居剩悽戚。"]'),
('23dbe0e0-5103-450f-b619-a3c30308d416','奉和李大夫同呂評事太行苦熱行兼寄院中諸公仍呈王員外','劉長卿','唐','唐诗','tang','','[]','迢遞太行路，自古稱險惡。',192,'全唐诗/poet.tang.7000.json','["迢遞太行路，自古稱險惡。", "千騎儼欲前，羣峰望如削。", "火雲從中出，仰視飛鳥落。", "汗馬臥高原，危旌倚長薄。", "清風竟不至，赤日方煎鑠。", "石枯山木燋，鱗窮水泉涸。", "九重今旰食，萬里傳明略。", "諸將候軒車，元凶愁鼎鑊。", "何勞短兵接，自有長纓縛。", "通越事豈難，渡瀘功未博。", "朝辭羊腸阪，夕望貝丘郭。", "漳水斜遶營，常山遙入幕。", "永懷姑蘇下，遙寄建安作。", "白雪和難成，滄波意空託。", "陳琳書記好，王粲從軍樂。", "早晚歸漢廷，隨公上麟閣。"]'),
('28c76401-3b91-4f73-976e-2643b9903b9e','洛陽主簿叔知和驛承恩赴選伏辭一首','劉長卿','唐','唐诗','tang','','[]','仲父王佐材，屈身仇香位。',192,'全唐诗/poet.tang.7000.json','["仲父王佐材，屈身仇香位。", "一從理京劇，萬事皆容易。", "則知無不可，通變有餘地。", "器宇溟渤寬，文鋒鏌铘利。", "憧憧洛陽道，日夕皇華使。", "二載出江亭，一心奉王事。", "功成良可錄，道在知無愧。", "天府留香名，銓闈就明試。", "賦詩皆舊友，攀轍多新吏。", "綵服辭高堂，青袍擁征騎。", "此行季春月，時物正鮮媚。", "官柳陰相連，桃花色如醉。", "長安想在目，前路遙髣髴。", "落日看華山，關門逼青翠。", "行襜稍已隔，結戀無能慰。", "誰念尊酒間，裴回竹林意。"]'),
('aa34c56f-f100-4a7f-8f79-2f5c52a4b6ec','題冤句宋少府廳留別','劉長卿','唐','唐诗','tang','','[]','宋侯人之秀，獨步南曹吏。',216,'全唐诗/poet.tang.7000.json','["宋侯人之秀，獨步南曹吏。", "世上無此才，天生一公器。", "尚甘黃綬屈，未適青雲意。", "洞澈萬頃陂，昂藏千里驥。", "從宦聞苦節，應物推高誼。", "薄俸不自資，傾家共人費。", "顧予倦棲託，終日憂窮匱。", "開口即有求，私心豈無愧。", "幸逢東道主，因輟西征騎。", "對話堪息機，披文欲忘味。", "壺觴招過客，几案無留事。", "綠樹映層城，蒼苔覆閑地。", "一言重然諾，累夕陪宴慰。", "何意秋風來，颯然動歸思。", "留歡殊自愜，去念能爲累。", "草色愁別時，槐花落行次。", "臨期仍把手，此會良不易。", "他日瓊樹枝，相思勞夢寐。"]'),
('e44342c3-069f-4a4a-88c0-2d36a761e0ea','罷攝官後將還舊居留辭李侍御','劉長卿','唐','唐诗','tang','','[]','江海今爲客，風波失所依。',264,'全唐诗/poet.tang.7000.json','["江海今爲客，風波失所依。", "白雲心已負，黃綬計仍非。", "累辱羣公薦，頻霑一尉微。", "去緣焚玉石，來爲采葑菲。", "州縣名何在，漁樵事亦違。", "故山桃李月，初服薜蘿衣。", "熊軾分朝寄，龍韜解賊圍。", "風謠傳吏體，雲物助兵威。", "白雲飄辭律，青春發禮闈。", "引軍橫吹動，援翰捷書揮。", "草映翻營綠，花臨檄羽飛。", "全吳爭轉戰，狂虜怯知機。", "憶昨趨金節，臨時廢玉徽。", "俗流應不厭，靜者或相譏。", "世難慵干謁，時閑喜放歸。", "潘郎悲白髮，謝客愛清輝。", "樗散材因棄，交親迹已稀。", "獨愁看五柳，無事掩雙扉。", "世累多行路，生涯向釣磯。", "榜連溪水碧，家羨渚田肥。", "旅食傷飄梗，巖棲憶采薇。", "悠然獨歸去，回首望旌旗。"]'),
('6a1d814c-c861-469d-9f1a-53860e4f03ce','贈別于羣投筆赴安西','劉長卿','唐','唐诗','tang','','[]','風流一才子，經史仍滿腹。',266,'全唐诗/poet.tang.7000.json','["風流一才子，經史仍滿腹。", "心鏡萬象生，文鋒衆人服。", "頃遊靈臺下，頻棄荆山玉。", "蹭蹬空數年，裴回冀微祿。", "朅來投筆硯，長揖謝親族。", "且欲圖變通，安能守拘束。", "本持鄉曲譽，肯料泥塗辱。", "誰謂命迍邅，還令計反覆。", "西戎今未弭，胡騎屯山谷。", "坐恃龍豹韜，全輕蜂蠆毒。", "拂衣從此去，擁傳一何速。", "元帥許提攜，他人佇瞻矚。", "出門寡儔侶，矧乃無僮僕。", "黠虜時相逢，黃沙暮愁宿。", "蕭條遠回首，萬里如在目。", "漢境天西窮，[胡]山海邊綠。", "想聞羌笛處，淚盡關山曲。", "地闊鳥飛遲，風寒馬毛縮。", "邊愁殊浩蕩，離思空斷續。", "塞上歸限賒，尊前別期促。", "知君志不小，一舉凌鴻鵠。", "且願樂從軍，功名在殊俗。"]'),
('3a09c1fb-69c2-46c4-a242-d811823d1df0','送薛據宰涉縣','劉長卿','唐','唐诗','tang','','[]','故人河山秀，獨立風神異。',288,'全唐诗/poet.tang.7000.json','["故人河山秀，獨立風神異。", "人許白眉長，天姿青雲器。", "雄辭變文名，高價喧時議。", "下筆盈萬言，皆合古人意。", "一從負能名，數載猶卑位。", "寶劒誠可用，烹鮮是虛棄。", "昔聞在河上，高臥自無事。", "几案終日閑，蒲鞭使人畏。", "頃因歲月滿，方謝風塵吏。", "頌德有輿人，薦賢逢八使。", "棲鸞往已屈，馴雀今可嗣。", "此道如不移，雲霄坐應致。", "縣前漳水綠，郭外晉山翠。", "日得謝客遊，時堪陶令醉。", "前期今尚遠，握手空宴慰。", "驛路疎柳長，春城百花媚。", "裴回白日隱，暝色含天地。", "一鳥向灞陵，孤雲送行騎。", "夫君多述作，而我常諷味。", "賴有瓊瑤資，能寬別離思。", "槐陰覆堂殿，苔色上階砌。", "鳥倦自歸飛，雲閑獨空㵝。", "既將慕幽絕，兼欲看定慧。", "遇物忘世緣，還家嬾生計。"]'),
('6a0f5b42-0e13-4f68-8ef4-571f4fe4ffdc','早春贈別趙居士還江左時長卿下第歸嵩陽舊居','劉長卿','唐','唐诗','tang','','[]','見君風塵裏，意出風塵外。',288,'全唐诗/poet.tang.7000.json','["見君風塵裏，意出風塵外。", "自有滄洲期，含情十餘載。", "深居鳳城曲，日預龍華會。", "果得僧家緣，能遺俗人態。", "一身今已適，萬物知何愛。", "悟法電已空，看心水無礙。", "且將窮妙理，兼欲尋勝概。", "何獨謝客遊，當爲遠公輩。", "放舟馳楚郭，負杖辭秦塞。", "目送南飛雲，令人想吳會。", "遙思舊遊處，髣髴疑相對。", "夜火金陵城，春煙石頭瀨。", "滄波極天末，萬里明如帶。", "一片孤客帆，飄然向青靄。", "楚天合江氣，雲色常霮䨴。", "隱見湖中山，相連數州內。", "君行意可得，全與時人背。", "歸路隨楓林，還鄉念蓴菜。", "顧予尚羈束，何幸承眄睞。", "素願徒自勤，清機本難逮。", "累幸忝賓薦，末路逢沙汰。", "濩落名不成，裴回意空大。", "逢時雖貴達，守道甘易退。", "逆旅鄉夢頻，春風客心碎。"]'),
('03857755-ded7-4098-9d07-94ad24cd20f2','夜宴洛陽程九主簿宅送楊三山人往天台尋智者禪師隱居','劉長卿','唐','唐诗','tang','','[]','東林問逋客，何處棲幽偏？',288,'全唐诗/poet.tang.7000.json','["東林問逋客，何處棲幽偏？", "滿腹萬餘卷，息機三十年。", "志圖良已久，鬢髮空蒼然。", "調嘯寄疎曠，形骸如棄捐。", "本家關西族，別業嵩陽田。", "雲臥能獨往，山棲幸周旋。", "垂竿不在魚，賣藥不爲錢。", "藜杖閑倚壁，松花常醉眠。", "頃辭青溪隱，來訪赤縣仙。", "南畝自甘賤，中朝唯愛賢。", "仍空世諦法，遠結天台緣。", "魏闕從此去，滄洲知所便。", "主人瓊枝秀，寵別瑤華篇。", "落日掃塵榻，春風吹客船。", "此行頗自適，物外誰能牽。", "弄棹白蘋裏，挂帆飛鳥邊。", "落潮見孤嶼，徹底觀澄漣。", "雁過湖上月，猿聲峰際天。", "羣峰趨海嶠，千里黛相連。", "遙倚赤城上，曈曈初日圓。", "昔聞智公隱，此地常安禪。", "千載已如夢，一燈今尚傳。", "雲龕閉遺影，石窟無人煙。", "古寺暗喬木，春崖鳴細泉。"]'),
('97dfdf56-aa86-4e99-a5fd-d7273ddf8146','瓜洲驛奉餞張侍御公拜膳部郎中却復憲臺充賀蘭大夫留後使之嶺南時侍御先在淮南幕府','劉長卿','唐','唐诗','tang','','[]','太華高標峻，青陽淑氣盤。',288,'全唐诗/poet.tang.7000.json','["太華高標峻，青陽淑氣盤。", "屬辭傾渤澥，稱價掩琅玕。", "楊葉頻推中，芸香早拜官。", "後來慚轍跡，先達仰門闌。", "佐劇勞黃綬，提綱疾素餐。", "風生趨府步，筆偃觸邪冠。", "骨鯁知難屈，鋒鋩豈易干。", "佇將調玉鉉，翻自落金丸。", "異議那容直，專權本畏彈。", "寸心寧有負，三黜竟無端。", "適喜鴻私降，旋驚羽檄攢。", "國憐朝市易，人怨虎狼殘。", "天地龍初見，風塵虜未殫。", "隨川歸少海，就日背長安。", "副相榮分寄，輸忠義不刊。", "擊胡馳汗馬，遷蜀扈鳴鑾。", "月罷名卿署，星懸上將壇。", "三軍搖斾出，百越畫圖觀。", "茅茹能相引，泥沙肯再蟠。", "兼榮知任重，交辟許才難。", "勁直隨臺柏，芳香動省蘭。", "璧從全趙去，鵬自北溟摶。", "星象銜新寵，風霜帶舊寒。", "是非生倚伏，榮辱繫悲歡。"]'),
('fde2f525-95e4-4dec-8e58-95f8ee53cfe8','至德三年春正月時謬蒙差攝海鹽令聞王師收二京因書事寄上浙西節度李侍郎中丞行營五十韻','劉長卿','唐','唐诗','tang','','[]','天上胡星孛，人間反氣橫。',288,'全唐诗/poet.tang.7000.json','["天上胡星孛，人間反氣橫。", "風塵生汗馬，河洛縱長鯨。", "本謂才非據，誰知禍已萌。", "食參將可待，誅錯輙爲名。", "萬里兵鋒接，三時羽檄驚。", "負恩殊鳥獸，流毒遍黎氓。", "朝市成蕪沒，干戈起戰爭。", "人心懸反覆，天道暫虛盈。", "略地侵中土，傳烽到上京。", "王師陷魑魅，帝座逼欃槍。", "渭水嘶胡馬，秦山泣漢兵。", "關原馳萬騎，煙火亂千甍。", "鳳駕瞻西幸，龍樓議北征。", "自將行破竹，誰學去吹笙。", "白日重輪慶，玄穹再造榮。", "鬼神潛釋憤，夷狄遠輸誠。", "海內戎衣卷，關中賊壘平。", "山川隨轉戰，草木困橫行。", "區宇神功立，謳歌帝業成。", "天回萬象慶，龍見五雲迎。", "小苑春猶在，長安日更明。", "星辰歸正位，雷雨發殘生。", "文物登前古，簫韶下太清。", "未央新柳色，長樂舊鐘聲。"]'),
('c832dd32-6f9f-46e4-ad67-5ce87da562b5','尋張逸人山居','劉長卿','唐','唐诗','tang','','[]','危石纔通鳥道，空山更有人家。',28,'全唐诗/poet.tang.7000.json','["危石纔通鳥道，空山更有人家。", "桃源定在深處，澗水浮來落花。"]'),
('dc4c89f7-437b-42d0-8362-b30a029b6a93','發越州赴潤州使院留別鮑侍御','劉長卿','唐','唐诗','tang','','[]','對水看山別離，孤舟日暮行遲。',28,'全唐诗/poet.tang.7000.json','["對水看山別離，孤舟日暮行遲。", "江南江北春草，獨向金陵去時。"]'),
('ff7cb898-487d-4ffa-8261-edf0bfabe31a','送陸[澧]還吳中','劉長卿','唐','唐诗','tang','','[]','瓜步寒潮送客，楊柳暮雨沾衣。',28,'全唐诗/poet.tang.7000.json','["瓜步寒潮送客，楊柳暮雨沾衣。", "故山南望何處，秋草連天獨歸。"]'),
('e1e365ee-c288-4279-9a84-3c0007144fe2','苕溪酬梁耿別後見寄','劉長卿','唐','唐诗','tang','','["\u79bb\u522b", "\u6292\u60c5", "\u5199\u666f", "\u6101\u82e6"]','清川永路何極，落日孤舟解攜。',56,'全唐诗/poet.tang.7000.json','["清川永路何極，落日孤舟解攜。", "鳥向平蕪遠近，人隨流水東西。", "白雲千里萬里，明月前溪後溪。", "惆悵長沙謫去，江潭芳草萋萋。"]'),
('8bfabdb6-574e-4a38-9d55-28ea0a213c01','蛇浦橋下重送嚴維','劉長卿','唐','唐诗','tang','','[]','秋風颯颯鳴條，風月相和寂寥。',56,'全唐诗/poet.tang.7000.json','["秋風颯颯鳴條，風月相和寂寥。", "黃葉一離一別，青山暮暮朝朝。", "寒江漸出高岸，古木猶依斷橋。", "明日行人已遠，空餘淚滴回潮。"]'),
('7cbf611f-031c-4fab-989d-a24645e7f46a','七里灘重送','劉長卿','唐','唐诗','tang','','[]','秋江渺渺水空波，越客孤舟欲榜歌。',32,'全唐诗/poet.tang.7000.json','["秋江渺渺水空波，越客孤舟欲榜歌。", "手折衰楊悲老大，故人零落已無多。"]'),
('4081cc15-d180-49bf-97f2-0d27f01695a5','家園瓜熟是故蕭相公所遺瓜種悽然感舊因賦此詩','劉長卿','唐','唐诗','tang','','[]','事去人亡跡自留，黃花綠蒂不勝愁。',32,'全唐诗/poet.tang.7000.json','["事去人亡跡自留，黃花綠蒂不勝愁。", "誰能更向青門外，秋草茫茫覓故侯。"]'),
('c3a427a0-3821-4310-aaf6-123c4ec020e4','重送裴郎中貶吉州','劉長卿','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u5199\u666f"]','猿啼客散暮江頭，人自傷心水自流。',32,'全唐诗/poet.tang.7000.json','["猿啼客散暮江頭，人自傷心水自流。", "同作逐臣君更遠，青山萬里一孤舟。"]'),
('4514a4e0-b491-43d8-8eb2-475c818ed4c5','尋盛禪師蘭若','劉長卿','唐','唐诗','tang','','[]','秋草黃花覆古阡，隔林何處起人煙。',32,'全唐诗/poet.tang.7000.json','["秋草黃花覆古阡，隔林何處起人煙。", "山僧獨在山中老，唯有寒松見少年。"]'),
('3b87ec62-ac72-447a-bea0-002579c3d6be','寄許尊師','劉長卿','唐','唐诗','tang','','[]','獨上雲梯入翠微，蒙蒙煙雪映巖扉。',32,'全唐诗/poet.tang.7000.json','["獨上雲梯入翠微，蒙蒙煙雪映巖扉。", "世人知在中峰裏，遙禮青山恨不歸。"]'),
('e3e453ce-b591-4a18-91ea-b9df0a17c500','酬李穆見寄','劉長卿','唐','唐诗','tang','','["\u6292\u60c5", "\u5ba2\u4eba", "\u5199\u666f"]','孤舟相訪至天涯，萬轉雲山路更賒。',32,'全唐诗/poet.tang.7000.json','["孤舟相訪至天涯，萬轉雲山路更賒。", "欲掃柴門迎遠客，青苔黃葉滿貧家。"]'),
('1898b1c7-c1ed-4790-8248-68c794d4c7d3','送王司馬秩滿西歸','劉長卿','唐','唐诗','tang','','[]','漢主何時放逐臣？江邊幾度送歸人。',32,'全唐诗/poet.tang.7000.json','["漢主何時放逐臣？江邊幾度送歸人。", "同官歲歲先辭滿，唯有青山伴老身。"]'),
('fa701a5e-8666-4100-a5be-f53ace69bdc5','送王司馬秩滿西歸','劉長卿','唐','唐诗','tang','','[]','漢代何人訪逐臣，江邊幾度送歸人。',32,'全唐诗/poet.tang.7000.json','["漢代何人訪逐臣，江邊幾度送歸人。", "同官歲歲先辭滿，唯有青山伴老身。"]'),
('439b19f5-2b3b-400f-99cb-f3245715ebf0','寄別朱拾遺','劉長卿','唐','唐诗','tang','','[]','天書遠召滄浪客，幾度臨岐病未能。',32,'全唐诗/poet.tang.7000.json','["天書遠召滄浪客，幾度臨岐病未能。", "江海茫茫春欲遍，行人一騎發金陵。"]'),
('b493aef4-d26b-4db6-912e-9b41401a825e','會赦後酬主簿所問','劉長卿','唐','唐诗','tang','','[]','江南海北長相憶，淺水深山獨掩扉。',32,'全唐诗/poet.tang.7000.json','["江南海北長相憶，淺水深山獨掩扉。", "重見太平身已老，桃源久住不能歸。"]'),
('d6a825a6-a414-4e25-bbb0-5b0ffb707b1d','贈秦系','劉長卿','唐','唐诗','tang','','[]','向風長嘯戴紗巾，野鶴由來不可親。',32,'全唐诗/poet.tang.7000.json','["向風長嘯戴紗巾，野鶴由來不可親。", "明日東歸變名姓，五湖煙水覓何人。"]'),
('c98d85c6-5b82-45a1-9b18-f64d24828165','酬靈徹公相招','劉長卿','唐','唐诗','tang','','[]','石磵泉聲久不聞，獨臨長路雪紛紛。',32,'全唐诗/poet.tang.7000.json','["石磵泉聲久不聞，獨臨長路雪紛紛。", "如今漸欲生黃髮，願脫頭冠與白雲。"]'),
('7f8e7ea2-7550-4805-9629-fc905e815bc4','贈崔九載華','劉長卿','唐','唐诗','tang','','[]','憐君一見一悲歌，歲歲無如老去何。',32,'全唐诗/poet.tang.7000.json','["憐君一見一悲歌，歲歲無如老去何。", "白屋漸看秋草沒，青雲莫道故人多。"]'),
('51188758-7ff5-4252-adc3-ef87fb6cbdca','同崔載華贈日本聘使','劉長卿','唐','唐诗','tang','','[]','憐君異域朝周遠，積水連天何處通。',32,'全唐诗/poet.tang.7000.json','["憐君異域朝周遠，積水連天何處通。", "遙指來從初日外，始知更有扶桑東。"]'),
('147e279d-ec0b-44c6-9a43-c93f3fe1dc63','送建州陸使君','劉長卿','唐','唐诗','tang','','[]','漢庭初拜建安侯，天子臨軒寄所憂。',32,'全唐诗/poet.tang.7000.json','["漢庭初拜建安侯，天子臨軒寄所憂。", "從此向南無限路，雙旌已去水悠悠。"]'),
('aec89983-bf8a-4474-9b19-e00ea24e0de7','送秦侍御外甥張篆之福州謁鮑大夫秦侍御與大夫有舊','劉長卿','唐','唐诗','tang','','[]','萬里閩中去渺然，孤舟水上入寒煙。',32,'全唐诗/poet.tang.7000.json','["萬里閩中去渺然，孤舟水上入寒煙。", "轅門拜首儒衣弊，貌似牢之豈不憐。"]'),
('23011bdb-2593-4ae8-a04e-69b1b1ce833e','聞奉迎皇太后使沈判官至因有此作','劉長卿','唐','唐诗','tang','','[]','長樂宮人掃落花，君王正候五雲車。',32,'全唐诗/poet.tang.7000.json','["長樂宮人掃落花，君王正候五雲車。", "萬方臣妾同瞻望，疑在曾城阿母家。"]'),
('be507a52-15f0-43be-96d8-f58a94e54c64','送劉萱之道州謁崔大夫','劉長卿','唐','唐诗','tang','','[]','沅水悠悠湘水春，臨岐南望一沾巾。',32,'全唐诗/poet.tang.7000.json','["沅水悠悠湘水春，臨岐南望一沾巾。", "信陵門下三千客，君到長沙見幾人。"]'),
('db76ca9e-6e19-409a-b66a-0fc2e277c060','過鄭山人所居','劉長卿','唐','唐诗','tang','','[]','寂寂孤鶯啼杏園，寥寥一犬吠桃源。',32,'全唐诗/poet.tang.7000.json','["寂寂孤鶯啼杏園，寥寥一犬吠桃源。", "落花芳草無尋處，萬壑千峰獨閉門。"]'),
('7d618f36-2127-411c-8978-9884a92f56d8','奉送賀若郎中賊退後之杭州','劉長卿','唐','唐诗','tang','','[]','江上初收戰馬塵，鶯聲柳色待行春。',32,'全唐诗/poet.tang.7000.json','["江上初收戰馬塵，鶯聲柳色待行春。", "雙旌誰道來何暮，萬井如今有幾人。"]'),
('b87684b6-8286-4391-be4b-3578d86e370c','瓜洲驛重送梁郎中赴吉州','劉長卿','唐','唐诗','tang','','[]','渺渺雲山去幾重，依依獨聽廣陵鐘。',32,'全唐诗/poet.tang.7000.json','["渺渺雲山去幾重，依依獨聽廣陵鐘。", "明朝借問南來客，五馬雙旌何處逢。"]'),
('d0a28e97-a4ad-4956-bebf-4950f46da6f8','奉使鄂渚至烏江道中作','劉長卿','唐','唐诗','tang','','[]','滄洲不復戀魚竿，白髮那堪戴鐵冠。',32,'全唐诗/poet.tang.7000.json','["滄洲不復戀魚竿，白髮那堪戴鐵冠。", "客路向南何處是，蘆花千里雪漫漫。"]'),
('80f3b863-0617-4347-bce9-467baacd9423','新息道中作','劉長卿','唐','唐诗','tang','','[]','蕭條獨向汝南行，客路多逢漢騎營。',32,'全唐诗/poet.tang.7000.json','["蕭條獨向汝南行，客路多逢漢騎營。", "古木蒼蒼離亂後，幾家同住一孤城。"]'),
('3bba59d0-7837-4edd-9651-efabe2d9753f','春日宴魏萬成湘水亭','劉長卿','唐','唐诗','tang','','[]','何年家住此江濱，幾度門前北渚春。',32,'全唐诗/poet.tang.7000.json','["何年家住此江濱，幾度門前北渚春。", "白髮亂生相顧老，黃鶯自語豈知人。"]'),
('1c32fc96-9419-4178-9fbf-e5e2809a2c28','重送道標上人','劉長卿','唐','唐诗','tang','','[]','衡陽千里去人稀，遙逐孤雲入翠微。',32,'全唐诗/poet.tang.7000.json','["衡陽千里去人稀，遙逐孤雲入翠微。", "春草青青新覆地，深山無路若爲歸。"]'),
('d0a52b5e-062d-4d77-870a-83b3f75b4c3a','送李判官之潤州行營','劉長卿','唐','唐诗','tang','','["\u9001\u522b", "\u53cb\u60c5"]','萬里辭家事鼓鼙，今陵驛路楚雲西。',32,'全唐诗/poet.tang.7000.json','["萬里辭家事鼓鼙，今陵驛路楚雲西。", "江春不肯留歸客，草色青青送馬蹄。"]'),
('eefce47d-74f9-4c94-9ec0-65a80d897d6a','將赴南巴至餘干別李十二','劉長卿','唐','唐诗','tang','','[]','江上花催問禮人，鄱陽鶯報越鄉春。',32,'全唐诗/poet.tang.7000.json','["江上花催問禮人，鄱陽鶯報越鄉春。", "誰憐此別悲歡異，萬里青山送逐臣。"]'),
('ee4f7562-3dfe-4b93-a8f8-14fca44a5960','時平後春日思歸','劉長卿','唐','唐诗','tang','','[]','一尉何曾及布衣，時平却憶臥柴扉。',32,'全唐诗/poet.tang.7000.json','["一尉何曾及布衣，時平却憶臥柴扉。", "故園柳色催南客，春水桃花待北歸。"]'),
('e15f0418-0911-4134-b0b7-01bd28ec5623','送陶十赴杭州攝掾','劉長卿','唐','唐诗','tang','','[]','莫歎江城一掾卑，滄洲未是阻心期。',32,'全唐诗/poet.tang.7000.json','["莫歎江城一掾卑，滄洲未是阻心期。", "浙中山色千萬狀，門外潮聲朝暮時。"]'),
('01033ac8-52e9-4cd7-a8b2-1f55b4cc1364','使還七里瀨上逢薛承規赴江西貶官','劉長卿','唐','唐诗','tang','','[]','遷客歸人醉晚寒，孤舟暫泊子陵灘。',32,'全唐诗/poet.tang.7000.json','["遷客歸人醉晚寒，孤舟暫泊子陵灘。", "憐君更去三千里，落日青山江上看。"]'),
('71b92ee1-1476-4a2d-bdb9-b618120a07b2','使回赴蘇州道中作','劉長卿','唐','唐诗','tang','','[]','春風何事遠相催，路盡天涯始却回。',32,'全唐诗/poet.tang.7000.json','["春風何事遠相催，路盡天涯始却回。", "萬里無人空楚水，孤帆送客到魚臺。"]'),
('a8a231a2-3110-46db-8454-0521b1ac5925','昭陽曲','劉長卿','唐','唐诗','tang','','[]','昨夜承恩宿未央，羅衣猶帶御衣香。',32,'全唐诗/poet.tang.7000.json','["昨夜承恩宿未央，羅衣猶帶御衣香。", "芙蓉帳小雲屏暗，楊柳風多水殿涼。"]'),
('22c1fb37-4ae2-4a05-b355-31cfe9a6e9d2','罪所留繫每夜聞長洲軍笛聲','劉長卿','唐','唐诗','tang','','[]','白日浮雲閉不開，黃沙誰問冶長猜。',32,'全唐诗/poet.tang.7000.json','["白日浮雲閉不開，黃沙誰問冶長猜。", "只憐橫笛關山月，知處愁人夜夜來。"]'),
('b891a3e0-c4af-42b3-833e-9083c22b7eb7','贈微上人','劉長卿','唐','唐诗','tang','','[]','禪門來往翠微間，萬里千峰在剡山。',32,'全唐诗/poet.tang.7000.json','["禪門來往翠微間，萬里千峰在剡山。", "何時共到天台裏，身與浮雲處處閑。"]'),
('638c9288-ef7f-4478-8731-0bf5ab7fdcd4','東湖送朱逸人歸','劉長卿','唐','唐诗','tang','','[]','山色湖光併在東，扁舟歸去有樵風。',32,'全唐诗/poet.tang.7000.json','["山色湖光併在東，扁舟歸去有樵風。", "莫道野人無外事，開田鑿井白雲中。"]'),
('0046c0d4-5957-496f-bc0f-0ee705197f5a','舟中送李十八','劉長卿','唐','唐诗','tang','','[]','釋子身心無有分，獨將衣鉢去人羣。',32,'全唐诗/poet.tang.7000.json','["釋子身心無有分，獨將衣鉢去人羣。", "相思晚望西林寺，唯有鐘聲出白雲。"]'),
('291050c9-d586-4465-8423-530b784b44f0','送李穆歸淮南','劉長卿','唐','唐诗','tang','','[]','揚州春草新年綠，未去先愁去不歸。',32,'全唐诗/poet.tang.7000.json','["揚州春草新年綠，未去先愁去不歸。", "淮水問君來早晚，老人偏畏過芳菲。"]'),
('c604753a-df3f-4171-8d5a-19b8e3260aa3','晚春歸山居題窗前竹','劉長卿','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','溪上殘春黃鳥稀，辛夷花盡杏花飛。',32,'全唐诗/poet.tang.7000.json','["溪上殘春黃鳥稀，辛夷花盡杏花飛。", "始憐幽竹山窗下，不改清陰待我歸。"]'),
('ed35e220-5c75-4dc8-986f-af19200286fb','送盧侍御赴河北','劉長卿','唐','唐诗','tang','','[]','謫居爲別倍傷情，何事從戎獨遠行。',64,'全唐诗/poet.tang.7000.json','["謫居爲別倍傷情，何事從戎獨遠行。", "千里按圖收故地，三軍罷戰及春耕。", "江天渺渺鴻初去，漳水悠悠草欲生。", "莫學仲連逃海上，田單空愧取聊城。"]'),
('f524913b-4ec2-43ab-838e-068a8121ccd1','送子壻崔真父歸長城','劉長卿','唐','唐诗','tang','','[]','送君巵酒不成歡，幼女辭家事伯鸞。',64,'全唐诗/poet.tang.7000.json','["送君巵酒不成歡，幼女辭家事伯鸞。", "桃葉宜人誠可詠，柳花如雪若爲看。", "心憐稚齒鳴環去，身愧衰顏對玉難。", "惆悵暮帆何處落，青山無限水漫漫。"]'),
('94688bea-6d3f-4aec-9a91-4fccae99de86','送陸[澧]倉曹西上','劉長卿','唐','唐诗','tang','','[]','長安此去欲何依，先達誰當薦陸機。',64,'全唐诗/poet.tang.7000.json','["長安此去欲何依，先達誰當薦陸機。", "日下鳳翔雙闕迥，雪中人去二陵稀。", "舟從故里難移棹，家住寒塘獨掩扉。", "臨水自傷流落久，贈君空有淚霑衣。"]'),
('6177928c-10b5-4b13-8c66-d54a9695036f','送柳使君赴袁州','劉長卿','唐','唐诗','tang','','[]','宜陽出守新恩至，京口因家始願違。',64,'全唐诗/poet.tang.7000.json','["宜陽出守新恩至，京口因家始願違。", "五柳閉門高士去，三苗按節遠人歸。", "月明江路聞猨斷，花暗山城見吏稀。", "惟有郡齋窗裏岫，朝朝空對謝玄暉。"]'),
('9cb449a6-871b-4105-ba63-700ebe55e2d1','戲題贈二小男','劉長卿','唐','唐诗','tang','','[]','異鄉流落頻生子，幾許悲歡併在身。',64,'全唐诗/poet.tang.7000.json','["異鄉流落頻生子，幾許悲歡併在身。", "欲並老容羞白髮，每看兒戲憶青春。", "未知門戶誰堪主，且免琴書別與人。", "何幸暮年方有後，舉家相對却霑巾。"]'),
('4d53fd44-4008-4822-ac67-79e9688142a5','謫官後臥病官舍簡賀蘭侍郎','劉長卿','唐','唐诗','tang','','[]','青春衣繡共稱宜，白首垂絲恨不遺。',64,'全唐诗/poet.tang.7000.json','["青春衣繡共稱宜，白首垂絲恨不遺。", "江上幾回今夜月，鏡中無復少年時。", "生還北闕誰相引，老向南邦衆所悲。", "歲歲任他芳草綠，長沙未有定歸期。"]'),
('39ea5d5d-5395-41ae-b662-f1f9a125ec98','歲日見新曆因寄都官裴郎中','劉長卿','唐','唐诗','tang','','[]','青陽振蟄初頒曆，白首銜冤欲問天。',64,'全唐诗/poet.tang.7000.json','["青陽振蟄初頒曆，白首銜冤欲問天。", "絳老更能經幾歲，賈生何事又三年。", "愁占蓍草終難決，病對椒花倍自憐。", "若道平分四時氣，南枝爲底發春偏。"]'),
('d9dd3520-9aab-4b1b-bd57-810f29391667','江州重別薛六柳八二員外','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9001\u522b", "\u4e03\u8a00\u5f8b\u8bd7"]','生涯豈料承優詔，世事空知學醉歌。',64,'全唐诗/poet.tang.7000.json','["生涯豈料承優詔，世事空知學醉歌。", "江上月明胡鴈過，淮南木落楚山多。", "寄身且喜滄洲近，顧影無如白髮何。", "今日龍鍾人共棄，媿君猶遣慎風波。"]'),
('1ab26a26-680d-40cd-92a0-49a4a94cba73','青溪口送人歸岳州','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭何處鴈南飛，江菼蒼蒼客去稀。',64,'全唐诗/poet.tang.7000.json','["洞庭何處鴈南飛，江菼蒼蒼客去稀。", "帆帶夕陽千里沒，天連秋水一人歸。", "黃花裛露開沙岸，白鳥銜魚上釣磯。", "岐路相逢無可贈，老年空有淚霑衣。"]'),
('2be42c69-302b-41b7-800d-0e5ce5084fb6','送靈澈上人還越中','劉長卿','唐','唐诗','tang','','[]','禪客無心杖錫還，沃洲深處草堂閑。',64,'全唐诗/poet.tang.7000.json','["禪客無心杖錫還，沃洲深處草堂閑。", "身隨敝屨經殘雪，手綻寒衣入舊山。", "獨向青溪依樹下，空留白日在人間。", "那堪別後長相憶，雲木蒼蒼但閉關。"]'),
('271a4a04-81b6-45b2-a14b-3afac8ce973e','送耿拾遺歸上都','劉長卿','唐','唐诗','tang','','[]','若爲天畔獨歸秦，對水看山欲暮春。',64,'全唐诗/poet.tang.7000.json','["若爲天畔獨歸秦，對水看山欲暮春。", "窮海別離無限路，隔河征戰幾歸人。", "長安萬里傳雙淚，建德千峰寄一身。", "想到郵亭愁駐馬，不堪西望見風塵。"]'),
('091efd68-4464-4304-b626-1d115da86f63','和樊使君登潤州城樓','劉長卿','唐','唐诗','tang','','[]','山城迢遰敞高樓，露冕吹鐃居上頭。',64,'全唐诗/poet.tang.7000.json','["山城迢遰敞高樓，露冕吹鐃居上頭。", "春草連天隨北望，夕陽浮水共東流。", "江田漠漠全吳地，野樹蒼蒼故蔣州。", "王粲尚爲南郡客，別來何處更銷憂。"]'),
('848a6a9f-9b2c-4b54-a98a-555f800745b4','餞王相公出牧括州','劉長卿','唐','唐诗','tang','','[]','縉雲詎比長沙遠，出牧猶承明主恩。',64,'全唐诗/poet.tang.7000.json','["縉雲詎比長沙遠，出牧猶承明主恩。", "城對寒山開畫戟，路飛秋葉轉朱轓。", "江潮淼淼連天望，旌斾悠悠上嶺翻。", "蕭索庭槐空閉閤，舊人誰到翟公門。"]'),
('fe83fa6d-6e42-4a20-a262-2ef7afe28a17','題靈祐和尚故居','劉長卿','唐','唐诗','tang','','[]','歎逝翻悲有此身，禪房寂寞見流塵。',64,'全唐诗/poet.tang.7000.json','["歎逝翻悲有此身，禪房寂寞見流塵。", "多時行徑空秋草，幾日浮生哭故人。", "風竹自吟遙入磬，雨花隨淚共霑巾。", "殘經窗下依然在，憶得山中問許詢。"]'),
('7db80963-60bb-4d4c-a0f1-0d20c3b30874','尋龍井楊老','劉長卿','唐','唐诗','tang','','[]','柴門草舍絕風塵，空谷耕田學子真。',64,'全唐诗/poet.tang.7000.json','["柴門草舍絕風塵，空谷耕田學子真。", "泉咽恐勞經隴底，山深不覺有秦人。", "手栽松樹蒼蒼老，身臥桃園寂寂春。", "唯有胡麻當雞黍，白雲來往未嫌貧。"]'),
('472a69cd-c17c-4780-b02f-6299a982c23c','見故人李均所借古鏡恨其未獲歸府斯人已亡愴然有作','劉長卿','唐','唐诗','tang','','[]','故人留鏡無歸處，今日懷君試暫窺。',64,'全唐诗/poet.tang.7000.json','["故人留鏡無歸處，今日懷君試暫窺。", "歲久豈堪塵自入，夜長應待月相隨。", "空憐瓊樹曾臨匣，猶見菱花獨映池。", "所恨平生還不早，如今始挂隴頭枝。"]'),
('b2160310-2cf5-46ac-832e-d7216c588d75','聞虞沔州有替將歸上都登漢東城寄贈','劉長卿','唐','唐诗','tang','','[]','淮南搖落客心悲，溳水悠悠怨別離。',64,'全唐诗/poet.tang.7000.json','["淮南搖落客心悲，溳水悠悠怨別離。", "早鴈初辭舊關塞，秋風先入古城池。", "腰章建隼皇恩賜，露冕臨人白髮垂。", "惆悵恨君先我去，漢陽耆老憶旌麾。"]'),
('8414e0dd-1d05-4f0f-b38d-92d937fa7a2f','獻淮寧軍節度使李相公','劉長卿','唐','唐诗','tang','','[]','建牙吹角不聞喧，三十登壇衆所尊。',64,'全唐诗/poet.tang.7000.json','["建牙吹角不聞喧，三十登壇衆所尊。", "家散萬金酬士死，身留一劍答君恩。", "漁陽老將多迴席，魯國諸生半在門。", "白馬翩翩春草細，郊原西去獵平原。"]'),
('56c5c24a-ea68-450d-8329-204042ff4f08','觀校獵上淮西相公','劉長卿','唐','唐诗','tang','','[]','龍驤校獵邵陵東，野火初燒楚澤空。',64,'全唐诗/poet.tang.7000.json','["龍驤校獵邵陵東，野火初燒楚澤空。", "師事黃公千戰後，身騎白馬萬人中。", "笳隨晚吹吟邊草，箭沒寒雲落塞鴻。", "三十擁旄誰不羨，周郎少小立奇功。"]'),
('d9b644fb-e623-47eb-b2b0-b97586564f63','送皇甫曾赴上都','劉長卿','唐','唐诗','tang','','[]','東遊久與故人違，西去荒涼舊路微。',64,'全唐诗/poet.tang.7000.json','["東遊久與故人違，西去荒涼舊路微。", "秋草不生三徑處，行人獨向五陵歸。", "離心日遠如流水，迴首川長共落暉。", "楚客豈勞傷此別，滄江欲暮自霑衣。"]'),
('b0539dbe-3448-4b90-a554-cd82d319ad5d','送李錄事兄歸襄鄧','劉長卿','唐','唐诗','tang','','[]','十年多難與君同，幾處移家逐轉蓬。',64,'全唐诗/poet.tang.7000.json','["十年多難與君同，幾處移家逐轉蓬。", "白首相逢征戰後，青春已過亂離中。", "行人杳杳看西月，歸馬蕭蕭向北風。", "漢水楚雲千萬里，天涯此別恨無窮。"]'),
('0b75e406-e8fa-453a-b749-52a205d807ba','漢陽獻李相公','劉長卿','唐','唐诗','tang','','[]','退身高臥楚城幽，獨掩閑門漢水頭。',64,'全唐诗/poet.tang.7000.json','["退身高臥楚城幽，獨掩閑門漢水頭。", "春草雨中行徑沒，暮山江上捲簾愁。", "幾人猶憶孫弘閣，百口同乘范蠡舟。", "早晚却還丞相印，十年空被白雲留。"]'),
('8cefa67f-2b9a-4e13-8158-4d38cbfb331b','長沙過賈誼宅','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u8fc1\u8c2a", "\u751f\u6d3b", "\u6000\u53e4", "\u4e03\u8a00\u5f8b\u8bd7"]','三年謫宦此棲遲，萬古惟留楚客悲。',64,'全唐诗/poet.tang.7000.json','["三年謫宦此棲遲，萬古惟留楚客悲。", "秋草獨尋人去後，寒林空見日斜時。", "漢文有道恩猶薄，湘水無情弔豈知。", "寂寂江山搖落處，憐君何事到天涯。"]'),
('f2aafd5a-1f1a-4eca-9801-284443b8cac5','奉酬辛大夫喜湖南臘月連日降雪見示之作','劉長卿','唐','唐诗','tang','','[]','長沙耆舊拜旌麾，喜見江潭積雪時。',64,'全唐诗/poet.tang.7000.json','["長沙耆舊拜旌麾，喜見江潭積雪時。", "柳絮三冬先北地，梅花一夜徧南枝。", "初開窗閣寒光滿，欲掩軍城暮色遲。", "閭里何人不相慶，萬家同唱郢中詞。"]'),
('d08bde34-da46-4e92-ac67-961c18ca7d1b','登餘干古縣城','劉長卿','唐','唐诗','tang','','[]','孤城上與白雲齊，萬古荒涼楚水西。',64,'全唐诗/poet.tang.7000.json','["孤城上與白雲齊，萬古荒涼楚水西。", "官舍已空秋草綠，女牆猶在夜烏啼。", "平江渺渺來人遠，落日亭亭向客低。", "沙鳥不知陵谷變，朝飛暮去弋陽溪。"]'),
('82ca796c-9117-448a-9d19-669ac1e6f831','將赴嶺外留題蕭寺遠公院','劉長卿','唐','唐诗','tang','','[]','竹房遙閉上方幽，苔徑蒼蒼訪昔遊。',64,'全唐诗/poet.tang.7000.json','["竹房遙閉上方幽，苔徑蒼蒼訪昔遊。", "內史舊山空日暮，南朝古木向人秋。", "天香月色同僧室，葉落猨啼傍客舟。", "此去播遷明主意，白雲何事欲相留。"]'),
('be1143da-ec70-486b-960a-13a50b8e73d4','初聞貶謫續喜量移登干越亭贈鄭校書','劉長卿','唐','唐诗','tang','','[]','青青草色滿江洲，萬里傷心水自流。',64,'全唐诗/poet.tang.7000.json','["青青草色滿江洲，萬里傷心水自流。", "越鳥豈知南國遠，江花獨向北人愁。", "生涯已逐滄浪去，冤氣初逢渙汗收。", "何事還邀遷客醉，春風日夜待歸舟。"]'),
('e9dc37bc-ac68-4ca7-86d2-9f29bc565b2d','北歸入至德州界偶逢洛陽鄰家李光宰','劉長卿','唐','唐诗','tang','','[]','生涯心事已蹉跎，舊路依然此重過。',64,'全唐诗/poet.tang.7000.json','["生涯心事已蹉跎，舊路依然此重過。", "近北始知黃葉落，向南空見白雲多。", "炎州日日人將老，寒渚年年水自波。", "華髮相逢俱若是，故園秋草復如何。"]'),
('58a87264-b316-4409-aaa5-903ace5479c8','自江西歸至舊任官舍贈袁贊府','劉長卿','唐','唐诗','tang','','[]','却見同官喜復悲，此生何幸有歸期。',64,'全唐诗/poet.tang.7000.json','["却見同官喜復悲，此生何幸有歸期。", "空庭客至逢搖落，舊邑人稀經亂離。", "湘路來過迴鴈處，江城臥聽擣衣時。", "南方風土勞君問，賈誼長沙豈不知。"]'),
('1dd68fdf-913e-4f32-a7a6-2696bad60c3e','赴南中題褚少府湖上亭子','劉長卿','唐','唐诗','tang','','[]','種田東郭傍春陂，萬事無情把釣絲。',64,'全唐诗/poet.tang.7000.json','["種田東郭傍春陂，萬事無情把釣絲。", "綠竹放侵行徑裏，青山常對卷簾時。", "紛紛花落門空閉，寂寂鶯啼日更遲。", "從此別君千萬里，白雲流水憶佳期。"]'),
('daf69f48-d5e3-404f-8e89-4db538d009f7','上巳日越中與鮑侍郎泛舟耶溪','劉長卿','唐','唐诗','tang','','[]','蘭橈縵轉傍汀沙，應接雲峰到若耶。',64,'全唐诗/poet.tang.7000.json','["蘭橈縵轉傍汀沙，應接雲峰到若耶。", "舊浦滿來移渡口，垂楊深處有人家。", "永和春色千年在，曲水鄉心萬里賒。", "君見漁船時借問，前洲幾路入烟花。"]'),
('af936ab6-911f-4133-bf56-8d8f79731971','雙峰下哭故人李宥','劉長卿','唐','唐诗','tang','','[]','憐君孤壠寄雙峰，埋骨窮泉復幾重。',64,'全唐诗/poet.tang.7000.json','["憐君孤壠寄雙峰，埋骨窮泉復幾重。", "白露空霑九原草，青山猶閉數株松。", "圖書經亂知何在，妻子因貧失所從。", "惆悵東臯却歸去，人間無處更相逢。"]'),
('88e9b2b2-8032-4c32-b5fe-3def1e3840e3','使次安陸寄友人','劉長卿','唐','唐诗','tang','','[]','新年草色遠萋萋，久客將歸失路蹊。',64,'全唐诗/poet.tang.7000.json','["新年草色遠萋萋，久客將歸失路蹊。", "暮雨不知溳口處，春風只到穆陵西。", "孤城盡日空花落，三戶無人自鳥啼。", "君在江南相憶否，門前五柳幾枝低。"]'),
('1a31f91c-d216-4169-9e56-b7f8794486a8','哭陳歙州','劉長卿','唐','唐诗','tang','','[]','千秋萬古葬平原，素業清風及子孫。',64,'全唐诗/poet.tang.7000.json','["千秋萬古葬平原，素業清風及子孫。", "旅櫬歸程傷道路，舉家行哭向田園。", "空山寂寂開新壠，喬木蒼蒼掩舊門。", "儒行公才竟何在，獨憐棠樹一枝存。"]'),
('3955c600-fc70-4d7f-9daf-bdd7d1d83b7d','酬屈突陜','劉長卿','唐','唐诗','tang','','[]','落葉紛紛滿四鄰，蕭條環堵絕風塵。',64,'全唐诗/poet.tang.7000.json','["落葉紛紛滿四鄰，蕭條環堵絕風塵。", "鄉看秋草歸無路，家對寒江病且貧。", "藜杖懶迎征騎客，菊花能醉去官人。", "憐君計畫誰知者，但見蓬蒿空沒身。"]'),
('28deb91b-aaa3-4c2f-8563-a36a97dfdf3f','送惠法師遊天台因懷智大師故居','劉長卿','唐','唐诗','tang','','[]','翠屏瀑水知何在，鳥道猨啼過幾重。',64,'全唐诗/poet.tang.7000.json','["翠屏瀑水知何在，鳥道猨啼過幾重。", "落日獨搖金策去，深山誰向石橋逢。", "定攀巖下叢生桂，欲買雲中若箇峰。", "憶想東林禪誦處，寂寥惟聽舊時鐘。"]'),
('3f049d66-1513-407f-bb4e-cf25a7b5069a','自夏口至鸚鵡洲夕望岳陽寄源中丞','劉長卿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6d1e\u5ead\u6e56", "\u8d2c\u8c2a", "\u4e03\u8a00\u5f8b\u8bd7", "\u89e6\u666f\u611f\u6000"]','[汀]洲無浪復無煙，楚客相思益渺然。',66,'全唐诗/poet.tang.7000.json','["[汀]洲無浪復無煙，楚客相思益渺然。", "漢口夕陽斜渡鳥，洞庭秋水遠連天。", "孤城背嶺寒吹角，獨戍臨江夜泊船。", "賈誼上書憂漢室，長沙謫去古今憐。"]'),
('fb2e7187-f5eb-4aab-81db-fb4258110e3b','送侯中丞流康州','劉長卿','唐','唐诗','tang','','["\u957f\u6c5f"]','長江極目帶楓林，匹馬孤雲不可尋。',64,'全唐诗/poet.tang.7000.json','["長江極目帶楓林，匹馬孤雲不可尋。", "遷播共知臣道枉，猜讒却爲主恩深。", "轅門畫角三軍思，驛路青山萬里心。", "北闕九重誰許屈，獨看湘水淚霑襟。"]'),
('0bf9ae01-feb3-4a31-a3ac-6148b69831fe','別嚴士元','劉長卿','唐','唐诗','tang','','["\u5199\u96e8", "\u9001\u522b", "\u6000\u624d\u4e0d\u9047", "\u96e8"]','春風倚棹闔閭城，水國春寒陰復晴。',64,'全唐诗/poet.tang.7000.json','["春風倚棹闔閭城，水國春寒陰復晴。", "細雨濕衣看不見，閑花落地聽無聲。", "日斜江上孤帆影，草綠湖南萬里情。", "東道若逢相識問，青袍今日誤儒生。"]'),
('38180b90-13e7-49c5-8c06-3cc6708a4e6b','避地江東留別淮南使院諸公','劉長卿','唐','唐诗','tang','','[]','長安路絕鳥飛通，萬里孤雲西復東。',64,'全唐诗/poet.tang.7000.json','["長安路絕鳥飛通，萬里孤雲西復東。", "舊業已應成茂草，餘生只是任飄蓬。", "何辭向物開秦鏡，却使他人得楚弓。", "此去行持一竿竹，等閑將狎釣漁翁。"]'),
('d4dceb4e-87b7-4665-87cc-be76263b9d94','罪所上御史惟則','劉長卿','唐','唐诗','tang','','[]','誤因微祿滯南昌，幽繫圜扉晝夜長。',64,'全唐诗/poet.tang.7000.json','["誤因微祿滯南昌，幽繫圜扉晝夜長。", "黃鶴翅垂同燕雀，青松心在任風霜。", "斗間誰與看冤氣，盆下無由見太陽。", "賢達不能同感激，更於何處問蒼蒼。"]'),
('3a28d9de-0421-4fd4-802b-c4a00638d54a','送台州李使君兼寄題國清寺','劉長卿','唐','唐诗','tang','','[]','露冕新承明主恩，山城別是武陵源。',64,'全唐诗/poet.tang.7000.json','["露冕新承明主恩，山城別是武陵源。", "花間五馬時行縣，山外千峰常在門。", "晴江洲渚帶春草，古寺杉松深暮猨。", "知到應真飛錫處，因君一想已忘言。"]'),
('96676df5-e945-4423-928d-d45ebaf99ed9','獄中聞收東京有赦','劉長卿','唐','唐诗','tang','','[]','傳聞闕下降絲綸，爲報關東滅虜塵。',64,'全唐诗/poet.tang.7000.json','["傳聞闕下降絲綸，爲報關東滅虜塵。", "壯志已憐成白首，餘生猶待發青春。", "風霜何事偏傷物，天地無情亦愛人。", "持法不須張密網，恩波自解惜枯鱗。"]'),
('aedfbefc-e345-4396-b23e-3323346f6f12','溫湯客舍','劉長卿','唐','唐诗','tang','','[]','冬狩溫泉歲欲闌，宮城佳氣晚宜看。',64,'全唐诗/poet.tang.7000.json','["冬狩溫泉歲欲闌，宮城佳氣晚宜看。", "湯熏仗裏千旗暖，雪照山邊萬井寒。", "君門獻賦誰相達，客舍無錢輙自安。", "且喜禮闈秦鏡在，還將妍醜付春官。"]'),
('9ce7b24e-e6dd-4298-8ac9-8f810b581d4a','送孫逸歸廬山','劉長卿','唐','唐诗','tang','','["\u5e90\u5c71"]','鑪峰絕頂楚雲銜，楚客東歸棲此巖。',64,'全唐诗/poet.tang.7000.json','["鑪峰絕頂楚雲銜，楚客東歸棲此巖。", "彭蠡湖邊香橘柚，潯陽郭外暗楓杉。", "青山不斷三湘道，飛鳥空隨萬里帆。", "常愛此中多勝事，新詩他日佇開緘。"]'),
('3b83c38d-6c25-4245-8a61-5be739961c66','送馬秀才落第歸江南','劉長卿','唐','唐诗','tang','','[]','南客懷歸鄉夢頻，東門悵別柳條新。',64,'全唐诗/poet.tang.7000.json','["南客懷歸鄉夢頻，東門悵別柳條新。", "慇懃斗酒城陰暮，蕩漾孤舟楚水春。", "湘竹舊斑思帝子，江蘺初綠怨騷人。", "憐君此去未得意，陌上愁看淚滿巾。"]'),
('7c4e8dc8-3c7d-4397-a00f-dc7bb1dcc8f3','送常十九歸嵩少故林','劉長卿','唐','唐诗','tang','','[]','迢迢此恨杳無涯，楚澤嵩丘千里賒。',64,'全唐诗/poet.tang.7000.json','["迢迢此恨杳無涯，楚澤嵩丘千里賒。", "岐路別時驚一葉，雲林歸處憶三花。", "秋天蒼翠寒飛鴈，古堞蕭條晚噪鵶。", "他日山中逢勝事，桃源洞裏幾人家。"]'),
('07ff7d73-e7dd-4f9d-a422-68f21b8af488','送宇文遷明府赴洪州張觀察追攝豐城令','劉長卿','唐','唐诗','tang','','[]','送君不復遠爲心，余亦扁舟湘水陰。',64,'全唐诗/poet.tang.7000.json','["送君不復遠爲心，余亦扁舟湘水陰。", "路逐山光何處盡，春隨草色向南深。", "陳蕃待客應懸榻，宓賤之官獨抱琴。", "儻見主人論謫宦，爾來空有白頭吟。"]'),
('8b587cf7-7828-4c9f-8397-fdd063f62117','送李將軍','劉長卿','唐','唐诗','tang','','[]','征西諸將一如君，報德誰能不顧勳。',64,'全唐诗/poet.tang.7000.json','["征西諸將一如君，報德誰能不顧勳。", "身逐塞鴻來萬里，手披荒草看孤墳。", "擒生絕漠經胡雪，懷舊長沙哭楚雲。", "歸去蕭條灞陵上，幾人看葬李將軍。"]'),
('5d7deeb8-5c1a-4287-a752-6448e133c82e','西陵寄一上人','劉長卿','唐','唐诗','tang','','[]','東山訪道成開士，南渡隋陽作本師。',64,'全唐诗/poet.tang.7000.json','["東山訪道成開士，南渡隋陽作本師。", "了義惠心能善誘，吳風越俗罷淫祠。", "室中時見天人命，物外長懸海嶽期。", "多謝清言異玄度，懸河高論有誰持。"]'),
('41d292d2-b752-4c30-8b6b-7b7380f2f9bd','賦得','劉長卿','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e03\u8a00\u5f8b\u8bd7", "\u6625\u5929", "\u5987\u5973", "\u5510\u8bd7\u4e09\u767e\u9996", "\u95fa\u6028"]','鶯啼燕語報新年，馬邑龍堆路幾千。',66,'全唐诗/poet.tang.7000.json','["鶯啼燕語報新年，馬邑龍堆路幾千。", "家住層城臨漢苑，[心]隨明月到胡天。", "機中錦字論長恨，樓上花枝笑獨眠。", "爲問元戎竇車騎，何時返斾勒燕然。"]'),
('e07c10e1-d8dc-4873-90a2-c1541adafc97','三月李明府後亭泛舟','劉長卿','唐','唐诗','tang','','[]','江南風景復如何，聞道新亭更欲過。',64,'全唐诗/poet.tang.7000.json','["江南風景復如何，聞道新亭更欲過。", "處處紉蘭春浦淥，萋萋籍草遠山多。", "壺觴須就陶彭澤，時俗猶傳晉永和。", "更待持橈徐轉去，微風落日水增波。"]'),
('c8bfa420-dc17-443a-bd6a-16e605824344','喜朱拾遺承恩拜命赴任上都','劉長卿','唐','唐诗','tang','','[]','詔書徵拜脫荷裳，身去東山閉草堂。',64,'全唐诗/poet.tang.7000.json','["詔書徵拜脫荷裳，身去東山閉草堂。", "閶闔九天通奏籍，華亭一鶴在朝行。", "滄洲離別風煙遠，青瑣幽深漏刻長。", "今日却迴垂釣處，海鷗相見已高翔。"]'),
('99398e91-1389-4bb1-9590-0469377bf33d','鄖上送韋司士歸上都舊業','劉長卿','唐','唐诗','tang','','[]','前朝舊業想遺塵，今日他鄉獨爾身。',64,'全唐诗/poet.tang.7000.json','["前朝舊業想遺塵，今日他鄉獨爾身。", "鄖地國除爲過客，杜陵家在有何人。", "蒼苔白露生三徑，古木寒蟬滿四鄰。", "西去茫茫問歸路，關河漸近淚盈巾。"]'),
('b6411113-bf90-4d8e-8fe8-ead16b7dd596','感懷','劉長卿','唐','唐诗','tang','','[]','秋風落葉正堪悲，黃菊殘花欲待誰。',64,'全唐诗/poet.tang.7000.json','["秋風落葉正堪悲，黃菊殘花欲待誰。", "水近偏逢寒氣早，山深常見日光遲。", "愁中卜命看周易，夢裏招魂讀楚詞。", "自笑不如湘浦鴈，飛來即是北歸時。"]'),
('1f7c1127-a645-49fa-9c54-e3434b7fb7b1','送楊於陵歸宋汴州別業','劉長卿','唐','唐诗','tang','','[]','半山溪雨帶斜暉，向水殘花映客衣。',64,'全唐诗/poet.tang.7000.json','["半山溪雨帶斜暉，向水殘花映客衣。", "旅食嗟余當歲晚，能文似汝少年稀。", "新河柳色千株暗，故國雲帆萬里歸。", "離亂要知君到處，寄書須及鴈南飛。"]'),
('5945c40b-69ab-4925-ad01-a1ebb37ef3ea','送崔使君赴壽州','劉長卿','唐','唐诗','tang','','[]','列郡專城分國憂，彤幨皂蓋古諸侯。',64,'全唐诗/poet.tang.7000.json','["列郡專城分國憂，彤幨皂蓋古諸侯。", "仲華遇主年猶少，公瑾論功位已酬。", "草色青青迎建隼，蟬聲處處雜鳴騶。", "千里相思如可見，淮南木葉正驚秋。"]'),
('cf3d96af-0a99-456a-966e-00bef5d97a6a','上陽宮望幸','劉長卿','唐','唐诗','tang','','[]','玉輦西巡久未還，春光猶入上陽間。',64,'全唐诗/poet.tang.7000.json','["玉輦西巡久未還，春光猶入上陽間。", "萬木長承新雨露，千門空對舊河山。", "深花寂寂宮城閉，細草青青御路閑。", "獨見彩雲飛不盡，只應來去候龍顏。"]'),
('2cc266d3-a598-4ead-8436-e2699bde4885','過裴舍人故居','劉長卿','唐','唐诗','tang','','[]','慘慘天寒獨掩扃，紛紛黃葉滿空庭。',64,'全唐诗/poet.tang.7000.json','["慘慘天寒獨掩扃，紛紛黃葉滿空庭。", "孤墳何處依山木，百口無家學水萍。", "籬花猶及重陽發，鄰笛那堪落日聽。", "書幌無人長不捲，秋來芳草自爲螢。"]'),
('b2bc9e19-d45c-49f5-be3e-de49b001df76','登松江驛樓北望故園','劉長卿','唐','唐诗','tang','','[]','淚盡江樓北望歸，田園已陷百重圍。',64,'全唐诗/poet.tang.7000.json','["淚盡江樓北望歸，田園已陷百重圍。", "平蕪萬里無人去，落日千山空鳥飛。", "孤舟漾漾寒潮小，極浦蒼蒼遠樹微。", "白鷗漁父徒相待，未掃欃槍嬾息機。"]'),
('0f6b1aa1-f00b-4901-91cd-d55a1ede6337','秋夜有懷高三十五適兼呈空上人','劉長卿','唐','唐诗','tang','','[]','晚節逢君趣道深，結茅栽樹近東林。',64,'全唐诗/poet.tang.7000.json','["晚節逢君趣道深，結茅栽樹近東林。", "吾師幾度曾摩頂，高士何年遂發心。", "北渚三更聞過鴈，西城萬里動寒砧。", "不見支公與玄度，相思擁膝坐長吟。"]'),
('4ea1c468-eee0-401e-8303-68f5bc515e62','送孔巢父赴河南軍','劉長卿','唐','唐诗','tang','','[]','江南相送隔煙波，況復新秋一鴈過。',64,'全唐诗/poet.tang.7000.json','["江南相送隔煙波，況復新秋一鴈過。", "聞道全軍征北虜，又言詩將會南河。", "邊心冉冉鄉人絕，寒色青青戰馬多。", "共許陳琳工奏記，知君名行未蹉跎。"]'),
('9878f498-8dff-41c1-872f-8ae5af36dbcf','登潤州萬歲樓','劉長卿','唐','唐诗','tang','','[]','高樓獨上思依依，極浦遙山合翠微。',64,'全唐诗/poet.tang.7000.json','["高樓獨上思依依，極浦遙山合翠微。", "江客不堪頻北望，寒鴻何事又南飛。", "垂山古渡寒煙積，瓜步空洲遠樹稀。", "聞道王師猶轉戰，更能談笑解重圍。"]'),
('bc5b8457-08db-481c-b004-43e0a1adf3df','江樓送太康郭主簿赴嶺南','劉長卿','唐','唐诗','tang','','[]','對酒憐君安可論，當官愛士如平原。',96,'全唐诗/poet.tang.7000.json','["對酒憐君安可論，當官愛士如平原。", "料錢用盡却爲謗，食客空多誰報恩。", "萬里孤舟向南越，蒼梧雲中暮帆滅。", "樹色應無江北秋，天涯尚見淮陽月。", "驛路南隨桂水流，猨聲不絕到炎州。", "青山落日那堪望，誰見思君江上樓。"]'),
('2562544c-5ab9-47f4-aa34-f4a8038cb2fa','客舍喜鄭三見寄','劉長卿','唐','唐诗','tang','','[]','客舍逢君未換衣，閉門愁見桃花飛。',96,'全唐诗/poet.tang.7000.json','["客舍逢君未換衣，閉門愁見桃花飛。", "遙想故園今已爾，家人應念行人歸。", "寂寞垂楊映深曲，長安日暮靈臺宿。", "窮巷無人鳥雀閑，空庭新雨莓苔綠。", "北中分與故交疎，何幸仍迴長者車。", "十年未稱平生意，好得辛勤謾讀書。"]'),
('e8d3e30d-97a9-48e3-a6c8-47a6e581d379','送賈三北遊','劉長卿','唐','唐诗','tang','','[]','賈生未達猶窘迫，身馳匹馬邯鄲陌。',96,'全唐诗/poet.tang.7000.json','["賈生未達猶窘迫，身馳匹馬邯鄲陌。", "片雲郊外遙送人，斗酒城邊暮留客。", "顧予他日仰時髦，不堪此別相思勞。", "雨色新添漳水綠，夕陽遠照蘇門高。", "把袂相看衣共緇，窮愁只是惜良時。", "亦知到處逢下榻，莫滯秋風西上期。"]'),
('24ab90a9-bba5-40f3-b16c-1f0ab0f55278','齊一和尚影堂','劉長卿','唐','唐诗','tang','','[]','一公住世忘世紛，暫來復去誰能分。',128,'全唐诗/poet.tang.7000.json','["一公住世忘世紛，暫來復去誰能分。", "身寄虛空如過客，心將生滅是浮雲。", "蕭散浮雲往不還，淒涼遺教歿仍傳。", "舊地愁看雙樹在，空堂只是一燈懸。", "一燈長照恆河沙，雙樹猶落諸天花。", "天花寂寂香深殿，苔蘚蒼蒼閟虛院。", "昔余精念訪禪扉，常接微言清道機。", "今來寂寞無所得，唯共門人淚滿衣。"]'),
('ab2a6dc6-6806-4667-8fe5-032dae7c481e','潁川留別司倉李萬','劉長卿','唐','唐诗','tang','','[]','故人早負干將器，誰言未展平生意。',128,'全唐诗/poet.tang.7000.json','["故人早負干將器，誰言未展平生意。", "想君疇昔高步時，肯料如今折腰事。", "且知投刃皆若虛，日揮案牘常有餘。", "槐暗公庭趨小吏，荷香陂水膾鱸魚。", "客裏相逢款話深，如何岐路剩霑襟。", "白雲西上催歸念，潁水東流是別心。", "落日征驂隨去塵，含情揮手背城闉。", "已恨良時空此別，不堪秋草更愁人。"]'),
('9e81b01a-81f5-42bd-8dba-9382999257b5','聽笛歌','劉長卿','唐','唐诗','tang','','[]','舊遊憐我長沙謫，載酒沙頭送遷客。',128,'全唐诗/poet.tang.7000.json','["舊遊憐我長沙謫，載酒沙頭送遷客。", "天涯望月自霑衣，江上何人復吹笛。", "橫笛能令孤客愁，淥波淡淡如不流。", "商聲寥亮羽聲苦，江天寂歷江楓秋。", "靜聽關山聞一叫，三湘月色悲猨嘯。", "又吹楊柳激繁音，千里春色傷人心。", "隨風飄向何處落，唯見曲盡平湖深。", "明發與君離別後，馬上一聲堪白首。"]'),
('1b4b3d8a-b7a0-4d97-af64-a68b4514b2be','時平後送范倫歸安州','劉長卿','唐','唐诗','tang','','[]','昨聞戰罷圖麟閣，破虜收兵卷戎幕。',176,'全唐诗/poet.tang.7000.json','["昨聞戰罷圖麟閣，破虜收兵卷戎幕。", "滄海初看漢月明，紫微已見胡星落。", "憶昔扁舟此南渡，荆棘煙塵滿歸路。", "與君攜手姑蘇臺，望鄉一日登幾迴。", "白雲飛鳥去寂寞，吳山楚岫空崔嵬。", "事往時平還舊丘，青青春草近家愁。", "洛陽舉目今誰在，潁水無情應自流。", "吳苑西人去欲稀，留連一日空知非。", "江潭歲盡愁不盡，鴻鴈春歸身未歸。", "萬里遙懸帝鄉憶，五年空帶風塵色。", "却到長安逢故人，不道姓名應不識。"]'),
('45bc67b6-c251-4afb-b3ac-931fc35cc499','小鳥篇上裴尹','劉長卿','唐','唐诗','tang','','[]','藩籬小鳥何甚微，翩翩日夕空此飛。',176,'全唐诗/poet.tang.7000.json','["藩籬小鳥何甚微，翩翩日夕空此飛。", "只緣六翮不自致，長似孤雲無所依。", "西城黯黯斜暉落，衆鳥紛紛皆有託。", "獨立雖輕燕雀羣，孤飛遠懼鷹鸇搏。", "自憐天上青雲路，弔影徘徊獨愁暮。", "銜花縱有報恩時，擇木誰容托身處。", "歲月蹉跎飛不進，羽毛鷦顇何人問。", "遶樹空隨烏鵲驚，巢林只有鷦鷯分。", "主人庭中蔭喬木，愛此清陰欲棲宿。", "少年挾彈遙相猜，遂使驚飛往復迴。", "不辭奮翼向君去，唯怕金丸隨後來。"]'),
('d9982930-a653-46df-9fe4-1d007f9c0f3e','登吳古城歌','劉長卿','唐','唐诗','tang','','[]','登古城兮思古人，感賢達兮同埃塵。',176,'全唐诗/poet.tang.7000.json','["登古城兮思古人，感賢達兮同埃塵。", "望平原兮寄遠目，歎姑蘇兮聚麋鹿。", "黃池高會事未終，滄海橫流人蕩覆。", "伍員殺身誰不冤，竟看墓樹如所言。", "越王嘗膽安可敵，遠取石田何所益。", "一朝空謝會稽人，萬古猶傷甬東客。", "黍離離兮城坡坨，牛羊踐兮牧豎歌。", "野無人兮秋草綠，園爲墟兮古木多。", "白楊蕭蕭悲故柯，黃雀啾啾爭晚禾。", "荒阡斷兮誰重過，孤舟逝兮愁若何。", "天寒日暮江楓落，葉去辭風水自波。"]'),
('43fbf223-5b50-4248-b7d2-3087b1c75909','疲兵篇','劉長卿','唐','唐诗','tang','','[]','驕虜乘秋下薊門，陰山日夕煙塵昏。',224,'全唐诗/poet.tang.7000.json','["驕虜乘秋下薊門，陰山日夕煙塵昏。", "三軍疲馬力已盡，百戰殘兵功未論。", "陣雲泱漭屯塞北，羽書紛紛來不息。", "孤城望處增斷腸，折劍看時可霑臆。", "元戎日夕且歌舞，不念關山久辛苦。", "自矜倚劍氣凌雲，却笑聞笳淚如雨。", "萬里飄颻空此身，十年征戰老胡塵。", "赤心報國無片賞，白首還家有幾人。", "朔風蕭蕭動枯草，旌旗獵獵榆關道。", "漢月何曾照客心，胡笳只解催人老。", "軍前仍欲破重圍，閨裏猶應愁未歸。", "小婦十年啼夜織，行人九月憶寒衣。", "飲馬滹河晚更清，行吹羗笛遠歸營。", "只恨漢家多苦戰，徒遺金鏃滿長城。"]'),
('e558a7b7-7fd0-4b33-97e5-8bf2a9f37bd2','新安送陸[澧]歸江陰','劉長卿','唐','唐诗','tang','','[]','新安路，人來去。',36,'全唐诗/poet.tang.7000.json','["新安路，人來去。", "早潮復晚潮，明日知何處。", "潮水無情亦解歸，自憐長在新安住。"]'),
('abb9a70e-157d-443b-b978-cc723b5786b0','弄白鷗歌','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','泛泛江上鷗，毛衣皓如雪。',38,'全唐诗/poet.tang.7000.json','["泛泛江上鷗，毛衣皓如雪。", "朝飛瀟湘水，夜宿洞庭月。", "歸客正夷猶，愛此滄江閑白鷗。"]'),
('aca36692-0e5b-444f-9abc-3b1a1916b2dc','長沙贈衡岳祝融峰般若禪師','劉長卿','唐','唐诗','tang','','[]','般若公，般若公，負鉢何時下祝融。',48,'全唐诗/poet.tang.7000.json','["般若公，般若公，負鉢何時下祝融。", "歸路却看飛鳥外，禪房空掩白雲中。", "桂花寥寥閑自落，流水無心西復東。"]'),
('39b5c07e-de40-4cfa-ab6f-03e2e361b3f6','贈湘南漁父','劉長卿','唐','唐诗','tang','','[]','聞君何所適，暮暮逢煙水。',68,'全唐诗/poet.tang.7000.json','["聞君何所適，暮暮逢煙水。", "獨與不繫舟，往來楚雲裏。", "釣魚非一歲，終日只如此。", "日落江清桂檝遲，纖鱗百尺深可窺。", "沈鉤垂餌不在得，白首滄浪空自知。"]'),
('e4714311-5f29-4d71-9013-2e3bc1167142','明月灣尋賀九不遇','劉長卿','唐','唐诗','tang','','[]','楚水日夜綠，傍江春草滋。',56,'全唐诗/poet.tang.7000.json','["楚水日夜綠，傍江春草滋。", "青青遙滿目，萬里傷心歸。", "故人川上復何之，明月灣南空所思。", "故人不在明月在，誰見孤舟來去時。"]'),
('0735f62f-1da0-4fad-988a-16b031265468','題曲阿三昧王佛殿前孤石','劉長卿','唐','唐诗','tang','','[]','孤石自何處，對之疑舊遊。',56,'全唐诗/poet.tang.7000.json','["孤石自何處，對之疑舊遊。", "氛氳峴首夕，蒼翠剡中秋。", "迥出羣峰當殿前，雪山靈鷲慙貞堅。", "一片孤雲長不去，莓苔古色空蒼然。"]'),
('32854806-3d64-426b-a1f1-1d461e19503e','送友人東歸','劉長卿','唐','唐诗','tang','','[]','對酒灞亭暮，相看愁自深。',56,'全唐诗/poet.tang.7000.json','["對酒灞亭暮，相看愁自深。", "河邊草已綠，此別難爲心。", "關路迢迢匹馬歸，垂楊寂寂數鶯飛。", "憐君獻策十餘載，今日猶爲一布衣。"]'),
('57f94ccb-ffbe-4a70-b0e1-388a7100a468','入桂渚次砂牛石穴','劉長卿','唐','唐诗','tang','','[]','扁舟傍歸路，日暮瀟湘深。',68,'全唐诗/poet.tang.7000.json','["扁舟傍歸路，日暮瀟湘深。", "湘水清見底，楚雲淡無心。", "片帆落桂渚，獨夜依楓林。", "楓林月出猨聲苦，桂渚天寒桂花吐。", "此中無處不堪愁，江客相看淚如雨。"]'),
('c8554bd4-482b-4d28-b579-d2d5a6a4c530','嚴陵釣臺送李康成赴江東使','劉長卿','唐','唐诗','tang','','[]','潺湲子陵瀨，髣髴如在目。',88,'全唐诗/poet.tang.7000.json','["潺湲子陵瀨，髣髴如在目。", "七里人已非，千年水空綠。", "新安江上孤帆遠，應逐楓林萬餘轉。", "古臺落日共蕭條，寒水無波更清淺。", "臺上漁竿不復持，却令猨鳥向人悲。", "灘聲山翠至今在，遲爾行舟晚泊時。"]'),
('6eaa9ab7-0a57-41a1-9db9-c59a8fb4af94','送姨子弟往南郊','劉長卿','唐','唐诗','tang','','[]','一展慰久闊，寸心仍未伸。',96,'全唐诗/poet.tang.7000.json','["一展慰久闊，寸心仍未伸。", "別時兩童稚，及此俱成人。", "那堪適會面，遽已悲分首。", "客路向楚雲，河橋對衰柳。", "送君匹馬別河橋，汝南山郭寒蕭條。", "今我單車復西上，郎去灞陵轉惆悵。", "何處共傷離別心，明月亭亭兩鄉望。"]'),
('94fc48c7-b281-4472-bf6b-31e3134a4bd0','銅雀臺','劉長卿','唐','唐诗','tang','','[]','嬌愛更何日，高臺空數層。',109,'全唐诗/poet.tang.7000.json','["嬌愛更何日，高臺空數層。", "含啼映雙袖，不忍看西陵。", "漳河東流無復來，百花輦路爲蒼苔。", "[青]樓月夜長寂寞，碧雲日暮空徘徊。", "君不見鄴中萬事非昔時，古人不在今人悲。", "春風不逐君王去，草色年年舊宮路。", "宮中歌舞已浮雲，空指行人往來處。"]'),
('370f10de-cf10-42b7-a058-aab0a42817eb','王昭君歌','劉長卿','唐','唐诗','tang','','["\u9ec4\u6cb3"]','自矜嬌豔色，不顧丹青人。',108,'全唐诗/poet.tang.7000.json','["自矜嬌豔色，不顧丹青人。", "那知粉繪能相負，却使容華翻誤身。", "上馬辭君嫁驕虜，玉顏對人啼不語。", "北風鴈急浮雲秋，萬里獨見黃河流。", "纖腰不復漢宮寵，雙蛾長向胡天愁。", "琵琶弦中苦調多，蕭蕭羌笛聲相和。", "誰憐一曲傳樂府，能使千秋傷綺羅。"]'),
('fed45702-6381-4819-bbfb-282184753777','送杜越江佐覲省往新安江','劉長卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','去帆楚天外，望遠愁復積。',104,'全唐诗/poet.tang.7000.json','["去帆楚天外，望遠愁復積。", "想見新安江，扁舟一行客。", "清流數千丈，底下看白石。", "色混元氣深，波連洞庭碧。", "鳴桹去未已，前路行可覿。", "猨鳥悲啾啾，杉松雨聲夕。", "送君東赴歸寧期，新安江水遠相隨。", "見說江中孤嶼在，此行應賦謝公詩。"]'),
('e5f81c89-f23d-4079-bf05-c2be5b20fca1','湘中憶歸','劉長卿','唐','唐诗','tang','','[]','終日空理棹，經年猶別家。',104,'全唐诗/poet.tang.7000.json','["終日空理棹，經年猶別家。", "頃來行已遠，彌覺天無涯。", "白雲意自深，滄海夢難隔。", "迢遞萬里帆，飄颻一行客。", "獨憐西江外，遠寄風波裏。", "平湖流楚天，孤鴈渡湘水。", "湘流澹澹空愁予，猨啼啾啾滿南楚。", "扁舟泊處聞此聲，江客相看淚如雨。"]'),
('b3cb1b34-5cbf-4975-8f20-6ed06da1b491','送郭六侍從之武陵郡','劉長卿','唐','唐诗','tang','','[]','常愛武陵郡，羨君將遠尋。',120,'全唐诗/poet.tang.7000.json','["常愛武陵郡，羨君將遠尋。", "空憐世界迫，孤負桃源心。", "洛陽遙想桃源隔，野水閑流春自碧。", "花下常迷楚客船，洞中時見秦人宅。", "落日相看斗酒前，送君南望但依然。", "河梁馬首隨春草，江路猨聲愁暮天。", "丈人別乘佐分憂，才子趨庭兼勝遊。", "澧浦荆門行可見，知君詩興滿滄洲。"]'),
('e55e7eb2-5814-4a6f-9293-695f6520a538','山鸜鵒歌','劉長卿','唐','唐诗','tang','','[]','山鸜鵒，長在此山吟古木。',132,'全唐诗/poet.tang.7000.json','["山鸜鵒，長在此山吟古木。", "嘲唽相呼響空谷，哀鳴萬變如成曲。", "江南逐臣悲放逐，倚樹聽之心斷續。", "巴人峽裏自聞猨，燕客水頭空擊筑。", "山鸜鵒，一生不及雙黃鵠。", "朝去秋田啄殘粟，暮入寒林嘯羣族。", "鳴相逐，啄殘粟，食不足。", "青雲杳杳無力飛，白露蒼蒼抱枝宿。", "不知何事守空山，萬壑千峰自愁獨。"]'),
('2e6a2d0d-7127-4871-a8e6-779d87d6454b','望龍山懷道士許法稜','劉長卿','唐','唐诗','tang','','[]','心惆悵，望龍山。',136,'全唐诗/poet.tang.7000.json','["心惆悵，望龍山。", "雲之際，鳥獨還。", "懸崖絕壁幾千丈，綠蘿嫋嫋不可攀。", "龍山高，誰能踐。", "靈原中，蒼翠晚。", "嵐煙瀑水如向人，終日迢迢空在眼。", "中有一人披霓裳，誦經山頂飧瓊漿。", "空林閑坐獨焚香，真官列侍儼成行。", "朝入青霄禮玉堂，夜掃白雲眠石牀。", "桃花洞裏居人滿，桂樹山中住日長，龍山高高遙相望。"]'),
('8438bae5-696d-403e-a24d-0ab37248db5e','戲贈干越尼子歌','劉長卿','唐','唐诗','tang','','[]','鄱陽女子年十五，家本秦人今在楚。',192,'全唐诗/poet.tang.7000.json','["鄱陽女子年十五，家本秦人今在楚。", "厭向春江空浣沙，龍宮落髮披袈裟。", "五年持戒長一食，至今猶自顏如花。", "亭亭獨立青蓮下，忍草禪枝繞精舍。", "自用黃金買地居，能嫌碧玉隨人嫁。", "北客相逢疑姓秦，鉛花拋却仍青春。", "一花一竹如有意，不語不笑能留人。", "黃鸝欲棲白日暮，天香未散經行處。", "却對香爐閑誦經，春泉漱玉寒泠泠。", "雲房寂寂夜鐘後，吳音清切令人聽。", "人聽吳音歌一曲，杳然如在諸天宿。", "誰堪世事更相牽，惆悵迴船江水淥。"]'),
('04d9c24f-f6f8-4687-9766-75a5274b9292','游四窗','劉長卿','唐','唐诗','tang','','[]','四明山絕奇，自古說登陸。',108,'全唐诗/poet.tang.7000.json','["四明山絕奇，自古說登陸。", "蒼崖倚天立，覆石如覆屋。", "玲瓏開戶牖，落落明四目。", "箕星分南野，有斗挂簷北。", "日月居東西，朝昏互出沒。", "我來游其間，寄傲巾半幅。", "白雲本無心，悠然伴幽獨。", "對此脫塵鞅，頓忘榮與辱。", "長笑天地寬，仙風吹佩玉。"]'),
('815159c5-8a9a-4668-b05f-b48b2033876e','和中丞出使恩命過終南別業','劉長卿','唐','唐诗','tang','','[]','不過林園久，多因寵遇偏。',74,'全唐诗/poet.tang.7000.json','["不過林園久，多因寵遇偏。", "故山長寂寂，春草過年年。", "花待朝衣間，雲迎驛騎連。", "松蘿深舊閤，樵木散閑田。", "拜闕貪搖珮，看琴懶更弦。", "君恩催早入，已夢[傅]巖邊。"]'),
('33f5625a-ef7b-48bd-99fe-2bbb5d416c9f','岳陽樓','劉長卿','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','行盡清溪日已蹉，雲容山影兩嵯峨。',64,'全唐诗/poet.tang.7000.json','["行盡清溪日已蹉，雲容山影兩嵯峨。", "樓前歸客怨秋夢，湖上美人疑夜歌。", "獨坐高高風勢急，平湖渺渺月明多。", "終期一艇載樵去，來往片帆愁白波。"]'),
('83581f16-b9b7-4586-b001-1642edcf2db3','春望寄王涔陽','劉長卿','唐','唐诗','tang','','[]','清明別後雨晴時，極浦空顰一望眉。',64,'全唐诗/poet.tang.7000.json','["清明別後雨晴時，極浦空顰一望眉。", "湖畔春山煙點點，雲中遠樹墨離離。", "依微水戍聞鉦鼓，掩映沙村見酒旗。", "風煖草長愁自醉，行吟無處寄相思。"]'),
('ae4ea64b-635e-4857-94eb-ea37d612dc7f','留辭','劉長卿','唐','唐诗','tang','','[]','南楚迢迢通漢口，西江淼淼去揚州。',32,'全唐诗/poet.tang.7000.json','["南楚迢迢通漢口，西江淼淼去揚州。", "春風已遣歸心促，縱復芳菲不可留。"]'),
('531c8893-705d-4365-8c15-266806af5b87','題杼山癸亭得暮字','顏真卿','唐','唐诗','tang','','[]','杼山多幽絕，勝事盈跬步。',132,'全唐诗/poet.tang.7000.json','["杼山多幽絕，勝事盈跬步。", "前者雖登攀，淹留恨晨暮。", "及茲紆勝引，曾是美無度。", "歘構三癸亭，實爲陸生故。", "高賢能剏物，疏鑿皆有趣。", "不越方丈間，居然雲霄遇。", "巍峨倚脩岫，曠望臨古渡。", "左右苔石攢，低昂桂枝蠹。", "山僧狎猨狖，巢鳥來枳椇。", "俯視何楷臺，傍瞻戴顒路。", "遲迴未能下，夕照明村樹。"]'),
('9807035e-5bcc-4180-a831-9f8f17ca0589','謝陸處士杼山折青桂花見寄之什','顏真卿','唐','唐诗','tang','','[]','羣子遊杼山，山寒桂花白。',60,'全唐诗/poet.tang.7000.json','["羣子遊杼山，山寒桂花白。", "綠荑含素蕚，采折自逋客。", "忽枉巖中詩，芳香潤金石。", "全高南越蠹，豈謝東堂策。", "會愜名山期，從君恣幽覿。"]'),
('1f4741cd-b7ee-4d1f-aa46-330d1fdb3de9','贈裴將軍','顏真卿','唐','唐诗','tang','','[]','大君制六合，猛將清九垓。',108,'全唐诗/poet.tang.7000.json','["大君制六合，猛將清九垓。", "戰馬若龍虎，騰凌何壯哉。", "將軍臨八荒，烜赫耀英材。", "劒舞若游電，隨風縈且迴。", "登高望天山，白雲正崔巍。", "入陣破驕虜，威名雄震雷。", "一射百馬倒，再射萬夫開。", "匈奴不敢敵，相呼歸去來。", "功成報天子，可以畫麟臺。"]'),
('958f2bc8-62f2-4ab8-96e5-285dc93fb775','贈僧皎然','顏真卿','唐','唐诗','tang','','[]','秋意西山多，別岑縈左次。',132,'全唐诗/poet.tang.7000.json','["秋意西山多，別岑縈左次。", "繕亭歷三癸，趾趾鄰什寺。", "元化隱靈蹤，始君啓高致。", "誅榛養翹楚，鞭草理芳穗。", "俯砌披水容，逼天掃峰翠。", "境新耳目換，物遠風塵異。", "倚石忘世情，援雲得真意。", "嘉林幸勿剪，禪侶欣可庇。", "衛法大臣過，佐遊羣英萃。", "龍池護清激，虎節到深邃。", "徒想嵊頂期，于今沒遺記。"]'),
('e5c624f4-7c97-44ab-a244-0473f8ee277a','詠陶淵明','顏真卿','唐','唐诗','tang','','[]','張良思報韓，龔勝恥事新。',84,'全唐诗/poet.tang.7000.json','["張良思報韓，龔勝恥事新。", "狙擊不肯就，舍生悲縉紳。", "嗚呼陶淵明，奕葉爲晉臣。", "自以公相後，每懷宗國屯。", "題詩庚子歲，自謂羲皇人。", "手持山海經，頭戴漉酒巾。", "興逐孤雲外，心隨還鳥泯。"]'),
('49549441-a732-4154-a315-93be06c236ba','三言擬五雜組二首 一','顏真卿','唐','唐诗','tang','','[]','五雜組，繡與錦。',24,'全唐诗/poet.tang.7000.json','["五雜組，繡與錦。", "往復還，興又寢。", "不得已，病伏枕。"]'),
('9d9fc2bc-180d-4ddb-af8b-662b760d2a51','三言擬五雜組二首 二','顏真卿','唐','唐诗','tang','','[]','五雜組，甘鹹醋。',24,'全唐诗/poet.tang.7000.json','["五雜組，甘鹹醋。", "往復還，烏與兔。", "不得已，韶光度。"]'),
('8b842cbd-4e97-47ab-9823-19d3daba3add','使過瑤臺寺有懷圓寂上人','顏真卿','唐','唐诗','tang','','[]','上人居此寺，不出三十年。',48,'全唐诗/poet.tang.7000.json','["上人居此寺，不出三十年。", "萬法元無著，一心唯趣禪。", "忽紆塵外軫，遠訪區中緣。", "及爾不復見，支提猶岌然。"]'),
('9f3b97a9-7740-4508-ae92-ec4cdd1f0fd2','登平望橋下作','顏真卿','唐','唐诗','tang','','[]','登橋試長望，望極與天平。',48,'全唐诗/poet.tang.7000.json','["登橋試長望，望極與天平。", "際海蒹葭色，終朝鳧鴈聲。", "近山猶髣髴，遠水忽微明。", "更覽諸公作，知高題柱名。"]'),
('ff35f1c3-1423-40ce-9474-690d7a177fba','刻清遠道士詩因而繼作','顏真卿','唐','唐诗','tang','','[]','不到東西寺，于今五十春。',144,'全唐诗/poet.tang.7000.json','["不到東西寺，于今五十春。", "朅來從舊賞，林壑宛相親。", "吳子多藏日，秦王厭勝辰。", "劒池穿萬仞，盤石坐千人。", "金氣騰爲虎，琴臺化若神。", "登壇仰生一，捨宅歎珣珉。", "中嶺分雙樹，迴巒絕四鄰。", "窺臨江海接，崇飾四時新。", "客有神仙者，於茲雅麗陳。", "名高清遠峽，文聚斗牛津。", "跡異心寧間，聲同質豈均。", "悠然千載後，知我揖光塵。"]'),
('930b7864-749c-4dfb-bb67-d9362a5b127f','雜詩六首 一','李華','唐','唐诗','tang','','[]','黃鍾扣元音，律呂更循環。',60,'全唐诗/poet.tang.7000.json','["黃鍾扣元音，律呂更循環。", "邪氣悖正聲，鄭衛生其間。", "典樂忽涓微，波浪與天渾。", "嘈嘈鴟梟動，好鳥徒緜蠻。", "王吉歸鄉里，甘心長閉關。"]'),
('098954de-58f8-4d53-9ac6-68e96b4da5bc','雜詩六首 二','李華','唐','唐诗','tang','','[]','玄黃與丹青，五氣之正色。',60,'全唐诗/poet.tang.7000.json','["玄黃與丹青，五氣之正色。", "聖人端其源，上下皆有則。", "齊侯好紫衣，魏帝婦人飾。", "女奴厭金翠，傾海未滿臆。", "何忍嚴子陵，羊裘死荆棘。"]'),
('846e8c71-76a5-4b36-b956-dfd78de9fe52','雜詩六首 三','李華','唐','唐诗','tang','','[]','甘酸不私人，元和運五行。',84,'全唐诗/poet.tang.7000.json','["甘酸不私人，元和運五行。", "生人受其用，味正心亦平。", "爪牙相踐傷，日與性命爭。", "聖人不能絕，鑽燧與炮烹。", "嗜慾乘此熾，百金資一傾。", "正銷神耗衰，邪勝體充盈。", "顏子有餘樂，瓢中寒水清。"]'),
('514a3560-e3b3-4c53-9a81-7b43013e5b55','雜詩六首 四','李華','唐','唐诗','tang','','[]','陰魄淪宇宙，太陽假其明。',84,'全唐诗/poet.tang.7000.json','["陰魄淪宇宙，太陽假其明。", "臣道不敢專，由此見虧盈。", "未聞東菑稼，一氣嘉穀成。", "上天降寒暑，地利乃可生。", "葛藟附柔木，繁陰蔽曾原。", "風霜摧枝幹，不復庇本根。", "女蘿依松柏，然後得長存。"]'),
('bf1ac423-a541-4ae6-b229-3b668ca8933e','雜詩六首 五','李華','唐','唐诗','tang','','[]','孔光尊董賢，胡廣慚李固。',48,'全唐诗/poet.tang.7000.json','["孔光尊董賢，胡廣慚李固。", "儒風冠天下，而乃敗王度。", "絳侯與愽陸，忠朴受遺顧。", "求名不考實，文弊反成蠹。"]'),
('96d2e744-49f9-47c0-8e2a-98eb302c8010','雜詩六首 六','李華','唐','唐诗','tang','','[]','結交得書生，書生鈍且直。',84,'全唐诗/poet.tang.7000.json','["結交得書生，書生鈍且直。", "爭權復爭利，終不得其力。", "我逢縱橫者，是我牙與翼。", "相旋如疾風，竝命趨紫極。", "奔車得停軌，風火何相逼。", "仁義豈有常，肝膽反爲賊。", "勿嫌書生直，鈍直深可憶。"]'),
('bcd29f16-7699-416c-99c1-2889a86b1a08','詠史十一首 一','李華','唐','唐诗','tang','','[]','昂藏獬豸獸，出自太平年。',62,'全唐诗/poet.tang.7000.json','["昂藏獬豸獸，出自太平年。", "亂代乃潛伏，縱人爲禍愆。", "嘗聞斷馬劒，每壯朱雲賢。", "身死名不滅，寒風吹[墓]田。", "精靈如有在，幽憤滿松煙。"]'),
('7b6fc679-0c7d-4a0d-bb00-0f267cbb2024','詠史十一首 二','李華','唐','唐诗','tang','','[]','漢皇修雅樂，乘輿臨太學。',72,'全唐诗/poet.tang.7000.json','["漢皇修雅樂，乘輿臨太學。", "三老與五更，天王親割牲。", "一人調風俗，萬國和且平。", "單于驟款塞，武庫欲銷兵。", "文物此朝盛，君臣何穆清。", "至今壝壇下，如有簫韶聲。"]'),
('400e8b32-e77d-4aa8-a6d6-3cd536afe277','詠史十一首 三','李華','唐','唐诗','tang','','[]','巢許在嵩潁，陶唐不得臣。',84,'全唐诗/poet.tang.7000.json','["巢許在嵩潁，陶唐不得臣。", "九州尚洗耳，一命安能親。", "緜邈數千祀，丘中誰隱淪。", "朝遊公卿府，夕是山林人。", "蒲帛揚側陋，薜蘿爲縉紳。", "九重念入夢，三事思降神。", "且設庭中燎，寧窺泉下鱗。"]'),
('1096f49c-cb1f-4321-9e8e-e608f69bec0c','詠史十一首 四','李華','唐','唐诗','tang','','[]','漢時征百粵，楊僕將樓船。',84,'全唐诗/poet.tang.7000.json','["漢時征百粵，楊僕將樓船。", "幕府功未立，江湖已騷然。", "島夷非敢亂，政暴地仍偏。", "得罪因懷璧，防身輒控弦。", "三軍求裂土，萬里詎聞天。", "魏闕心猶在，旗門首已懸。", "如何得良吏，一爲制方圓。"]'),
('a1291a9d-45de-4f6b-b26d-df8c1a511ec6','詠史十一首 五','李華','唐','唐诗','tang','','[]','秦滅漢帝興，南山有遺老。',132,'全唐诗/poet.tang.7000.json','["秦滅漢帝興，南山有遺老。", "危冠揖萬乘，幸得厭征討。", "當君逐鹿時，臣等已枯槁。", "寧知市朝變，但覺林泉好。", "高臥三十年，相看成四皓。", "帝言翁甚善，見顧何不早。", "咸稱太子仁，重義亦尊道。", "側聞驪姬事，申生不自保。", "暫出商山雲，朅來趨灑掃。", "東宮成羽翼，楚舞傷懷抱。", "後代無其人，戾園滿秋草。"]'),
('7b07fa27-ac03-4a4a-a486-da0f236e280e','詠史十一首 六','李華','唐','唐诗','tang','','[]','日照崑崙上，羽人披羽衣。',84,'全唐诗/poet.tang.7000.json','["日照崑崙上，羽人披羽衣。", "乘龍駕雲霧，欲往心無違。", "此山在西北，乃是神仙國。", "靈氣皆自然，求之不可得。", "何爲漢武帝，精思徧羣山。", "糜費巨萬計，宮車終不還。", "蒼蒼茂陵樹，足以戒人間。"]'),
('849a2d8e-b5c7-4b47-a662-fef1f4590356','詠史十一首 七','李華','唐','唐诗','tang','','[]','天生忠與義，本以佐雍熙。',84,'全唐诗/poet.tang.7000.json','["天生忠與義，本以佐雍熙。", "何意李司隸，而當昏亂時。", "古墳襄城野，斜徑橫秋陂。", "況不禁樵采，茅莎無孑遺。", "高標尚可仰，精爽今何之。", "一忤中常侍，銜冤誰見知。", "嘗觀黨錮傳，撫卷不勝悲。"]'),
('3026d9c2-2490-4302-829d-42c98b7f6845','詠史十一首 八','李華','唐','唐诗','tang','','[]','文侯耽鄭衛，一聽一忘餐。',72,'全唐诗/poet.tang.7000.json','["文侯耽鄭衛，一聽一忘餐。", "白雪燕姬舞，朱弦趙女彈。", "淫聲流不返，慆蕩日無端。", "獻歲受朝時，鳴鐘讌百官。", "兩牀陳管磬，九奏殊未闌。", "對此唯恐臥，更能整衣冠。"]'),
('d6bd5abc-cb8e-4326-8418-169ea68a008c','詠史十一首 九','李華','唐','唐诗','tang','','[]','蜀主相諸葛，功高名亦尊。',72,'全唐诗/poet.tang.7000.json','["蜀主相諸葛，功高名亦尊。", "驅馳千萬衆，怒目瞰中原。", "曹伯任公孫，國亡身不存。", "社宮久蕪沒，白鴈猶飛翻。", "勿言君臣合，可以濟黎元。", "爲蜀諒不易，如曹難復論。"]'),
('bd96c6b2-8e1e-44c5-989a-d1e8eda25d86','詠史十一首 十','李華','唐','唐诗','tang','','[]','六國韓最弱，末年尤畏秦。',48,'全唐诗/poet.tang.7000.json','["六國韓最弱，末年尤畏秦。", "鄭生爲韓計，且欲疲秦人。", "利物可分社，原情堪滅身。", "咸陽古城下，萬頃稻苗新。"]'),
('9aa07344-86bd-4631-9cb9-70a506e52241','詠史十一首 十一','李華','唐','唐诗','tang','','[]','沂水春可涉，泮宮映楊葉。',156,'全唐诗/poet.tang.7000.json','["沂水春可涉，泮宮映楊葉。", "麗色異人間，珊珊搖珮環。", "展禽恆獨處，深巷生禾黍。", "城上飛海雲，城中暗春雨。", "適來鳴珮者，復是誰家女。", "泥沾珠綴履，雨濕翠毛簪。", "電影開蓮臉，雷聲飛蕙心。", "自言沂水曲，采萍兼采菉。", "歸逕雖可尋，天陰光景促。", "憐君貞且獨，願許君家宿。", "徒勞惜衾枕，了不顧雙蛾。", "豔質誠可重，淫風如禮何。", "周王惑襃姒，城闕成陂陁。"]'),
('b18dcf48-594b-4293-a324-ccd46562dae9','雲母泉詩','李華','唐','唐诗','tang','','["\u5e90\u5c71"]','晨登玄石嶺，嶺上寒松聲。',228,'全唐诗/poet.tang.7000.json','["晨登玄石嶺，嶺上寒松聲。", "朗日風雨霽，高秋天地清。", "山門開古寺，石竇含純精。", "洞徹淨金界，夤緣流玉英。", "澤藥滋畦茂，氣染茶甌馨。", "飲液盡眉壽，飡和皆體平。", "瓊漿駐容髮，甘露瑩心靈。", "岱谷謝巧妙，匡山徒有名。", "願言構蓬蓽，荷鍤引泠泠。", "訪道出人世，招賢依福庭。", "此心不能已，寤寐見吾兄。", "曾結潁陽契，窮年無所成。", "東西同放逐，蛇豕尚縱橫。", "江漢阻攜手，天涯萬里情。", "恩光起憔悴，西上謁承明。", "秋色變江樹，相思紛以盈。", "猨啼巴丘戍，月上武陵城。", "共恨川路永，無由會友生。", "雲泉不可忘，何日遂躬耕。"]'),
('4e898b27-d1ec-4ff1-95b8-0461e652b18a','寄趙七侍御','李華','唐','唐诗','tang','','[]','搖槳曙江流，江清山復重。',288,'全唐诗/poet.tang.7000.json','["搖槳曙江流，江清山復重。", "心愜賞未足，川迥失前峰。", "淩灘出極浦，曠若天池通。", "君陽青嵯峨，開拆混元中。", "九潭魚龍窟，仙成羽人宮。", "陰奧潛鬼物，精光動煙空。", "玄猨啼深蘢，白鳥戲葱蒙。", "飛湍鳴金石，激溜鼓雷風。", "雨濯萬木鮮，霞照千山濃。", "草閑長餘綠，花靜落幽紅。", "渚煙見晨釣，山月聞夜舂。", "覆溪窈窕波，涵石淘溶溶。", "丹丘忽聚散，素壁相奔衝。", "白日破昏靄，靈山出其東。", "勢排昊蒼上，氣壓吳越雄。", "迴頭望雲卿，此恨發吾衷。", "昔日蕭邵遊，四人纔成童。", "屬詞慕孔門，入仕希上公。", "緯卿陷非罪，折我昆吾鋒。", "茂挺獨先覺，拔身渡京虹。", "斯人謝明代，百代墜鵷鴻。", "世故墜橫流，與君哀路窮。", "相顧無死節，蒙恩逐殊封。", "天波洗其瑕，朱衣備朝容。"]'),
('69cda70d-9494-4392-b189-2cbb39e2ba69','仙遊寺','李華','唐','唐诗','tang','','[]','捨事入樵逕，雲木深谷口。',144,'全唐诗/poet.tang.7000.json','["捨事入樵逕，雲木深谷口。", "萬壑移晦明，千峰轉前後。", "嶷然龍潭上，石勢若奔走。", "開拆秋天光，崩騰夏雷吼。", "靈谿自茲去，紆直互紛糾。", "聽聲靜復喧，望色無更有。", "冥冥翠微下，高殿映杉柳。", "滴滴洞穴中，懸泉響相扣。", "昔時秦王女，羽化年代久。", "日暮松風來，簫聲生左右。", "早窺神仙籙，願結芝朮友。", "安得羨門方，青囊繫吾肘。"]'),
('de5c1eb6-0200-41ee-8db9-cf66ffde46bb','春遊吟','李華','唐','唐诗','tang','','[]','初春遍芳甸，千里藹盈矚。',52,'全唐诗/poet.tang.7000.json','["初春遍芳甸，千里藹盈矚。", "美人摘新英，步步翫春綠。", "所思杳何處，宛在吳江曲。", "可憐不得共芳菲，日暮歸來淚滿衣。"]'),
('179a6adb-d7a7-48c7-a629-98f6fc151235','長門怨','李華','唐','唐诗','tang','','[]','弱體鴛鴦薦，啼妝翡翠衾。',48,'全唐诗/poet.tang.7000.json','["弱體鴛鴦薦，啼妝翡翠衾。", "鴉鳴秋殿曉，人靜禁門深。", "每憶椒房寵，那堪永巷陰。", "自驚羅帶緩，非復舊來心。"]'),
('9c338f61-1381-4fb0-be26-3973b70c3065','奉使朔方贈郭都護','李華','唐','唐诗','tang','','[]','絕塞臨光祿，孤營佐貳師。',48,'全唐诗/poet.tang.7000.json','["絕塞臨光祿，孤營佐貳師。", "鐵衣山月冷，金鼓朔風悲。", "都護徵兵日，將軍破虜時。", "揚鞭玉關道，回首望旌旗。"]'),
('cddacbb0-624e-498c-b134-e2260dfc45d6','尚書都堂瓦松','李華','唐','唐诗','tang','','[]','華省祕仙蹤，高堂露瓦松。',72,'全唐诗/poet.tang.7000.json','["華省祕仙蹤，高堂露瓦松。", "葉因春後長，花爲雨來濃。", "影混鴛鴦色，光含翡翠容。", "天然斯所寄，地勢太無從。", "接棟臨雙闕，連甍近九重。", "寧知深澗底，霜雪歲兼封。"]'),
('c8810763-ae84-41aa-9dd7-fff0f5081624','海上生明月','李華','唐','唐诗','tang','','[]','皎皎秋中月，團團海上生。',72,'全唐诗/poet.tang.7000.json','["皎皎秋中月，團團海上生。", "影開金鏡滿，輪抱玉壺清。", "漸出三山岊，將凌一漢橫。", "素娥嘗藥去，烏鵲遶枝驚。", "照水光偏白，浮雲色最明。", "此時堯砌下，蓂莢自將榮。"]'),
('c320cbaa-89ab-4ef7-8096-9e736a8347f8','晚日湖上寄所思','李華','唐','唐诗','tang','','[]','與君爲近別，不啻遠相思。',24,'全唐诗/poet.tang.7000.json','["與君爲近別，不啻遠相思。", "落日平湖上，看山對此時。"]'),
('f010433e-6ddd-4be5-a98b-4119038bb7df','寄從弟','李華','唐','唐诗','tang','','[]','眼病身亦病，浮生已半空。',24,'全唐诗/poet.tang.7000.json','["眼病身亦病，浮生已半空。", "迢迢千里月，應與惠連同。"]'),
('020e67e0-f7b4-4f36-8277-004b92ea77af','奉寄彭城公','李華','唐','唐诗','tang','','[]','公子三千客，人人願報恩。',24,'全唐诗/poet.tang.7000.json','["公子三千客，人人願報恩。", "應憐抱關者，貧病老夷門。"]'),
('fed8f172-406c-40a5-ae5d-0b1c2290eca6','春行寄興','李華','唐','唐诗','tang','','["\u6625\u5929", "\u611f\u4f24", "\u5199\u666f"]','宜陽城下草萋萋，澗水東流復向西。',32,'全唐诗/poet.tang.7000.json','["宜陽城下草萋萋，澗水東流復向西。", "芳樹無人花自落，春山一路鳥空啼。"]'),
('94d61054-d280-46a9-8894-bf068aa0a900','江有楓一篇十章 一','蕭穎士','唐','唐诗','tang','','[]','江有楓，其葉蒙蒙。',19,'全唐诗/poet.tang.7000.json','["江有楓，其葉蒙蒙。", "我友自東，于以遊從。"]'),
('d85868ac-6915-478d-9b8f-75f3f8254654','江有楓一篇十章 二','蕭穎士','唐','唐诗','tang','','[]','山有槭，其葉漠漠。',19,'全唐诗/poet.tang.7000.json','["山有槭，其葉漠漠。", "我友徂北，于以休息。"]'),
('9b7e90e0-426e-4f88-9d65-bfed619cf8ea','江有楓一篇十章 三','蕭穎士','唐','唐诗','tang','','[]','想彼槭矣，亦類其楓。',20,'全唐诗/poet.tang.7000.json','["想彼槭矣，亦類其楓。", "矧伊懷人，而忘其東。"]'),
('5b20402c-4823-4330-b54d-88147a1a3fc5','江有楓一篇十章 四','蕭穎士','唐','唐诗','tang','','[]','東可遊矣，會之丘矣。',40,'全唐诗/poet.tang.7000.json','["東可遊矣，會之丘矣。", "于山于水，于廟于寺。", "于亭于里，君子遊焉。", "于以宴喜，其樂亹亹。"]'),
('cb047209-77a1-44d4-9690-a6ba5a8f52e2','江有楓一篇十章 五','蕭穎士','唐','唐诗','tang','','[]','粵東可居，彼吳之墟。',40,'全唐诗/poet.tang.7000.json','["粵東可居，彼吳之墟。", "有田有庭，有朋有書。", "有蓴有魚，君子居焉。", "惟以宴醑，其樂徐徐。"]'),
('fa986a33-2414-4c5a-894a-1312bf0d1a4b','江有楓一篇十章 六','蕭穎士','唐','唐诗','tang','','[]','我朋在矣，彼陸之子。',20,'全唐诗/poet.tang.7000.json','["我朋在矣，彼陸之子。", "如松如杞，淑問不已。"]'),
('f0575edd-5f4e-4a8e-9323-6c352f9b4a47','江有楓一篇十章 七','蕭穎士','唐','唐诗','tang','','[]','我友于征，彼鄭之子。',20,'全唐诗/poet.tang.7000.json','["我友于征，彼鄭之子。", "如琇如英，德音孔明。"]'),
('db51f017-bb54-4054-a9c9-7ab2c42303d5','江有楓一篇十章 八','蕭穎士','唐','唐诗','tang','','[]','我思震澤，菱芡幕幕。',30,'全唐诗/poet.tang.7000.json','["我思震澤，菱芡幕幕。", "寤寐如覿，我思剡谿。", "杉篠萋萋，寤寐無迷。"]'),
('0223b12b-6e1b-47bd-a8ab-3ba123bcf93b','江有楓一篇十章 九','蕭穎士','唐','唐诗','tang','','[]','有鳥有鳥，粵鷗與鷺。',35,'全唐诗/poet.tang.7000.json','["有鳥有鳥，粵鷗與鷺。", "浮湍戲渚，皓然潔素。", "忘其猜妒，彼何人斯，曾足傷懼。"]'),
('9dac1225-1872-4da4-a929-44f28900bd98','江有楓一篇十章 十','蕭穎士','唐','唐诗','tang','','[]','此懼惟何，懼寘于羅。',55,'全唐诗/poet.tang.7000.json','["此懼惟何，懼寘于羅。", "彼驕者子，讒言孔多。", "我聞先師，體命委和。", "公伯之愬，則如予何。", "悵然山河，惟以嘯歌，其憂也哉。"]'),
('82974f04-09c3-493b-8e4d-5d8cf5a6b610','菊榮一篇五章 一','蕭穎士','唐','唐诗','tang','','[]','采采者菊，芬其榮斯。',50,'全唐诗/poet.tang.7000.json','["采采者菊，芬其榮斯。", "紫英黃萼，照灼丹墀。", "愷悌君子，佩服攸宜。", "王國是維，大君是毗。", "貽爾子孫，百祿萃之。"]'),
('cf843715-ea79-469b-adec-c14de2346d5d','菊榮一篇五章 二','蕭穎士','唐','唐诗','tang','','[]','采采者菊，于邑之城。',50,'全唐诗/poet.tang.7000.json','["采采者菊，于邑之城。", "舊根新莖，布葉垂英。", "彼美淑人，應家之禎。", "有弦既鳴，我政則平。", "宜爾棟崇，必復其慶。"]'),
('f27cd298-6c2d-4bf0-a54c-140104265ce1','菊榮一篇五章 三','蕭穎士','唐','唐诗','tang','','[]','采采者菊，于邦之府。',50,'全唐诗/poet.tang.7000.json','["采采者菊，于邦之府。", "陰槐翳柳，邇楹近宇。", "彼勞者子，喧卑是處。", "慨其莫知，蘊結誰語。", "企彼高人，色斯遐舉。"]'),
('6df762f3-0519-4321-979b-867871f44371','菊榮一篇五章 四','蕭穎士','唐','唐诗','tang','','[]','采采者菊，于賓之館。',50,'全唐诗/poet.tang.7000.json','["采采者菊，于賓之館。", "既低其枝，又弱其幹。", "有斐君子，是焉披翫。", "良辰旨酒，宴飲無算。", "愴其仳別，終然永歎。"]'),
('2900bc66-bc71-44b6-99b4-8f65afe92fbe','菊榮一篇五章 五','蕭穎士','唐','唐诗','tang','','[]','歲方晏矣，霜露殘促。',50,'全唐诗/poet.tang.7000.json','["歲方晏矣，霜露殘促。", "誰其榮斯，有英者菊。", "豈微春華，懿此貞色。", "人之侮我，混于薪棘。", "詩人有言，好是正直。"]'),
('a6993739-4600-4f15-9835-c784f432ba0b','涼雨一章','蕭穎士','唐','唐诗','tang','','[]','習習涼風，泠泠浮飆。',45,'全唐诗/poet.tang.7000.json','["習習涼風，泠泠浮飆。", "君子樂胥，于其賓僚。", "有女斯夭，式歌且謠。", "欲言終宥，惟以招邀，于胥樂兮。"]'),
('3181e8d5-a187-4328-97b1-189ddedfa2af','有竹一篇七章','蕭穎士','唐','唐诗','tang','','[]','有竹斯竿，于閣之前。',162,'全唐诗/poet.tang.7000.json','["有竹斯竿，于閣之前。", "君子秉心，惟其貞堅兮。", "有竿斯竹，于閣之側。", "君子秉操，惟其正直兮。", "彼蔚者竹，蕭其森矣。", "有開者閤，宛其深矣。", "迴簷幽砌，如翼如齒。", "冬之霄，霰雪斯瀌。", "我有金鑪，熺其以歊。", "夏之日，炎景斯鬱。", "我有珍簟，淒其以栗。", "彼紛者務，體其豫矣。", "有旨者酒，歡其且矣。", "友僚萃止，跗蕚載韡。", "彼美公之姓兮，那歟應積慶兮，期子惟去之柄兮。"]'),
('56232b75-2409-4b3c-a341-cc2f668f69a9','有竹一篇七章 一','蕭穎士','唐','唐诗','tang','','[]','有竹斯竿，于閣之前。',21,'全唐诗/poet.tang.7000.json','["有竹斯竿，于閣之前。", "君子秉心，惟其貞堅兮。"]'),
('c792590a-599f-46cf-b882-5b504c95cebf','有竹一篇七章 二','蕭穎士','唐','唐诗','tang','','[]','有竿斯竹，于閣之側。',21,'全唐诗/poet.tang.7000.json','["有竿斯竹，于閣之側。", "君子秉操，惟其正直兮。"]'),
('ccb49f44-0495-4a5a-be73-a31997b47a42','有竹一篇七章 三','蕭穎士','唐','唐诗','tang','','[]','彼蔚者竹，蕭其森矣。',30,'全唐诗/poet.tang.7000.json','["彼蔚者竹，蕭其森矣。", "有開者閤，宛其深矣。", "迴簷幽砌，如翼如齒。"]'),
('8cf76dcf-0833-42df-bb98-3d02e628d72b','有竹一篇七章 四','蕭穎士','唐','唐诗','tang','','[]','冬之霄，霰雪斯瀌。',19,'全唐诗/poet.tang.7000.json','["冬之霄，霰雪斯瀌。", "我有金鑪，熺其以歊。"]'),
('2790fed0-2956-4a02-8973-83a3325efb2c','有竹一篇七章 五','蕭穎士','唐','唐诗','tang','','[]','夏之日，炎景斯鬱。',19,'全唐诗/poet.tang.7000.json','["夏之日，炎景斯鬱。", "我有珍簟，淒其以栗。"]'),
('7eac2430-c28d-4873-b13f-60de470ee779','有竹一篇七章 六','蕭穎士','唐','唐诗','tang','','[]','彼紛者務，體其豫矣。',30,'全唐诗/poet.tang.7000.json','["彼紛者務，體其豫矣。", "有旨者酒，歡其且矣。", "友僚萃止，跗蕚載韡。"]'),
('228cb24a-d906-4365-a3e7-6958711dc087','有竹一篇七章 七','蕭穎士','唐','唐诗','tang','','[]','彼美公之姓兮，那歟應積慶兮，期子惟去之柄兮。',22,'全唐诗/poet.tang.7000.json','["彼美公之姓兮，那歟應積慶兮，期子惟去之柄兮。"]'),
('40557e94-3c29-4668-b046-bbc15e2fe71e','江有歸舟三章 一','蕭穎士','唐','唐诗','tang','','[]','江有歸舟，亦亂其流。',30,'全唐诗/poet.tang.7000.json','["江有歸舟，亦亂其流。", "之子言旋，嘉名孔修。", "揚于王庭，允焯其休。"]'),
('fb1ba66d-3252-4b58-b68b-5f516b270406','江有歸舟三章 二','蕭穎士','唐','唐诗','tang','','[]','舟既歸止，人亦榮止。',30,'全唐诗/poet.tang.7000.json','["舟既歸止，人亦榮止。", "兄矣弟矣，孝斯踐矣。", "稱觴燕喜，于岵于屺。"]'),
('d94ef38b-0534-4c03-adbd-1c7b931ee610','江有歸舟三章 三','蕭穎士','唐','唐诗','tang','','[]','彼遊惟帆，匪風不揚。',30,'全唐诗/poet.tang.7000.json','["彼遊惟帆，匪風不揚。", "有彬伊父，匪學不彰。", "予其懷而，勉爾無忘。"]'),
('d47e3ff1-8601-4476-becb-b51b7f233003','過河濱和文學張志尹','蕭穎士','唐','唐诗','tang','','[]','隆古日以遠，舉世喪其淳。',120,'全唐诗/poet.tang.7000.json','["隆古日以遠，舉世喪其淳。", "慷慨懷黃虞，化理何由臻。", "步出城西門，裴回見河濱。", "當其側陋時，河水清且潾。", "滄桑一以變，莽然翳荆榛。", "至化無苦窳，宇宙將陶甄。", "太息感悲泉，人往跡未湮。", "瑟瑟寒原暮，冷風吹衣巾。", "顧我譾劣質，希聖杳無因。", "且盡登臨意，斗酒歡相親。"]'),
('de48ce53-1660-45f3-9281-fc8b1cceeb74','舟中遇陸棣兄西歸數日得廣陵二三子書知遲晚次沙墊西岸作','蕭穎士','唐','唐诗','tang','','[]','林烏遙岸鳴，早知東方曙。',168,'全唐诗/poet.tang.7000.json','["林烏遙岸鳴，早知東方曙。", "波上風雨歇，舟人叫將去。", "蒼蒼前洲日，的的回沙鷺。", "水氣清曉陰，灘聲隱川霧。", "舊山勞魂想，憶人阻洄泝。", "信宿千里餘，佳期曷由遇。", "前程入楚鄉，弭棹問維揚。", "但見土音異，始知程路長。", "寥寥晚空靜，漫漫風淮涼。", "雲景信可美，風潮殊未央。", "故人江臯上，永日念容光。", "中路枉尺書，謂余瓊樹芳。", "深期結晤語，竟夕恨相望。", "冀願崇朝霽，吾其一葦航。"]'),
('29c83696-8b87-47dc-841c-4c6f790b10c0','重陽日陪元魯山德秀登北城矚對新霽因以贈別','蕭穎士','唐','唐诗','tang','','[]','山縣遶古堞，悠悠快登望。',168,'全唐诗/poet.tang.7000.json','["山縣遶古堞，悠悠快登望。", "雨餘秋天高，目盡無隱狀。", "綿連滍川迴，杳渺鴉路深。", "彭澤興不淺，臨風動歸心。", "賴茲琴堂暇，傲睨傾菊酒。", "人和歲已登，從政復何有。", "遠山十里碧，一道銜長雲。", "青霞半落日，混合疑晴曛。", "漸聞驚栖羽，坐歎清夜月。", "中歡愴有違，行子念明發。", "僅能泯寵辱，未免傷別離。", "江湖不可忘，風雨勞相思。", "明時當盛才，短伎安所設。", "何日謝百里，從君漢之澨。"]'),
('14cd929a-3532-4d36-a2d1-17f3cc1cf24f','留別二三子得韻字','蕭穎士','唐','唐诗','tang','','[]','二紀尚雌伏，徒然忝先進。',48,'全唐诗/poet.tang.7000.json','["二紀尚雌伏，徒然忝先進。", "英英爾衆賢，名實鬱雙振。", "殘春惜將別，清洛行不近。", "相與愛後時，無令孤逸韻。"]'),
('34deac87-ef32-4def-88ba-c28428ea91c5','仰荅韋司業垂訪五首 一','蕭穎士','唐','唐诗','tang','','[]','呦呦食苹鹿，常飲清泠川。',96,'全唐诗/poet.tang.7000.json','["呦呦食苹鹿，常飲清泠川。", "但悅豐草美，寧知牢饌鮮。", "主人有幽意，將以充林泉。", "羅網幸免傷，蒙君復羈牽。", "高堂列衆賓，廣座鳴清絃。", "俯仰轉驚惕，裴回獨憂煎。", "緬懷雲巖路，欲往無由緣。", "物各有所好，違之傷自然。"]'),
('f7c99a08-18ed-4cf7-9760-9c90b11ba950','仰荅韋司業垂訪五首 二','蕭穎士','唐','唐诗','tang','','[]','神龜在南國，緬邈湘川陰。',84,'全唐诗/poet.tang.7000.json','["神龜在南國，緬邈湘川陰。", "遊止蓮葉上，歲時嘉樹林。", "毒蟲且不近，斤斧何由尋。", "錯落負奇文，熒煌耀丹金。", "江山萬里餘，淮海阻且深。", "獨保貞素質，不爲寒暑侵。", "一逢盛明代，應見通靈心。"]'),
('e9bf909f-abbd-4fa8-b14b-8ace03c17a0c','仰荅韋司業垂訪五首 三','蕭穎士','唐','唐诗','tang','','[]','晉代有儒臣，當年富詞藻。',72,'全唐诗/poet.tang.7000.json','["晉代有儒臣，當年富詞藻。", "立言寄青史，將以贊王道。", "遼落緬歲時，辛勤歷江島。", "且言風波倦，探涉豈爲寶。", "不遇庾征西，云誰展懷抱。", "士貧乏知己，安得成所好。"]'),
('2000eb66-9670-4e20-b8a0-f7ab308108b2','仰荅韋司業垂訪五首 四','蕭穎士','唐','唐诗','tang','','[]','彭陽昔遊說，願謁南郢都。',74,'全唐诗/poet.tang.7000.json','["彭陽昔遊說，願謁南郢都。", "王果尚未達，況從夷節謨。", "豈知晉叔向，無罪嬰囚拘。", "臨難俟解紛，獨知[祁]大夫。", "舉讐且不棄，何必論親疎。", "夫子覺者也，其能遺我乎。"]'),
('1cfbd201-1374-47b5-99a5-8fb5a95a2ea3','仰荅韋司業垂訪五首 五','蕭穎士','唐','唐诗','tang','','[]','關西一公子，年貌獨青春。',72,'全唐诗/poet.tang.7000.json','["關西一公子，年貌獨青春。", "被褐來上京，翳然聲未振。", "中郎何爲者，倒屣驚座賓。", "詞賦豈不佳，盛名亦相因。", "爲君奏此曲，此曲多苦辛。", "千載不可誣，孰言今無人。"]'),
('891222e7-ee6e-4881-97a2-c31055317363','答鄒象先','蕭穎士','唐','唐诗','tang','','[]','桂枝常共擢，茅茨冀同薦。',48,'全唐诗/poet.tang.7000.json','["桂枝常共擢，茅茨冀同薦。", "一命何阻脩，載馳各川縣。", "壯圖悲歲月，明代恥貧賤。", "回首無津梁，祗令二毛變。"]'),
('37cd5393-d24a-426a-9c53-a774251bd650','蒙山作','蕭穎士','唐','唐诗','tang','','[]','東蒙鎮海沂，合沓餘百里。',180,'全唐诗/poet.tang.7000.json','["東蒙鎮海沂，合沓餘百里。", "清秋淨氛靄，崖崿隱天起。", "于役勞往還，息徒暫攀躋。", "將窮絕迹處，偶得冥心理。", "雲氣雜虹霓，松聲亂風水。", "微明綠林際，杳窱丹洞裏。", "仙鳥時可聞，羽人邈難視。", "此焉多深邃，賢達昔所止。", "子尚捐俗紛，季隨躡遐軌。", "蘊真道彌曠，懷古情未已。", "白鹿凡幾遊，黃精復奚似。", "顧予尚牽纏，家業重書史。", "少學務從師，壯年貴趨仕。", "方馳桂林譽，未暇桃源美。", "歲暮期再尋，幽哉羨門子。"]'),
('1fe9c185-de0e-40f6-a3a2-27fa03cb0ac8','早春過七嶺寄題硤石裴丞廳壁','蕭穎士','唐','唐诗','tang','','[]','出硤寄趣少，晚行偏憶君。',72,'全唐诗/poet.tang.7000.json','["出硤寄趣少，晚行偏憶君。", "依然向來處，官路谿邊雲。", "茲路豈不劇，能無俗累紛。", "槐陰永未合，泉聲細猶聞。", "彌歎春罷酒，牽卑從此分。", "登高望城入，斜影半風薰。"]'),
('43299da8-2c0d-499a-8dfd-913f3e01d0d2','送張翬下第歸江東','蕭穎士','唐','唐诗','tang','','[]','俱飛仍失路，綵服邇清波。',48,'全唐诗/poet.tang.7000.json','["俱飛仍失路，綵服邇清波。", "地積東南美，朝遺甲乙科。", "客愁千里別，春色五湖多。", "明日舊山去，其如相望何。"]'),
('b9c80ee4-da68-4098-8ac1-403819eae07d','越江秋曙','蕭穎士','唐','唐诗','tang','','[]','扁舟東路遠，曉月下江濆。',72,'全唐诗/poet.tang.7000.json','["扁舟東路遠，曉月下江濆。", "瀲灩信潮上，蒼茫孤嶼分。", "林聲寒動葉，水氣曙連雲。", "暾日浪中出，榜歌天際聞。", "伯鸞常去國，安道惜離羣。", "延首剡谿近，詠言懷數君。"]'),
('7c00e43d-6a89-435a-9be6-f0420b615698','山莊月夜作','蕭穎士','唐','唐诗','tang','','[]','獻書嗟棄置，疲拙歸田園。',96,'全唐诗/poet.tang.7000.json','["獻書嗟棄置，疲拙歸田園。", "且事計然策，將符公冶言。", "桑榆清暮景，雞犬應遙村。", "蠶罷里閭晏，麥秋田野喧。", "澗聲連枕簟，峯勢入階軒。", "未奏東山妓，先傾北海尊。", "隴瓜香早熟，庭果落初繁。", "更愜野人意，農談朝竟昏。"]'),
('e5b68e17-6380-472f-8ab4-553d2ac9d2bc','古意','崔曙','唐','唐诗','tang','','[]','綠筍總成竹，紅花亦成子。',36,'全唐诗/poet.tang.7000.json','["綠筍總成竹，紅花亦成子。", "能當此時好，獨自幽閨裏。", "夜夜苦更長，愁來不如死。"]');
